    def apply_local_reasoning_bridge_profile(
        self,
        *,
        profile_id: str,
        replace: bool = True,
        restart: bool = False,
        wait_ready: bool = True,
        timeout_s: Optional[float] = None,
        force: bool = False,
        override_updates: Optional[Dict[str, Any]] = None,
        template_id: str = "",
    ) -> Dict[str, Any]:
        clean_profile_id = str(profile_id or "").strip().lower()
        clean_template_id = str(template_id or "").strip().lower()
        if not clean_profile_id:
            return {"status": "error", "message": "profile_id is required", "ready": False}
        catalog = self.model_bridge_profiles(task="reasoning", limit=256)
        profile_rows = catalog.get("profiles", []) if isinstance(catalog, dict) else []
        selected = None
        if isinstance(profile_rows, list):
            for row in profile_rows:
                if not isinstance(row, dict):
                    continue
                if str(row.get("profile_id", "") or "").strip().lower() == clean_profile_id:
                    selected = row
                    break
        if not isinstance(selected, dict):
            return {"status": "error", "message": f"reasoning bridge profile not found: {clean_profile_id}", "ready": False}
        if not bool(selected.get("apply_supported", False)):
            return {"status": "error", "message": f"profile '{clean_profile_id}' is not directly applyable", "ready": False}
        override_patch = dict(override_updates) if isinstance(override_updates, dict) else dict(selected.get("override_patch", {}))
        if not override_patch:
            return {"status": "error", "message": f"profile '{clean_profile_id}' has no runtime override patch", "ready": False}
        planner = getattr(self.kernel, "planner", None)
        if planner is None:
            return {"status": "error", "message": "planner unavailable", "ready": False}
        fn = getattr(planner, "apply_local_reasoning_bridge_overrides", None)
        if not callable(fn):
            return {"status": "unavailable", "message": "planner reasoning bridge profile apply unavailable", "ready": False}
        try:
            apply_payload = fn(
                updates=dict(override_patch),
                profile_id=clean_profile_id,
                template_id=clean_template_id,
                replace=bool(replace),
            )
            result: Dict[str, Any] = {
                "status": str((apply_payload or {}).get("status", "success")),
                "profile_id": clean_profile_id,
                "template_id": clean_template_id,
                "profile": _to_jsonable(selected),
                "replace": bool(replace),
                "override_patch": _to_jsonable(override_patch),
                "bridge": _to_jsonable(apply_payload) if isinstance(apply_payload, dict) else {"status": "error", "message": "invalid apply payload"},
            }
            if restart:
                restart_payload = self.restart_local_reasoning_bridge(
                    wait_ready=bool(wait_ready),
                    timeout_s=timeout_s,
                    reason=f"profile:{clean_profile_id}",
                    force=bool(force),
                )
                result["restart"] = _to_jsonable(restart_payload) if isinstance(restart_payload, dict) else {"status": "error", "message": "invalid restart payload"}
                result["bridge"] = result["restart"]
                result["status"] = str((restart_payload or {}).get("status", result["status"]))
            bridge_payload = result.get("bridge", {})
            result["ready"] = bool(bridge_payload.get("ready", False)) if isinstance(bridge_payload, dict) else False
            return result
        except Exception as exc:  # noqa: BLE001
            return {"status": "error", "message": str(exc), "ready": False}

    def apply_local_neural_tts_profile(
        self,
        *,
        profile_id: str,
        replace: bool = True,
        restart: bool = True,
        wait_ready: bool = True,
        timeout_s: Optional[float] = None,
        force: bool = False,
        override_updates: Optional[Dict[str, Any]] = None,
        template_id: str = "",
    ) -> Dict[str, Any]:
        clean_profile_id = str(profile_id or "").strip().lower()
        clean_template_id = str(template_id or "").strip().lower()
        if not clean_profile_id:
            return {"status": "error", "message": "profile_id is required", "ready": False}
        catalog = self.model_bridge_profiles(task="tts", limit=256)
        profile_rows = catalog.get("profiles", []) if isinstance(catalog, dict) else []
        selected = None
        if isinstance(profile_rows, list):
            for row in profile_rows:
                if not isinstance(row, dict):
                    continue
                if str(row.get("profile_id", "") or "").strip().lower() == clean_profile_id:
                    selected = row
                    break
        if not isinstance(selected, dict):
            return {"status": "error", "message": f"tts bridge profile not found: {clean_profile_id}", "ready": False}
        if not bool(selected.get("apply_supported", False)):
            return {"status": "error", "message": f"profile '{clean_profile_id}' is not directly applyable", "ready": False}
        override_patch = dict(override_updates) if isinstance(override_updates, dict) else (
            dict(selected.get("override_patch", {})) if isinstance(selected.get("override_patch"), dict) else {}
        )
        if not override_patch:
            return {"status": "error", "message": f"profile '{clean_profile_id}' has no runtime override patch", "ready": False}
        try:
            from backend.python.speech.local_tts import LocalTTS
            from backend.python.speech.local_tts_bridge import LocalNeuralTtsBridge

            bridge = LocalNeuralTtsBridge.shared()
            apply_payload = bridge.set_runtime_overrides(
                updates=override_patch,
                profile_id=clean_profile_id,
                template_id=clean_template_id,
                replace=bool(replace),
            )
            execution_backend = str(override_patch.get("execution_backend", selected.get("execution_backend", "")) or "").strip().lower()
            restart_payload: Optional[Dict[str, Any]] = None
            if restart and execution_backend == "openai_http":
                bridge.stop(reason=f"profile:{clean_profile_id}")
                restart_payload = bridge.start(
                    wait_ready=bool(wait_ready),
                    timeout_s=max(1.0, min(float(timeout_s or override_patch.get("timeout_s", 18.0) or 18.0), 240.0)),
                    reason=f"profile:{clean_profile_id}",
                    force=bool(force),
                )
            elif restart and bool(bridge.status(probe=False).get("running", False)):
                restart_payload = bridge.stop(reason=f"profile:{clean_profile_id}")
            tts_diagnostics = LocalTTS.diagnostics(history_limit=24)
            neural_runtime = dict(tts_diagnostics.get("neural_runtime", {})) if isinstance(tts_diagnostics.get("neural_runtime"), dict) else {}
            bridge_payload = (
                restart_payload
                if isinstance(restart_payload, dict)
                else bridge.status(probe=execution_backend == "openai_http")
            )
            result: Dict[str, Any] = {
                "status": "success",
                "profile_id": clean_profile_id,
                "template_id": clean_template_id,
                "profile": _to_jsonable(selected),
                "replace": bool(replace),
                "ready": bool(neural_runtime.get("ready", False)),
                "override_patch": _to_jsonable(override_patch),
                "bridge": _to_jsonable(bridge_payload) if isinstance(bridge_payload, dict) else _to_jsonable(apply_payload),
                "restart": _to_jsonable(restart_payload) if isinstance(restart_payload, dict) else None,
                "neural_runtime": _to_jsonable(neural_runtime),
                "tts_diagnostics": _to_jsonable(tts_diagnostics),
            }
            return result
        except Exception as exc:  # noqa: BLE001
            return {"status": "error", "message": str(exc), "ready": False}

    def apply_local_stt_profile(
        self,
        *,
        profile_id: str,
        replace: bool = True,
        restart_voice_if_running: bool = True,
        override_updates: Optional[Dict[str, Any]] = None,
        template_id: str = "",
    ) -> Dict[str, Any]:
        clean_profile_id = str(profile_id or "").strip().lower()
        clean_template_id = str(template_id or "").strip().lower()
        if not clean_profile_id:
            return {"status": "error", "message": "profile_id is required", "ready": False}
        catalog = self.model_bridge_profiles(task="stt", limit=256)
        profile_rows = catalog.get("profiles", []) if isinstance(catalog, dict) else []
        selected = None
        if isinstance(profile_rows, list):
            for row in profile_rows:
                if not isinstance(row, dict):
                    continue
                if str(row.get("profile_id", "") or "").strip().lower() == clean_profile_id:
                    selected = row
                    break
        if not isinstance(selected, dict):
            return {"status": "error", "message": f"stt runtime profile not found: {clean_profile_id}", "ready": False}
        if not bool(selected.get("apply_supported", False)):
            return {"status": "error", "message": f"profile '{clean_profile_id}' is not directly applyable", "ready": False}
        override_patch = dict(override_updates) if isinstance(override_updates, dict) else (
            dict(selected.get("override_patch", {})) if isinstance(selected.get("override_patch"), dict) else {}
        )
        local_model_path = str(
            override_patch.get("local_model_path", selected.get("detected_model_path", ""))
            or selected.get("detected_model_path", "")
        ).strip()
        if not local_model_path:
            return {"status": "error", "message": f"profile '{clean_profile_id}' has no local STT model path", "ready": False}
        model_name = str(
            override_patch.get(
                "model",
                override_patch.get(
                    "model_label",
                    selected.get("name", Path(local_model_path).name if local_model_path else "whisper-large-v3"),
                ),
            )
            or Path(local_model_path).name
        ).strip() or "whisper-large-v3"
        previous_policy: Dict[str, Any] = {}
        previous_voice_config: Dict[str, Any] = {}
        was_running = False
        with self._voice_lock:
            if self._stt_engine is not None:
                policy_fn = getattr(self._stt_engine, "policy_status", None)
                if callable(policy_fn):
                    try:
                        previous_policy = policy_fn(history_limit=120)
                    except Exception:
                        previous_policy = {}
            if self._voice_session is not None:
                try:
                    voice_status = self._voice_session.status()
                except Exception:
                    voice_status = {}
                if isinstance(voice_status, dict):
                    was_running = bool(voice_status.get("running", False))
                    previous_voice_config = (
                        dict(voice_status.get("config", {}))
                        if isinstance(voice_status.get("config"), dict)
                        else {}
                    )
                    if was_running and restart_voice_if_running:
                        try:
                            self._voice_session.stop()
                        except Exception:
                            pass
            os.environ["JARVIS_STT_MODEL_PATH"] = local_model_path
            os.environ["JARVIS_STT_MODEL"] = model_name
            self._stt_engine = self._create_stt_engine(model_name=model_name, local_model_path=local_model_path)
            self._apply_stt_policy_snapshot(self._stt_engine, previous_policy)
            self._sync_stt_engine_route_policy_snapshot(self._stt_engine, force_refresh=True)
            self._ensure_voice_session_controller()
            self._voice_session.stt_engine = self._stt_engine
            self._stt_runtime_profile_state = {
                "status": "success",
                "task": "stt",
                "profile_id": clean_profile_id,
                "template_id": clean_template_id,
                "model": model_name,
                "local_model_path": local_model_path,
                "updated_at": time.time(),
            }
        restart_payload: Dict[str, Any] | None = None
        if was_running and restart_voice_if_running:
            restart_payload = self.start_voice_session(config=previous_voice_config if previous_voice_config else {})
        stt_diagnostics: Dict[str, Any] = {}
        if self._stt_engine is not None:
            diagnostics_fn = getattr(self._stt_engine, "diagnostics", None)
            if callable(diagnostics_fn):
                try:
                    stt_diagnostics = diagnostics_fn(history_limit=24)
                except Exception:
                    stt_diagnostics = {}
        if isinstance(stt_diagnostics, dict):
            stt_diagnostics["runtime_profile"] = self._stt_runtime_profile_status()
        stt_policy = self.get_stt_policy(history_limit=120, source="stt-profile-apply")
        voice_status = self.get_voice_session_status()
        return {
            "status": "success",
            "profile_id": clean_profile_id,
            "template_id": clean_template_id,
            "profile": _to_jsonable(selected),
            "replace": bool(replace),
            "ready": bool(stt_diagnostics.get("available", self._stt_engine is not None)),
            "override_patch": _to_jsonable(override_patch),
            "stt_diagnostics": _to_jsonable(stt_diagnostics),
            "stt_policy": _to_jsonable(stt_policy),
            "voice": _to_jsonable(voice_status),
            "restart": _to_jsonable(restart_payload) if isinstance(restart_payload, dict) else None,
            "runtime_profile": _to_jsonable(self._stt_runtime_profile_status()),
        }

    def apply_local_vision_profile(
        self,
        *,
        profile_id: str,
        override_updates: Optional[Dict[str, Any]] = None,
        template_id: str = "",
    ) -> Dict[str, Any]:
        clean_profile_id = str(profile_id or "").strip().lower()
        clean_template_id = str(template_id or "").strip().lower()
        if not clean_profile_id:
            return {"status": "error", "message": "profile_id is required", "ready": False}
        catalog = self.model_bridge_profiles(task="vision", limit=256)
        profile_rows = catalog.get("profiles", []) if isinstance(catalog, dict) else []
        selected = None
        if isinstance(profile_rows, list):
            for row in profile_rows:
                if not isinstance(row, dict):
                    continue
                if str(row.get("profile_id", "") or "").strip().lower() == clean_profile_id:
                    selected = row
                    break
        if not isinstance(selected, dict):
            return {"status": "error", "message": f"vision runtime profile not found: {clean_profile_id}", "ready": False}
        if not bool(selected.get("apply_supported", False)):
            return {"status": "error", "message": f"profile '{clean_profile_id}' is not directly applyable", "ready": False}
        override_patch = dict(override_updates) if isinstance(override_updates, dict) else (
            dict(selected.get("override_patch", {})) if isinstance(selected.get("override_patch"), dict) else {}
        )
        models = [
            str(item or "").strip().lower()
            for item in (override_patch.get("models", []) if isinstance(override_patch.get("models"), list) else [])
            if str(item or "").strip()
        ]
        if not models:
            return {"status": "error", "message": f"profile '{clean_profile_id}' has no supported vision runtime targets", "ready": False}
        clear_cache = bool(override_patch.get("clear_cache", False))
        force_reload = bool(override_patch.get("force_reload", False))
        reset_payload: Optional[Dict[str, Any]] = None
        if clear_cache:
            reset_payload = self.reset_vision_runtime(models=models, clear_cache=True)
        warm_payload = self.warm_vision_runtime(models=models, force_reload=force_reload and not clear_cache)
        runtime_payload = warm_payload.get("runtime", {}) if isinstance(warm_payload, dict) else {}
        ready_models = {
            str(item.get("model", "") or "").strip().lower()
            for item in runtime_payload.get("items", [])
            if isinstance(item, dict) and bool(item.get("loaded", False))
        } if isinstance(runtime_payload, dict) else set()
        ready = all(model_name in ready_models for model_name in models)
        self._vision_runtime_profile_state = {
            "status": "success" if ready else "degraded",
            "task": "vision",
            "profile_id": clean_profile_id,
            "template_id": clean_template_id,
            "models": list(models),
            "updated_at": time.time(),
        }
        return {
            "status": "success" if ready else "degraded",
            "profile_id": clean_profile_id,
            "template_id": clean_template_id,
            "profile": _to_jsonable(selected),
            "override_patch": _to_jsonable(override_patch),
            "ready": ready,
            "vision_runtime": _to_jsonable(runtime_payload),
            "warm": _to_jsonable(warm_payload),
            "reset": _to_jsonable(reset_payload) if isinstance(reset_payload, dict) else None,
            "runtime_profile": _to_jsonable(self._vision_runtime_profile_status()),
        }

    def execute_model_launch_template(
        self,
        *,
        profile_id: str,
        template_id: str,
        replace: bool = True,
        wait_ready: bool = True,
        timeout_s: Optional[float] = None,
        force: bool = False,
        allow_unready: bool = False,
        probe: bool = True,
        auto_fallback: bool = True,
        retry_on_failure: bool = True,
        max_attempts: int = 2,
        retry_profile: str = "",
        retry_base_delay_ms: Optional[int] = None,
        retry_max_delay_ms: Optional[int] = None,
        retry_jitter_ms: Optional[int] = None,
        retry_prefer_recommended: Optional[bool] = None,
        _attempt_chain: Optional[list[Dict[str, Any]]] = None,
        _attempted_template_ids: Optional[list[str]] = None,
        _attempt_index: int = 1,
        _attempt_chain_id: str = "",
        _original_requested_template_id: str = "",
        _original_requested_template: Optional[Dict[str, Any]] = None,
        _retry_trigger: str = "",
    ) -> Dict[str, Any]:
        clean_profile_id = str(profile_id or "").strip().lower()
        clean_template_id = str(template_id or "").strip().lower()
        if not clean_profile_id:
            return {"status": "error", "message": "profile_id is required", "ready": False}
        if not clean_template_id:
            return {"status": "error", "message": "template_id is required", "ready": False}
        catalog = self.model_bridge_profiles(limit=256)
        profile_rows = catalog.get("profiles", []) if isinstance(catalog, dict) else []
        selected: Optional[Dict[str, Any]] = None
        if isinstance(profile_rows, list):
            for row in profile_rows:
                if not isinstance(row, dict):
                    continue
                if str(row.get("profile_id", "") or "").strip().lower() == clean_profile_id:
                    selected = row
                    break
        if not isinstance(selected, dict):
            return {
                "status": "error",
                "message": f"bridge profile not found: {clean_profile_id}",
                "profile_id": clean_profile_id,
                "template_id": clean_template_id,
                "ready": False,
            }
        bridge_kind = str(selected.get("bridge_kind", "") or "").strip().lower()
        selected_template: Optional[Dict[str, Any]] = None
        launch_templates = selected.get("launch_templates", [])
        if isinstance(launch_templates, list):
            for row in launch_templates:
                if not isinstance(row, dict):
                    continue
                if str(row.get("template_id", "") or "").strip().lower() == clean_template_id:
                    selected_template = row
                    break
        if not isinstance(selected_template, dict):
            return {
                "status": "error",
                "message": f"launch template not found: {clean_template_id}",
                "profile_id": clean_profile_id,
                "template_id": clean_template_id,
                "profile": _to_jsonable(selected),
                "ready": False,
            }
        requested_template_id = clean_template_id
        requested_template = dict(selected_template)
        requested_health = (
            dict(requested_template.get("health", {}))
            if isinstance(requested_template.get("health"), dict)
            else {}
        )
        bounded_max_attempts = max(1, min(int(max_attempts or 1), 4))
        attempt_index = max(1, int(_attempt_index or 1))
        attempt_chain_id = str(_attempt_chain_id or f"{clean_profile_id}:{time.time_ns()}").strip()
        attempted_template_ids = [
            str(item or "").strip().lower()
            for item in (_attempted_template_ids or [])
            if str(item or "").strip()
        ]
        original_requested_template_id = (
            str(_original_requested_template_id or requested_template_id).strip().lower()
            or requested_template_id
        )
        original_requested_template = (
            dict(_original_requested_template)
            if isinstance(_original_requested_template, dict)
            else dict(requested_template)
        )
        fallback_applied = False
        fallback_reason = ""
        fallback_source = ""
        fallback_from_template_id = requested_template_id
        recommended_template_id = str(selected.get("recommended_launch_template_id", "") or "").strip().lower()
        if auto_fallback and recommended_template_id and recommended_template_id != clean_template_id:
            fallback_candidate: Optional[Dict[str, Any]] = None
            if isinstance(launch_templates, list):
                for row in launch_templates:
                    if not isinstance(row, dict):
                        continue
                    if str(row.get("template_id", "") or "").strip().lower() == recommended_template_id:
                        fallback_candidate = row
                        break
            fallback_reasons: list[str] = []
            if bool(requested_template.get("blacklisted", False)) or bool(requested_health.get("blacklisted", False)):
                fallback_reasons.append("policy_blacklisted")
            if bool(requested_template.get("suppressed", False)) or bool(requested_health.get("suppressed", False)):
                fallback_reasons.append("strategy_suppressed")
            if bool(requested_health.get("demoted", False)):
                fallback_reasons.append("demoted")
            elif bool(requested_health.get("unstable", False)) and (
                int(requested_health.get("failure_streak", 0) or 0) >= 2
                or float(requested_health.get("recent_failure_rate", 0.0) or 0.0) >= 0.67
            ):
                fallback_reasons.append("unstable")
            if not bool(requested_template.get("ready", False)) and not allow_unready:
                fallback_reasons.append("not_ready")
            if fallback_reasons and isinstance(fallback_candidate, dict):
                selected_template = fallback_candidate
                clean_template_id = recommended_template_id
                fallback_applied = True
                fallback_reason = "+".join(dict.fromkeys(fallback_reasons))
                fallback_source = "recommended_launch_template"
        launch_started_monotonic = time.perf_counter()
        template_patch = dict(selected_template.get("profile_patch", {})) if isinstance(selected_template.get("profile_patch"), dict) else {}
        if not template_patch:
            template_patch = dict(selected.get("override_patch", {})) if isinstance(selected.get("override_patch"), dict) else {}
        if not template_patch:
            return {
                "status": "error",
                "message": f"launch template '{clean_template_id}' has no runtime patch",
                "profile_id": clean_profile_id,
                "template_id": clean_template_id,
                "profile": _to_jsonable(selected),
                "template": _to_jsonable(selected_template),
                "ready": False,
            }

        missing_requirements = [
            str(item or "").strip()
            for item in selected_template.get("missing_requirements", [])
            if isinstance(item, str) and str(item or "").strip()
        ]
        remediation_hints = [
            str(item or "").strip()
            for item in selected_template.get("remediation_hints", [])
            if isinstance(item, str) and str(item or "").strip()
        ]
        launcher = str(selected_template.get("launcher", "") or "").strip().lower()
        manual_only = bool(selected_template.get("manual_only", False))
        autostart_capable = bool(selected_template.get("autostart_capable", False))
        template_ready = bool(selected_template.get("ready", False))

        def _finish(payload: Dict[str, Any]) -> Dict[str, Any]:
            response = _to_jsonable(payload) if isinstance(payload, dict) else {"status": "error", "message": "invalid payload"}
            if not isinstance(response, dict):
                response = {"status": "error", "message": "invalid payload"}
            response.setdefault("bridge_kind", bridge_kind)
            response.setdefault("profile_id", clean_profile_id)
            response.setdefault("template_id", clean_template_id)
            response.setdefault("launcher", launcher)
            response.setdefault("manual_only", manual_only)
            response.setdefault("autostart_capable", autostart_capable)
            response.setdefault("profile", _to_jsonable(selected))
            response.setdefault("template", _to_jsonable(selected_template))
            response.setdefault("requested_template_id", requested_template_id)
            response.setdefault("requested_template", _to_jsonable(requested_template))
            response.setdefault("executed_template_id", clean_template_id)
            response.setdefault("fallback_applied", fallback_applied)
            response.setdefault("fallback_reason", fallback_reason)
            response.setdefault("fallback_source", fallback_source)
            response.setdefault("attempt_chain_id", attempt_chain_id)
            response.setdefault("attempt_index", attempt_index)
            response.setdefault("retry_trigger", str(_retry_trigger or "").strip().lower())
            response.setdefault("override_patch", _to_jsonable(template_patch))
            response.setdefault("missing_requirements", list(missing_requirements))
            response.setdefault("remediation_hints", list(remediation_hints))
            response["duration_s"] = round(max(0.0, time.perf_counter() - launch_started_monotonic), 4)
            initial_failure_like = self._is_model_launch_failure_like(
                {
                    "status": str(response.get("status", "unknown") or "unknown"),
                    "ready": bool(response.get("ready", False)),
                }
            )
            initial_retry_policy = self._model_launch_retry_policy(
                bridge_kind=bridge_kind,
                profile_id=clean_profile_id,
                requested_template=requested_template,
                current_template=selected_template,
                recommended_template_id=str(selected.get("recommended_launch_template_id", "") or ""),
                attempt_index=attempt_index,
                max_attempts=bounded_max_attempts,
                failure_like=initial_failure_like,
                retry_profile=retry_profile,
                retry_base_delay_ms=retry_base_delay_ms,
                retry_max_delay_ms=retry_max_delay_ms,
                retry_jitter_ms=retry_jitter_ms,
                retry_prefer_recommended=retry_prefer_recommended,
            )
            history_result = self._record_model_launch_template_event(
                {
                    "occurred_at": datetime.now(timezone.utc).isoformat(),
                    "status": str(response.get("status", "unknown") or "unknown").strip().lower() or "unknown",
                    "ready": bool(response.get("ready", False)),
                    "bridge_kind": bridge_kind,
                    "profile_id": clean_profile_id,
                    "template_id": clean_template_id,
                    "requested_template_id": requested_template_id,
                    "profile_title": str(selected.get("title", "") or selected.get("name", "") or "").strip(),
                    "template_title": str(selected_template.get("title", "") or selected_template.get("launcher", "") or "").strip(),
                    "requested_template_title": str(
                        requested_template.get("title", "") or requested_template.get("launcher", "") or ""
                    ).strip(),
                    "launcher": launcher,
                    "requested_launcher": str(requested_template.get("launcher", "") or "").strip().lower(),
                    "transport": str(selected_template.get("transport", "") or "").strip().lower(),
                    "requested_transport": str(requested_template.get("transport", "") or "").strip().lower(),
                    "recommended": bool(selected_template.get("recommended", False)),
                    "manual_only": manual_only,
                    "requested_manual_only": bool(requested_template.get("manual_only", False)),
                    "autostart_capable": autostart_capable,
                    "requested_autostart_capable": bool(requested_template.get("autostart_capable", False)),
                    "fallback_applied": fallback_applied,
                    "fallback_reason": fallback_reason,
                    "fallback_source": fallback_source,
                    "fallback_from_template_id": fallback_from_template_id,
                    "fallback_to_template_id": clean_template_id if fallback_applied else "",
                    "attempt_chain_id": attempt_chain_id,
                    "attempt_index": attempt_index,
                    "retry_trigger": str(_retry_trigger or "").strip().lower(),
                    "retry_requested_profile": str(initial_retry_policy.get("requested_profile", "") or "").strip().lower(),
                    "retry_profile": str(initial_retry_policy.get("profile", "") or "").strip().lower(),
                    "retry_profile_adjusted": bool(initial_retry_policy.get("profile_adjusted", False)),
                    "retry_profile_adjustment_reason": str(
                        initial_retry_policy.get("profile_adjustment_reason", "") or ""
                    ).strip().lower(),
                    "retry_strategy": str(initial_retry_policy.get("strategy", "") or "").strip().lower(),
                    "retry_strategy_score": round(
                        float(
                            (
                                initial_retry_policy.get("strategy_health", {})
                                if isinstance(initial_retry_policy.get("strategy_health"), dict)
                                else {}
                            ).get("score", 0.0)
                            or 0.0
                        ),
                        4,
                    ),
                    "retry_escalation_mode": str(initial_retry_policy.get("escalation_mode", "") or "").strip().lower(),
                    "retry_prefer_recommended": bool(initial_retry_policy.get("prefer_recommended", False)),
                    "retry_delay_ms": int(initial_retry_policy.get("delay_ms", 0) or 0),
                    "retry_jitter_ms": int(initial_retry_policy.get("jitter_ms", 0) or 0),
                    "retry_recommended_template_id": str(
                        initial_retry_policy.get("recommended_template_id", "") or ""
                    ).strip().lower(),
                    "retry_preview_schedule_ms": list(initial_retry_policy.get("preview_schedule_ms", [])),
                    "message": str(response.get("message", "") or "").strip(),
                    "duration_s": float(response.get("duration_s", 0.0) or 0.0),
                    "missing_requirements": list(response.get("missing_requirements", [])),
                    "remediation_hints": list(response.get("remediation_hints", [])),
                }
            )
            response["history_record"] = (
                _to_jsonable(history_result.get("event", {}))
                if isinstance(history_result, dict) and isinstance(history_result.get("event"), dict)
                else {}
            )
            refreshed_profile = selected
            refreshed_template = selected_template
            refreshed_catalog = self.model_bridge_profiles(task=bridge_kind, limit=256)
            refreshed_rows = refreshed_catalog.get("profiles", []) if isinstance(refreshed_catalog, dict) else []
            if isinstance(refreshed_rows, list):
                for row in refreshed_rows:
                    if not isinstance(row, dict):
                        continue
                    if str(row.get("profile_id", "") or "").strip().lower() != clean_profile_id:
                        continue
                    refreshed_profile = row
                    launch_rows = row.get("launch_templates", [])
                    if isinstance(launch_rows, list):
                        for launch_row in launch_rows:
                            if not isinstance(launch_row, dict):
                                continue
                            if str(launch_row.get("template_id", "") or "").strip().lower() == clean_template_id:
                                refreshed_template = launch_row
                                break
                    break
            response["profile"] = _to_jsonable(refreshed_profile)
            response["template"] = _to_jsonable(refreshed_template)
            if isinstance(refreshed_profile, dict):
                response["recommended_template_id"] = str(
                    refreshed_profile.get("recommended_launch_template_id", "") or ""
                ).strip()
                response["profile_launch_health"] = _to_jsonable(
                    refreshed_profile.get("launch_health", {})
                    if isinstance(refreshed_profile.get("launch_health"), dict)
                    else {}
                )
            if isinstance(refreshed_template, dict) and isinstance(refreshed_template.get("health"), dict):
                response["template_health"] = _to_jsonable(refreshed_template.get("health", {}))
            else:
                response["template_health"] = _to_jsonable(
                    self._model_launch_template_health(
                        bridge_kind=bridge_kind,
                        profile_id=clean_profile_id,
                        template_id=clean_template_id,
                        template_ready=template_ready,
                        base_recommended=bool(selected_template.get("recommended", False)),
                    )
                )
            attempt_execution_diff = self._model_launch_execution_diff(
                requested_template_id=requested_template_id,
                executed_template_id=clean_template_id,
                requested_template=requested_template,
                executed_template=refreshed_template if isinstance(refreshed_template, dict) else selected_template,
            )
            root_execution_diff = self._model_launch_execution_diff(
                requested_template_id=original_requested_template_id,
                executed_template_id=clean_template_id,
                requested_template=original_requested_template,
                executed_template=refreshed_template if isinstance(refreshed_template, dict) else selected_template,
            )
            current_attempt = _to_jsonable(
                {
                    "attempt_index": attempt_index,
                    "attempt_chain_id": attempt_chain_id,
                    "retry_trigger": str(_retry_trigger or "").strip().lower(),
                    "status": str(response.get("status", "unknown") or "unknown").strip().lower() or "unknown",
                    "ready": bool(response.get("ready", False)),
                    "requested_template_id": requested_template_id,
                    "executed_template_id": clean_template_id,
                    "launcher": launcher,
                    "requested_launcher": str(requested_template.get("launcher", "") or "").strip().lower(),
                    "fallback_applied": fallback_applied,
                    "fallback_reason": fallback_reason,
                    "duration_s": float(response.get("duration_s", 0.0) or 0.0),
                    "history_record": response.get("history_record", {}),
                    "execution_diff": attempt_execution_diff,
                }
            )
            combined_attempt_chain = list(_attempt_chain or [])
            combined_attempt_chain.append(current_attempt)
            failure_like = self._is_model_launch_failure_like(
                {
                    "status": str(response.get("status", "unknown") or "unknown"),
                    "ready": bool(response.get("ready", False)),
                }
            )
            response_retry_policy = self._model_launch_retry_policy(
                bridge_kind=bridge_kind,
                profile_id=clean_profile_id,
                requested_template=requested_template,
                current_template=refreshed_template if isinstance(refreshed_template, dict) else selected_template,
                recommended_template_id=str(
                    (refreshed_profile.get("recommended_launch_template_id", "") if isinstance(refreshed_profile, dict) else "")
                    or ""
                ),
                attempt_index=attempt_index,
                max_attempts=bounded_max_attempts,
                failure_like=failure_like,
                retry_profile=retry_profile,
                retry_base_delay_ms=retry_base_delay_ms,
                retry_max_delay_ms=retry_max_delay_ms,
                retry_jitter_ms=retry_jitter_ms,
                retry_prefer_recommended=retry_prefer_recommended,
            )
            current_attempt["retry_policy"] = _to_jsonable(response_retry_policy)
            current_attempt["retry_requested_profile"] = str(
                response_retry_policy.get("requested_profile", "") or ""
            ).strip().lower()
            current_attempt["retry_profile"] = str(response_retry_policy.get("profile", "") or "").strip().lower()
            current_attempt["retry_profile_adjusted"] = bool(response_retry_policy.get("profile_adjusted", False))
            current_attempt["retry_profile_adjustment_reason"] = str(
                response_retry_policy.get("profile_adjustment_reason", "") or ""
            ).strip().lower()
            current_attempt["retry_strategy"] = str(response_retry_policy.get("strategy", "") or "").strip().lower()
            current_attempt["retry_strategy_score"] = round(
                float(
                    (
                        response_retry_policy.get("strategy_health", {})
                        if isinstance(response_retry_policy.get("strategy_health"), dict)
                        else {}
                    ).get("score", 0.0)
                    or 0.0
                ),
                4,
            )
            current_attempt["retry_escalation_mode"] = str(
                response_retry_policy.get("escalation_mode", "") or ""
            ).strip().lower()
            current_attempt["retry_delay_ms"] = int(response_retry_policy.get("delay_ms", 0) or 0)
            current_attempt["retry_prefer_recommended"] = bool(
                response_retry_policy.get("prefer_recommended", False)
            )
            response["attempt_chain"] = _to_jsonable(combined_attempt_chain)
            response["attempt_count"] = len(combined_attempt_chain)
            response["attempt_chain_id"] = attempt_chain_id
            response["execution_diff"] = _to_jsonable(root_execution_diff)
            response["attempt_execution_diff"] = _to_jsonable(attempt_execution_diff)
            response["requested_template_id"] = original_requested_template_id
            response["requested_template"] = _to_jsonable(original_requested_template)
            response["root_requested_template_id"] = original_requested_template_id
            response["attempt_requested_template_id"] = requested_template_id
            response["retry_applied"] = len(combined_attempt_chain) > 1
            response["retry_policy"] = _to_jsonable(response_retry_policy)
            if response.get("fallback_applied"):
                response.setdefault(
                    "message",
                    f"Auto-fallback switched launch execution from {requested_template_id} to {clean_template_id}.",
                )
            exhausted_attempts = list(dict.fromkeys(attempted_template_ids + [clean_template_id]))
            if retry_on_failure and bounded_max_attempts > attempt_index and failure_like:
                preferred_retry_template_id = (
                    str(response_retry_policy.get("recommended_template_id", "") or "").strip().lower()
                    if bool(response_retry_policy.get("prefer_recommended", False))
                    else ""
                )
                retry_candidate = self._pick_model_launch_retry_template(
                    profile=refreshed_profile if isinstance(refreshed_profile, dict) else selected,
                    exclude_template_ids=exhausted_attempts,
                    allow_unready=allow_unready,
                    preferred_template_id=preferred_retry_template_id,
                )
                if isinstance(retry_candidate, dict):
                    retry_template_id = str(retry_candidate.get("template_id", "") or "").strip().lower()
                    if retry_template_id:
                        retry_delay_ms = int(response_retry_policy.get("delay_ms", 0) or 0)
                        current_attempt["retry_target_template_id"] = retry_template_id
                        current_attempt["retry_delay_ms"] = retry_delay_ms
                        current_attempt["retry_backoff_applied"] = retry_delay_ms > 0
                        response["attempt_chain"] = _to_jsonable(combined_attempt_chain)
                        response["retry_reason"] = "prior_attempt_failure"
                        response["retry_target_template_id"] = retry_template_id
                        response["retry_delay_ms"] = retry_delay_ms
                        response["retry_backoff_applied"] = retry_delay_ms > 0
                        if retry_delay_ms > 0:
                            time.sleep(max(0.0, min(float(retry_delay_ms), 2_500.0) / 1000.0))
                        retry_response = self.execute_model_launch_template(
                            profile_id=clean_profile_id,
                            template_id=retry_template_id,
                            replace=replace,
                            wait_ready=wait_ready,
                            timeout_s=timeout_s,
                            force=force,
                            allow_unready=allow_unready,
                            probe=probe,
                            auto_fallback=False,
                            retry_on_failure=retry_on_failure,
                            max_attempts=bounded_max_attempts,
                            retry_profile=retry_profile,
                            retry_base_delay_ms=retry_base_delay_ms,
                            retry_max_delay_ms=retry_max_delay_ms,
                            retry_jitter_ms=retry_jitter_ms,
                            retry_prefer_recommended=retry_prefer_recommended,
                            _attempt_chain=combined_attempt_chain,
                            _attempted_template_ids=exhausted_attempts,
                            _attempt_index=attempt_index + 1,
                            _attempt_chain_id=attempt_chain_id,
                            _original_requested_template_id=original_requested_template_id,
                            _original_requested_template=original_requested_template,
                            _retry_trigger="prior_attempt_failure",
                        )
                        if isinstance(retry_response, dict):
                            retry_response = _to_jsonable(retry_response)
                            retry_response["retry_applied"] = True
                            retry_response.setdefault("retry_reason", "prior_attempt_failure")
                            retry_response.setdefault("retry_target_template_id", retry_template_id)
                            retry_response.setdefault("retry_delay_ms", retry_delay_ms)
                            retry_response.setdefault("retry_backoff_applied", retry_delay_ms > 0)
                            retry_response.setdefault(
                                "retry_source_event_id",
                                int(((response.get("history_record", {}) if isinstance(response.get("history_record", {}), dict) else {}).get("event_id", 0) or 0)),
                            )
                            return retry_response
                response["retry_candidates_exhausted"] = True
                response["attempt_chain"] = _to_jsonable(combined_attempt_chain)
            return response

        if not template_ready and not allow_unready:
            return _finish({
                "status": "error",
                "message": f"launch template '{clean_template_id}' is not ready",
                "profile_id": clean_profile_id,
                "template_id": clean_template_id,
                "profile": _to_jsonable(selected),
                "template": _to_jsonable(selected_template),
                "missing_requirements": missing_requirements,
                "remediation_hints": remediation_hints,
                "ready": False,
            })

        recommendations = list(remediation_hints)
        if fallback_applied:
            recommendations.append(
                f"Auto-fallback switched from {requested_template_id} to {clean_template_id} because the requested launcher was {fallback_reason.replace('+', ', ')}."
            )
        if bridge_kind == "reasoning":
            should_restart = not manual_only and (autostart_capable or launcher in {"llama-server", "reasoning_bridge"})
            apply_payload = self.apply_local_reasoning_bridge_profile(
                profile_id=clean_profile_id,
                replace=replace,
                restart=should_restart,
                wait_ready=wait_ready,
                timeout_s=timeout_s,
                force=force,
                override_updates=template_patch,
                template_id=clean_template_id,
            )
            if str((apply_payload or {}).get("status", "")).strip().lower() == "error":
                return _finish({
                    **(_to_jsonable(apply_payload) if isinstance(apply_payload, dict) else {"status": "error", "message": "launch execution failed"}),
                    "profile_id": clean_profile_id,
                    "template_id": clean_template_id,
                    "profile": _to_jsonable(selected),
                    "template": _to_jsonable(selected_template),
                    "ready": False,
                })
            probe_payload: Optional[Dict[str, Any]] = None
            if probe and not should_restart:
                probe_payload = self.probe_local_reasoning_bridge(force=True)
            bridge_payload = (
                probe_payload
                if isinstance(probe_payload, dict)
                else apply_payload.get("bridge", {}) if isinstance(apply_payload, dict) else {}
            )
            runtime_payload = self.model_runtime_supervisors(
                preferred_model_name=str(selected.get("name", "") or "").strip().lower(),
                limit=8,
            )
            ready = bool(bridge_payload.get("ready", False)) if isinstance(bridge_payload, dict) else False
            status = "success"
            if probe and not ready:
                status = "degraded"
                if not recommendations:
                    recommendations.append("The reasoning endpoint was applied but did not probe as ready. Verify the endpoint or start the managed launcher.")
            return _finish({
                "status": status,
                "bridge_kind": bridge_kind,
                "profile_id": clean_profile_id,
                "template_id": clean_template_id,
                "launcher": launcher,
                "manual_only": manual_only,
                "autostart_capable": autostart_capable,
                "ready": ready,
                "profile": _to_jsonable(selected),
                "template": _to_jsonable(selected_template),
                "override_patch": _to_jsonable(template_patch),
                "missing_requirements": missing_requirements,
                "remediation_hints": remediation_hints,
                "bridge": _to_jsonable(bridge_payload),
                "apply": _to_jsonable(apply_payload),
                "probe_result": _to_jsonable(probe_payload) if isinstance(probe_payload, dict) else None,
                "reasoning_runtime": _to_jsonable(runtime_payload),
                "recommendations": _to_jsonable(recommendations),
            })

        if bridge_kind == "stt":
            apply_payload = self.apply_local_stt_profile(
                profile_id=clean_profile_id,
                replace=replace,
                restart_voice_if_running=True,
                override_updates=template_patch,
                template_id=clean_template_id,
            )
            if str((apply_payload or {}).get("status", "")).strip().lower() == "error":
                return _finish({
                    **(_to_jsonable(apply_payload) if isinstance(apply_payload, dict) else {"status": "error", "message": "launch execution failed"}),
                    "profile_id": clean_profile_id,
                    "template_id": clean_template_id,
                    "profile": _to_jsonable(selected),
                    "template": _to_jsonable(selected_template),
                    "ready": False,
                })
            stt_diagnostics = apply_payload.get("stt_diagnostics") if isinstance(apply_payload, dict) else {}
            if not isinstance(stt_diagnostics, dict):
                stt_diagnostics = {}
            stt_policy = apply_payload.get("stt_policy") if isinstance(apply_payload, dict) else {}
            if not isinstance(stt_policy, dict):
                stt_policy = self.get_stt_policy(history_limit=120, source="launch-template")
            runtime_profile = apply_payload.get("runtime_profile") if isinstance(apply_payload, dict) else {}
            if not isinstance(runtime_profile, dict):
                runtime_profile = self._stt_runtime_profile_status()
            ready = bool(stt_diagnostics.get("available", False)) or bool(runtime_profile.get("available", False))
            status = "success" if ready else "degraded"
            if not ready and not recommendations:
                recommendations.append("The STT runtime was applied but the voice stack is not reporting ready yet. Verify the selected local model path.")
            return _finish({
                "status": status,
                "bridge_kind": bridge_kind,
                "profile_id": clean_profile_id,
                "template_id": clean_template_id,
                "launcher": launcher,
                "manual_only": manual_only,
                "autostart_capable": autostart_capable,
                "ready": ready,
                "profile": _to_jsonable(selected),
                "template": _to_jsonable(selected_template),
                "override_patch": _to_jsonable(template_patch),
                "missing_requirements": missing_requirements,
                "remediation_hints": remediation_hints,
                "apply": _to_jsonable(apply_payload),
                "stt_diagnostics": _to_jsonable(stt_diagnostics),
                "stt_policy": _to_jsonable(stt_policy),
                "runtime_profile": _to_jsonable(runtime_profile),
                "recommendations": _to_jsonable(recommendations),
            })

        if bridge_kind == "tts":
            execution_backend = str(
                template_patch.get("execution_backend", selected.get("execution_backend", ""))
                or ""
            ).strip().lower()
            should_restart = not manual_only
            apply_payload = self.apply_local_neural_tts_profile(
                profile_id=clean_profile_id,
                replace=replace,
                restart=should_restart,
                wait_ready=wait_ready,
                timeout_s=timeout_s,
                force=force,
                override_updates=template_patch,
                template_id=clean_template_id,
            )
            if str((apply_payload or {}).get("status", "")).strip().lower() == "error":
                return _finish({
                    **(_to_jsonable(apply_payload) if isinstance(apply_payload, dict) else {"status": "error", "message": "launch execution failed"}),
                    "profile_id": clean_profile_id,
                    "template_id": clean_template_id,
                    "profile": _to_jsonable(selected),
                    "template": _to_jsonable(selected_template),
                    "ready": False,
                })
            probe_payload: Optional[Dict[str, Any]] = None
            if probe and manual_only and execution_backend == "openai_http":
                probe_payload = self.probe_local_neural_tts_bridge(force=True)
            bridge_payload = (
                probe_payload
                if isinstance(probe_payload, dict)
                else apply_payload.get("bridge", {}) if isinstance(apply_payload, dict) else {}
            )
            tts_diagnostics = apply_payload.get("tts_diagnostics") if isinstance(apply_payload, dict) else {}
            if not isinstance(tts_diagnostics, dict) or not tts_diagnostics:
                tts_diagnostics = self.get_tts_diagnostics(history_limit=24)
            neural_runtime = apply_payload.get("neural_runtime") if isinstance(apply_payload, dict) else {}
            if not isinstance(neural_runtime, dict) or not neural_runtime:
                providers = tts_diagnostics.get("providers", {}) if isinstance(tts_diagnostics, dict) else {}
                local_provider = providers.get("local", {}) if isinstance(providers, dict) else {}
                neural_runtime = (
                    dict(local_provider.get("neural_runtime", {}))
                    if isinstance(local_provider, dict) and isinstance(local_provider.get("neural_runtime", {}), dict)
                    else {}
                )
            ready = bool(neural_runtime.get("ready", False))
            if not ready and execution_backend == "openai_http" and isinstance(bridge_payload, dict):
                ready = bool(bridge_payload.get("ready", False))
            if not ready and execution_backend in {"command", "coqui_cli"}:
                ready = str((apply_payload or {}).get("status", "")).strip().lower() == "success"
            status = "success" if ready else "degraded"
            if not ready and not recommendations:
                recommendations.append("The TTS runtime was applied but is not reporting ready yet. Check the selected launcher diagnostics.")
            return _finish({
                "status": status,
                "bridge_kind": bridge_kind,
                "profile_id": clean_profile_id,
                "template_id": clean_template_id,
                "launcher": launcher,
                "manual_only": manual_only,
                "autostart_capable": autostart_capable,
                "execution_backend": execution_backend,
                "ready": ready,
                "profile": _to_jsonable(selected),
                "template": _to_jsonable(selected_template),
                "override_patch": _to_jsonable(template_patch),
                "missing_requirements": missing_requirements,
                "remediation_hints": remediation_hints,
                "bridge": _to_jsonable(bridge_payload),
                "apply": _to_jsonable(apply_payload),
                "probe_result": _to_jsonable(probe_payload) if isinstance(probe_payload, dict) else None,
                "neural_runtime": _to_jsonable(neural_runtime),
                "tts_diagnostics": _to_jsonable(tts_diagnostics),
                "recommendations": _to_jsonable(recommendations),
            })

        if bridge_kind == "vision":
            apply_payload = self.apply_local_vision_profile(
                profile_id=clean_profile_id,
                override_updates=template_patch,
                template_id=clean_template_id,
            )
            if str((apply_payload or {}).get("status", "")).strip().lower() == "error":
                return _finish({
                    **(_to_jsonable(apply_payload) if isinstance(apply_payload, dict) else {"status": "error", "message": "launch execution failed"}),
                    "profile_id": clean_profile_id,
                    "template_id": clean_template_id,
                    "profile": _to_jsonable(selected),
                    "template": _to_jsonable(selected_template),
                    "ready": False,
                })
            vision_runtime = apply_payload.get("vision_runtime") if isinstance(apply_payload, dict) else {}
            if not isinstance(vision_runtime, dict):
                vision_runtime = {}
            runtime_profile = apply_payload.get("runtime_profile") if isinstance(apply_payload, dict) else {}
            if not isinstance(runtime_profile, dict):
                runtime_profile = self._vision_runtime_profile_status()
            ready = bool(apply_payload.get("ready", False))
            status = "success" if ready else "degraded"
            if not ready and not recommendations:
                recommendations.append("The selected vision runtime did not finish loading. Check the artifact path and runtime diagnostics.")
            return _finish({
                "status": status,
                "bridge_kind": bridge_kind,
                "profile_id": clean_profile_id,
                "template_id": clean_template_id,
                "launcher": launcher,
                "manual_only": manual_only,
                "autostart_capable": autostart_capable,
                "ready": ready,
                "profile": _to_jsonable(selected),
                "template": _to_jsonable(selected_template),
                "override_patch": _to_jsonable(template_patch),
                "missing_requirements": missing_requirements,
                "remediation_hints": remediation_hints,
                "apply": _to_jsonable(apply_payload),
                "vision_runtime": _to_jsonable(vision_runtime),
                "runtime_profile": _to_jsonable(runtime_profile),
                "recommendations": _to_jsonable(recommendations),
            })

        return _finish({
            "status": "error",
            "message": f"unsupported bridge kind: {bridge_kind or 'unknown'}",
            "profile_id": clean_profile_id,
            "template_id": clean_template_id,
            "profile": _to_jsonable(selected),
            "template": _to_jsonable(selected_template),
            "ready": False,
        })

    def probe_local_reasoning_bridge(self, *, force: bool = True) -> Dict[str, Any]:
        planner = getattr(self.kernel, "planner", None)
        if planner is None:
            return {"status": "error", "message": "planner unavailable", "ready": False}
        fn = getattr(planner, "probe_local_reasoning_bridge", None)
        if not callable(fn):
            return {"status": "unavailable", "message": "planner reasoning bridge unavailable", "ready": False}
        try:
            payload = fn(force=bool(force))
            return _to_jsonable(payload) if isinstance(payload, dict) else {"status": "error", "message": "invalid payload", "ready": False}
        except Exception as exc:  # noqa: BLE001
            return {"status": "error", "message": str(exc), "ready": False}

    def restart_local_reasoning_bridge(
        self,
        *,
        wait_ready: bool = True,
        timeout_s: Optional[float] = None,
        reason: str = "desktop-ui",
        force: bool = True,
    ) -> Dict[str, Any]:
        planner = getattr(self.kernel, "planner", None)
        if planner is None:
            return {"status": "error", "message": "planner unavailable", "ready": False}
        fn = getattr(planner, "restart_local_reasoning_bridge", None)
        if not callable(fn):
            return {"status": "unavailable", "message": "planner reasoning bridge unavailable", "ready": False}
        try:
            payload = fn(wait_ready=bool(wait_ready), timeout_s=timeout_s, reason=str(reason or "desktop-ui"), force=bool(force))
            return _to_jsonable(payload) if isinstance(payload, dict) else {"status": "error", "message": "invalid payload", "ready": False}
        except Exception as exc:  # noqa: BLE001
            return {"status": "error", "message": str(exc), "ready": False}

    def restart_reasoning_runtime(
        self,
        *,
        preferred_model_name: str = "",
        prompt: str = "",
        load_all: bool = False,
        force_reload: bool = True,
        probe: bool = True,
        clear_all: bool = False,
        restart_bridge: bool = False,
    ) -> Dict[str, Any]:
        normalized_preferred = str(preferred_model_name or "").strip().lower()
        clean_prompt = str(prompt or "").strip()
        bridge_before = self.get_local_reasoning_bridge_status(probe=False)
        bridge_restart_payload: Optional[Dict[str, Any]] = None
        should_restart_bridge = bool(restart_bridge)
        if bool(bridge_before.get("configured", False)) and bool(bridge_before.get("managed", False)):
            if bool(force_reload) or not bool(bridge_before.get("ready", False)) or not bool(bridge_before.get("running", False)):
                should_restart_bridge = True
        if should_restart_bridge:
            bridge_restart_payload = self.restart_local_reasoning_bridge(
                wait_ready=True,
                reason="desktop_reasoning_restart",
                force=bool(force_reload),
            )
        reset_payload = self.reset_reasoning_runtime(
            model_name=normalized_preferred,
            clear_all=bool(clear_all or (load_all and not normalized_preferred)),
        )
        warm_payload = self.warm_reasoning_runtime(
            preferred_model_name=normalized_preferred,
            load_all=bool(load_all),
            force_reload=bool(force_reload),
        )
        probe_payload: Optional[Dict[str, Any]] = None
        if bool(probe):
            probe_payload = self.probe_reasoning_runtime(
                preferred_model_name=normalized_preferred,
                prompt=clean_prompt,
                force_reload=False,
            )
        runtime_payload = self.model_runtime_supervisors(
            preferred_model_name=normalized_preferred,
            limit=8,
        )
        reasoning_payload = (
            runtime_payload.get("reasoning", {})
            if isinstance(runtime_payload.get("reasoning"), dict)
            else {}
        )
        recovered = bool(reasoning_payload.get("runtime_ready", False))
        stage_rows: list[Dict[str, Any]] = [
            {
                "stage": "reset",
                "status": str(reset_payload.get("status", "unknown")),
                "message": str(reset_payload.get("message", "") or ""),
                "removed_count": int(reset_payload.get("removed_count", 0) or 0),
            },
            {
                "stage": "warm",
                "status": str(warm_payload.get("status", "unknown")),
                "message": str(warm_payload.get("message", "") or ""),
                "count": int(warm_payload.get("count", 0) or 0),
            },
        ]
        if isinstance(bridge_restart_payload, dict):
            stage_rows.insert(
                0,
                {
                    "stage": "bridge_restart",
                    "status": str(bridge_restart_payload.get("status", "unknown")),
                    "message": str(bridge_restart_payload.get("message", "") or ""),
                    "pid": int(bridge_restart_payload.get("pid", 0) or 0),
                },
            )
        if isinstance(probe_payload, dict):
            stage_rows.append(
                {
                    "stage": "probe",
                    "status": str(probe_payload.get("status", "unknown")),
                    "message": str(probe_payload.get("message", "") or ""),
                    "model": str(probe_payload.get("model", "") or ""),
                }
            )
        recommendations: list[str] = []
        if str(warm_payload.get("status", "")).strip().lower() != "success":
            recommendations.append(
                "Warmup did not recover a ready reasoning runtime. Check the selected model backend, path, and local runtime dependencies."
            )
        if bool(probe) and isinstance(probe_payload, dict) and str(probe_payload.get("status", "")).strip().lower() != "success":
            recommendations.append(
                "Probe failed after restart. Inspect probe errors and runtime cooldown state before routing harder requests to this model."
            )
        if not recovered:
            recommendations.append(
                "No reasoning runtime is currently ready. Narrow the preferred model filter or use force reload to rebuild the local runtime."
            )
        if recovered and not recommendations:
            recommendations.append(
                "Reasoning runtime recovered. Keep probe enabled so future failures are detected before the planner routes complex local work."
            )
        status = "error"
        if recovered:
            status = "success"
        elif str(reset_payload.get("status", "")).strip().lower() == "success" or str(warm_payload.get("status", "")).strip().lower() == "success":
            status = "degraded"
        message = "Reasoning runtime restart completed."
        if not recovered:
            message = (
                "Reasoning runtime restart completed without a fully ready runtime."
                if status == "degraded"
                else "Reasoning runtime restart failed."
            )
        return {
            "status": status,
            "message": message,
            "preferred_model_name": normalized_preferred,
            "load_all": bool(load_all),
            "force_reload": bool(force_reload),
            "probe": bool(probe),
            "clear_all": bool(clear_all or (load_all and not normalized_preferred)),
            "restart_bridge": bool(should_restart_bridge),
            "recovered": recovered,
            "active_model": str(reasoning_payload.get("active_model", "") or ""),
            "active_backend": str(reasoning_payload.get("active_backend", "") or ""),
            "stages": stage_rows,
            "bridge": bridge_restart_payload if isinstance(bridge_restart_payload, dict) else bridge_before,
            "reset": reset_payload,
            "warm": warm_payload,
            "probe_result": probe_payload,
            "runtime": runtime_payload,
            "recommendations": recommendations[:6],
        }

    def runtime_health_summary(
        self,
        *,
        stack_name: str = "desktop_agent",
        preferred_model_name: str = "",
        limit_per_task: int = 4,
        runtime_limit: int = 8,
        requires_offline: bool = False,
        privacy_mode: bool = False,
        latency_sensitive: bool = False,
        mission_profile: str = "balanced",
        cost_sensitive: bool = False,
        max_cost_units: Optional[float] = None,
        refresh_provider_credentials: bool = False,
        include_bridge_context: bool = False,
        refresh_rust_caps: bool = False,
        probe_tts_bridge: bool = True,
        record_history: bool = True,
    ) -> Dict[str, Any]:
        normalized_stack = str(stack_name or "desktop_agent").strip().lower() or "desktop_agent"
        normalized_preferred = str(preferred_model_name or "").strip().lower()
        normalized_profile = str(mission_profile or "balanced").strip().lower() or "balanced"
        operations_payload = self.model_operations_summary(
            stack_name=normalized_stack,
            preferred_model_name=normalized_preferred,
            limit_per_task=limit_per_task,
            runtime_limit=runtime_limit,
            requires_offline=bool(requires_offline),
            privacy_mode=bool(privacy_mode),
            latency_sensitive=bool(latency_sensitive),
            mission_profile=normalized_profile,
            cost_sensitive=bool(cost_sensitive),
            max_cost_units=max_cost_units,
        )
        runtime_payload = (
            operations_payload.get("runtime_supervisors", {})
            if isinstance(operations_payload.get("runtime_supervisors"), dict)
            else self.model_runtime_supervisors(
                preferred_model_name=normalized_preferred,
                limit=runtime_limit,
            )
        )
        if not isinstance(runtime_payload, dict):
            runtime_payload = {}
        bridge_payload = self.bridge_status(
            include_context=bool(include_bridge_context),
            refresh_rust_caps=bool(refresh_rust_caps),
            include_tools=False,
            include_voice=False,
        )
        rust_payload = self.rust_runtime_load(timeout_s=1.8)
        tts_bridge_payload = self.get_local_neural_tts_bridge_status(probe=bool(probe_tts_bridge))
        provider_payload = (
            operations_payload.get("provider_credentials", {})
            if isinstance(operations_payload.get("provider_credentials"), dict)
            else self._provider_credentials_snapshot(refresh=bool(refresh_provider_credentials))
        )
        reasoning_payload = runtime_payload.get("reasoning", {}) if isinstance(runtime_payload.get("reasoning"), dict) else {}
        reasoning_bridge_payload = (
            reasoning_payload.get("bridge", {})
            if isinstance(reasoning_payload.get("bridge"), dict)
            else self.get_local_reasoning_bridge_status(probe=False)
        )
        if not isinstance(provider_payload, dict):
            provider_payload = self._provider_credentials_snapshot(refresh=bool(refresh_provider_credentials))
        vision_payload = runtime_payload.get("vision", {}) if isinstance(runtime_payload.get("vision"), dict) else {}
        launch_profile_payload = self.model_bridge_profiles(limit=192)
        launch_health_summary = (
            launch_profile_payload.get("launch_health_summary", {})
            if isinstance(launch_profile_payload.get("launch_health_summary"), dict)
            else {}
        )
        route_bundle = operations_payload.get("route_bundle", {}) if isinstance(operations_payload.get("route_bundle"), dict) else {}
        connector_diagnostics = (
            operations_payload.get("connector_diagnostics", {})
            if isinstance(operations_payload.get("connector_diagnostics"), dict)
            else {}
        )
        provider_rows = provider_payload.get("providers", {}) if isinstance(provider_payload.get("providers"), dict) else {}
        route_items = route_bundle.get("items", []) if isinstance(route_bundle.get("items"), list) else []
        route_provider_counts = (
            route_bundle.get("provider_counts", {})
            if isinstance(route_bundle.get("provider_counts"), dict)
            else {}
        )
        route_policy_summary = (
            route_bundle.get("launch_policy_summary", {})
            if isinstance(route_bundle.get("launch_policy_summary"), dict)
            else {}
        )
        route_warnings = [str(item).strip() for item in route_bundle.get("warnings", []) if str(item).strip()] if isinstance(route_bundle.get("warnings"), list) else []
        route_policy_local_provider_count = int(route_policy_summary.get("local_provider_task_count", 0) or 0)
        route_policy_monitored_count = int(route_policy_summary.get("policy_monitored_task_count", 0) or 0)
        route_policy_matched_count = int(route_policy_summary.get("matched_policy_task_count", 0) or 0)
        route_policy_unmatched_count = int(route_policy_summary.get("unmatched_policy_task_count", 0) or 0)
        route_policy_local_viable_count = int(route_policy_summary.get("local_viable_task_count", 0) or 0)
        route_policy_autonomy_safe_count = int(route_policy_summary.get("autonomy_safe_task_count", 0) or 0)
        route_policy_review_required_count = int(route_policy_summary.get("review_required_task_count", 0) or 0)
        route_policy_blacklisted_count = int(route_policy_summary.get("blacklisted_task_count", 0) or 0)
        route_policy_rerouted_count = int(route_policy_summary.get("rerouted_task_count", 0) or 0)
        route_policy_blocked_count = int(route_policy_summary.get("blocked_task_count", 0) or 0)
        route_policy_protected_count = int(route_policy_summary.get("protected_local_task_count", 0) or 0)
        route_policy_recovery_pending_count = int(route_policy_summary.get("recovery_pending_task_count", 0) or 0)
        reasoning_candidate_count = int(reasoning_payload.get("candidate_count", 0) or 0)
        reasoning_loaded_count = int(reasoning_payload.get("loaded_count", 0) or 0)
        reasoning_cooldown_count = int(reasoning_payload.get("cooldown_count", 0) or 0)
        reasoning_probe_healthy_count = int(reasoning_payload.get("probe_healthy_count", 0) or 0)
        reasoning_bridge_transport_count = int(reasoning_payload.get("bridge_transport_count", 0) or 0)
        reasoning_ready = bool(reasoning_payload.get("runtime_ready", False))
        reasoning_bridge_configured = bool(
            reasoning_bridge_payload.get("configured", False)
            or reasoning_bridge_payload.get("endpoint_configured", False)
            or reasoning_bridge_payload.get("server_command_configured", False)
        )
        reasoning_bridge_ready = bool(reasoning_bridge_payload.get("ready", False))
        reasoning_bridge_running = bool(reasoning_bridge_payload.get("running", False))
        vision_items = vision_payload.get("items", []) if isinstance(vision_payload.get("items"), list) else []
        vision_loaded_count = int(vision_payload.get("loaded_count", 0) or 0)
        vision_artifact_count = sum(
            1 for row in vision_items if isinstance(row, dict) and bool(row.get("artifact_exists", False))
        )
        launch_template_count = int(launch_health_summary.get("template_count", 0) or 0)
        launch_ready_template_count = int(launch_health_summary.get("ready_template_count", 0) or 0)
        launch_stable_ready_count = int(launch_health_summary.get("stable_ready_template_count", 0) or 0)
        launch_unstable_template_count = int(launch_health_summary.get("unstable_template_count", 0) or 0)
        launch_demoted_template_count = int(launch_health_summary.get("demoted_template_count", 0) or 0)
        launch_suppressed_template_count = int(launch_health_summary.get("suppressed_template_count", 0) or 0)
        launch_blacklisted_template_count = int(launch_health_summary.get("blacklisted_template_count", 0) or 0)
        launch_autonomous_ready_template_count = int(launch_health_summary.get("autonomous_ready_template_count", 0) or 0)
        launch_history_count = int(launch_health_summary.get("history_count", 0) or 0)
        bridge_ready = bool(bridge_payload.get("ready_for_workflow", False))
        rust_data = rust_payload.get("data", {}) if isinstance(rust_payload.get("data"), dict) else {}
        rust_overloaded = bool(rust_data.get("overloaded", False))
        rust_running = int(rust_data.get("running", 0) or 0)
        rust_queued = int(rust_data.get("queued", 0) or 0)
        tts_configured = bool(
            tts_bridge_payload.get("configured", False)
            or tts_bridge_payload.get("endpoint_configured", False)
            or tts_bridge_payload.get("server_command_configured", False)
        )
        tts_ready = bool(tts_bridge_payload.get("ready", False))
        tts_running = bool(tts_bridge_payload.get("running", False))
        ready_providers = [
            str(name)
            for name, row in provider_rows.items()
            if isinstance(row, dict) and bool(row.get("ready", row.get("present", False)))
        ]
        cloud_providers = ("groq", "nvidia", "elevenlabs")
        missing_cloud_providers = [
            name
            for name in cloud_providers
            if not bool((provider_rows.get(name, {}) if isinstance(provider_rows.get(name, {}), dict) else {}).get("ready", False))
        ]
        alerts: list[Dict[str, Any]] = []
        recommendations: list[str] = []
        seen_recommendations: set[str] = set()

        def add_alert(code: str, severity: str, message: str, recommendation: str = "") -> None:
            row = {
                "code": str(code),
                "severity": str(severity),
                "message": str(message),
            }
            if recommendation:
                row["recommendation"] = str(recommendation)
            alerts.append(row)
            if recommendation and recommendation not in seen_recommendations:
                recommendations.append(recommendation)
                seen_recommendations.add(recommendation)

        if len(route_items) == 0:
            add_alert(
                "route_bundle_empty",
                "blocker",
                "Model routing returned no runnable route candidates for the current stack and policy filters.",
                "Relax the routing filters or add compatible local/cloud model coverage for this stack.",
            )
        elif route_warnings:
            add_alert(
                "route_bundle_warnings",
                "warning",
                f"Routing emitted {len(route_warnings)} warning(s) for the current stack.",
                route_warnings[0],
            )
        if route_policy_blocked_count > 0:
            add_alert(
                "route_local_policy_blocked",
                "blocker" if bool(requires_offline) or route_policy_protected_count > 0 else "warning",
                f"{route_policy_blocked_count} local route(s) are blocked by launch autonomy policy or missing viable launchers.",
                "Recover the blocked local launcher profiles or relax offline/privacy constraints so routing can pivot to healthy cloud providers.",
            )
        elif route_policy_rerouted_count > 0:
            add_alert(
                "route_local_policy_rerouted",
                "info",
                f"{route_policy_rerouted_count} local route(s) were rerouted away from degraded launchers.",
                "Review the affected local runtime profiles and recover them before restoring unattended local-first routing.",
            )
        if route_policy_blacklisted_count > 0:
            add_alert(
                "route_local_policy_blacklisted",
                "warning",
                f"{route_policy_blacklisted_count} local route(s) map to blacklisted launch templates.",
                "Inspect launch history, cooldown windows, and the active retry profile before allowing those local runtimes back into autonomous routing.",
            )
        if route_policy_monitored_count > 0 and route_policy_autonomy_safe_count <= 0:
            add_alert(
                "route_local_policy_no_autonomy_safe_routes",
                "warning",
                "No monitored local routes currently qualify as autonomy-safe.",
                "Stabilize the recommended local launchers or keep cloud failover available for unattended execution.",
            )
        if route_policy_unmatched_count > 0:
            add_alert(
                "route_local_policy_unmatched_profiles",
                "warning",
                f"{route_policy_unmatched_count} local route(s) could not be matched to a launch-policy profile.",
                "Align model inventory metadata and bridge profile detection so route selection can evaluate launcher health before choosing local execution.",
            )
        if reasoning_candidate_count <= 0:
            add_alert(
                "reasoning_no_candidates",
                "blocker",
                "No local reasoning runtime candidates matched the current preferred model filter.",
                "Clear the preferred model filter or install a matching local reasoning artifact.",
            )
        elif not reasoning_ready:
            add_alert(
                "reasoning_runtime_unready",
                "warning",
                "Local reasoning candidates exist but none are currently ready for planner work.",
                "Run a supervised reasoning restart to rebuild the active local runtime before routing harder tasks locally.",
            )
        if reasoning_candidate_count > 0 and reasoning_probe_healthy_count <= 0:
            add_alert(
                "reasoning_probe_unhealthy",
                "warning",
                "No reasoning candidate has a recent healthy runtime probe.",
                "Probe the preferred reasoning model after warmup so routing decisions are based on a verified runtime.",
            )
        if reasoning_cooldown_count > 0:
            add_alert(
                "reasoning_cooldown_active",
                "warning",
                f"{reasoning_cooldown_count} reasoning runtime candidate(s) are cooling down after repeated failures.",
                "Wait for cooldown expiry or force a restart on the affected local reasoning runtime.",
            )
        if reasoning_bridge_configured and not reasoning_bridge_ready:
            add_alert(
                "reasoning_bridge_not_ready",
                "warning",
                "Local reasoning bridge is configured but not ready.",
                "Start or restart the managed reasoning bridge before routing bridge-backed local models.",
            )
        if not bridge_ready:
            add_alert(
                "bridge_not_ready",
                "blocker",
                "Python and Rust bridge readiness is below workflow level.",
                "Refresh bridge diagnostics and recover the Rust side before issuing higher-autonomy desktop workflows.",
            )
        if str(rust_payload.get("status", "")).strip().lower() != "success":
            add_alert(
                "rust_runtime_unavailable",
                "blocker",
                "Rust runtime load data is unavailable.",
                "Check the Rust runtime process and bridge health before depending on desktop execution paths.",
            )
        elif rust_overloaded:
            add_alert(
                "rust_runtime_overloaded",
                "warning",
                f"Rust runtime is overloaded with {rust_running} running and {rust_queued} queued request(s).",
                "Reduce queued execution pressure or wait for Rust permits to recover before dispatching more work.",
            )
        if tts_configured and not tts_ready:
            add_alert(
                "tts_bridge_not_ready",
                "warning",
                "Local neural TTS bridge is configured but not ready.",
                "Probe or restart the local neural TTS bridge so voice output can stay on the local path.",
            )
        if launch_demoted_template_count > 0:
            add_alert(
                "launch_templates_demoted",
                "warning",
                f"{launch_demoted_template_count} launch template(s) are currently demoted after repeated instability.",
                "Prefer the active recommended launcher or recover the demoted template before routing unattended recovery through it.",
            )
        elif launch_unstable_template_count > 0:
            add_alert(
                "launch_templates_unstable",
                "info",
                f"{launch_unstable_template_count} launch template(s) show recent instability patterns.",
                "Monitor launch failures and favor stable ready launchers for autonomous local runtime recovery.",
            )
        if launch_blacklisted_template_count > 0:
            add_alert(
                "launch_templates_blacklisted",
                "warning",
                f"{launch_blacklisted_template_count} launch template(s) are blacklisted by long-horizon autonomy policy.",
                "Keep those launchers out of autonomous routing until their recovery window and success history return them to a safe state.",
            )
        if launch_template_count > 0 and launch_autonomous_ready_template_count <= 0:
            add_alert(
                "launch_templates_no_autonomy_ready",
                "warning",
                "Launch templates exist, but none are currently autonomy-ready.",
                "Use manual review mode for local runtime recovery or restore a stable template before unattended operations rely on it.",
            )
        if missing_cloud_providers:
            add_alert(
                "cloud_provider_headroom_reduced",
                "warning",
                f"Cloud provider headroom is reduced: missing ready credentials for {', '.join(missing_cloud_providers)}.",
                "Configure Groq, NVIDIA, and ElevenLabs credentials so routing can fail over cleanly when local models are constrained.",
            )
        if vision_loaded_count <= 0 and vision_artifact_count > 0:
            add_alert(
                "vision_runtime_cold",
                "info",
                "Vision artifacts are present but no vision runtime is currently loaded.",
                "Warm the required local vision models before running UI-grounded perception tasks.",
            )

        for row in bridge_payload.get("recommendations", []) if isinstance(bridge_payload.get("recommendations"), list) else []:
            text = str(row or "").strip()
            if text and text not in seen_recommendations:
                recommendations.append(text)
                seen_recommendations.add(text)

        route_score = 1.0 if len(route_items) > 0 else 0.2
        if route_warnings:
            route_score = max(0.35, route_score - 0.18)
        if route_policy_review_required_count > 0:
            route_score = max(0.2, route_score - min(0.2, route_policy_review_required_count * 0.04))
        if route_policy_blocked_count > 0:
            route_score = max(0.1, route_score - min(0.4, route_policy_blocked_count * 0.12))
        elif route_policy_rerouted_count > 0:
            route_score = max(0.3, route_score - min(0.18, route_policy_rerouted_count * 0.05))
        elif route_policy_autonomy_safe_count > 0 and route_policy_local_provider_count > 0:
            route_score = min(1.0, route_score + 0.03)
        reasoning_score = 1.0 if reasoning_ready else (0.55 if reasoning_candidate_count > 0 else 0.05)
        if reasoning_cooldown_count > 0:
            reasoning_score = max(0.15, reasoning_score - 0.18)
        if reasoning_candidate_count > 0 and reasoning_probe_healthy_count <= 0:
            reasoning_score = max(0.1, reasoning_score - 0.15)
        reasoning_bridge_score = 1.0 if reasoning_bridge_ready else (
            0.72 if not reasoning_bridge_configured else (0.45 if reasoning_bridge_running else 0.15)
        )
        vision_score = 1.0 if vision_loaded_count > 0 else (0.65 if vision_artifact_count > 0 else 0.3)
        launch_score = 1.0 if launch_stable_ready_count > 0 else (0.7 if launch_ready_template_count > 0 else (0.45 if launch_template_count > 0 else 0.2))
        if launch_demoted_template_count > 0:
            launch_score = max(0.2, launch_score - min(0.35, launch_demoted_template_count * 0.08))
        elif launch_unstable_template_count > 0:
            launch_score = max(0.3, launch_score - min(0.18, launch_unstable_template_count * 0.04))
        if launch_suppressed_template_count > 0:
            launch_score = max(0.18, launch_score - min(0.14, launch_suppressed_template_count * 0.03))
        if launch_blacklisted_template_count > 0:
            launch_score = max(0.12, launch_score - min(0.28, launch_blacklisted_template_count * 0.06))
        if launch_template_count > 0 and launch_autonomous_ready_template_count <= 0:
            launch_score = min(launch_score, 0.5)
        elif launch_autonomous_ready_template_count > 0 and launch_blacklisted_template_count <= 0:
            launch_score = min(1.0, launch_score + 0.04)
        bridge_score = 1.0 if bridge_ready else (0.45 if str(bridge_payload.get("status", "")).strip().lower() in {"success", "degraded"} else 0.1)
        rust_score = 1.0 if str(rust_payload.get("status", "")).strip().lower() == "success" and not rust_overloaded else (
            0.45 if str(rust_payload.get("status", "")).strip().lower() == "success" else 0.1
        )
        provider_total = max(1, len(provider_rows))
        provider_score = min(1.0, max(0.15, len(ready_providers) / provider_total))
        voice_score = 1.0 if tts_ready else (0.7 if not tts_configured else (0.45 if tts_running else 0.15))
        weighted_score = (
            route_score * 0.11
            + reasoning_score * 0.22
            + reasoning_bridge_score * 0.10
            + vision_score * 0.07
            + launch_score * 0.06
            + bridge_score * 0.18
            + rust_score * 0.14
            + provider_score * 0.08
            + voice_score * 0.04
        )
        score = round(weighted_score * 100.0, 1)
        blocker_count = sum(1 for row in alerts if str(row.get("severity", "")).strip().lower() == "blocker")
        warning_count = sum(1 for row in alerts if str(row.get("severity", "")).strip().lower() == "warning")
        readiness = "success"
        if blocker_count > 0:
            readiness = "blocked"
        elif warning_count > 0 or score < 82.0:
            readiness = "degraded"
        subsystems = {
            "routing": {
                "status": "ready" if len(route_items) > 0 else "blocked",
                "ready": bool(route_items),
                "score": round(route_score * 100.0, 1),
                "stack_name": normalized_stack,
                "mission_profile": normalized_profile,
                "item_count": len(route_items),
                "provider_counts": route_provider_counts,
                "warning_count": len(route_warnings),
                "local_provider_task_count": route_policy_local_provider_count,
                "policy_monitored_count": route_policy_monitored_count,
                "matched_policy_count": route_policy_matched_count,
                "unmatched_policy_count": route_policy_unmatched_count,
                "local_viable_count": route_policy_local_viable_count,
                "autonomy_safe_count": route_policy_autonomy_safe_count,
                "review_required_count": route_policy_review_required_count,
                "blacklisted_count": route_policy_blacklisted_count,
                "rerouted_count": route_policy_rerouted_count,
                "blocked_count": route_policy_blocked_count,
                "recovery_pending_count": route_policy_recovery_pending_count,
            },
            "reasoning": {
                "status": "ready" if reasoning_ready else ("degraded" if reasoning_candidate_count > 0 else "blocked"),
                "ready": reasoning_ready,
                "score": round(reasoning_score * 100.0, 1),
                "candidate_count": reasoning_candidate_count,
                "loaded_count": reasoning_loaded_count,
                "probe_healthy_count": reasoning_probe_healthy_count,
                "cooldown_count": reasoning_cooldown_count,
                "bridge_transport_count": reasoning_bridge_transport_count,
                "active_model": str(reasoning_payload.get("active_model", "") or ""),
                "active_backend": str(reasoning_payload.get("active_backend", "") or ""),
                "message": str(reasoning_payload.get("message", "") or ""),
            },
            "reasoning_bridge": {
                "status": "ready" if reasoning_bridge_ready else ("optional" if not reasoning_bridge_configured else "degraded"),
                "ready": bool(reasoning_bridge_ready or not reasoning_bridge_configured),
                "score": round(reasoning_bridge_score * 100.0, 1),
                "configured": reasoning_bridge_configured,
                "running": reasoning_bridge_running,
                "transport_count": reasoning_bridge_transport_count,
                "message": str(reasoning_bridge_payload.get("message", "") or ""),
            },
            "vision": {
                "status": "ready" if vision_loaded_count > 0 else ("degraded" if vision_artifact_count > 0 else "idle"),
                "ready": bool(vision_loaded_count > 0),
                "score": round(vision_score * 100.0, 1),
                "loaded_count": vision_loaded_count,
                "artifact_count": vision_artifact_count,
                "device": str(vision_payload.get("device", "") or ""),
            },
            "launch_templates": {
                "status": "ready" if launch_stable_ready_count > 0 else ("degraded" if launch_template_count > 0 else "idle"),
                "ready": bool(launch_stable_ready_count > 0),
                "score": round(launch_score * 100.0, 1),
                "template_count": launch_template_count,
                "ready_count": launch_ready_template_count,
                "stable_ready_count": launch_stable_ready_count,
                "unstable_count": launch_unstable_template_count,
                "demoted_count": launch_demoted_template_count,
                "suppressed_count": launch_suppressed_template_count,
                "blacklisted_count": launch_blacklisted_template_count,
                "autonomous_ready_count": launch_autonomous_ready_template_count,
                "history_count": launch_history_count,
            },
            "bridge": {
                "status": "ready" if bridge_ready else "blocked",
                "ready": bridge_ready,
                "score": round(bridge_score * 100.0, 1),
                "ready_for_workflow": bridge_ready,
                "message": str(bridge_payload.get("message", "") or ""),
            },
            "rust_runtime": {
                "status": "ready" if str(rust_payload.get("status", "")).strip().lower() == "success" and not rust_overloaded else (
                    "degraded" if str(rust_payload.get("status", "")).strip().lower() == "success" else "blocked"
                ),
                "ready": bool(str(rust_payload.get("status", "")).strip().lower() == "success" and not rust_overloaded),
                "score": round(rust_score * 100.0, 1),
                "running": rust_running,
                "queued": rust_queued,
                "overloaded": rust_overloaded,
                "message": str(rust_payload.get("message", "") or ""),
            },
            "voice_bridge": {
                "status": "ready" if tts_ready else ("optional" if not tts_configured else "degraded"),
                "ready": bool(tts_ready or not tts_configured),
                "score": round(voice_score * 100.0, 1),
                "configured": tts_configured,
                "running": tts_running,
                "ready_flag": tts_ready,
                "message": str(tts_bridge_payload.get("message", "") or ""),
            },
            "providers": {
                "status": "ready" if len(missing_cloud_providers) == 0 else "degraded",
                "ready": bool(len(ready_providers) > 0),
                "score": round(provider_score * 100.0, 1),
                "ready_count": len(ready_providers),
                "total_count": len(provider_rows),
                "missing_cloud": missing_cloud_providers,
            },
        }
        payload = {
            "status": readiness,
            "generated_at": datetime.now(timezone.utc).isoformat(),
            "stack_name": normalized_stack,
            "preferred_model_name": normalized_preferred,
            "mission_profile": normalized_profile,
            "requires_offline": bool(requires_offline),
            "privacy_mode": bool(privacy_mode),
            "latency_sensitive": bool(latency_sensitive),
            "cost_sensitive": bool(cost_sensitive),
            "max_cost_units": max_cost_units,
            "score": score,
            "blocker_count": blocker_count,
            "warning_count": warning_count,
            "alerts": alerts[:20],
            "recommendations": recommendations[:12],
            "subsystems": subsystems,
            "model_operations": operations_payload,
            "runtime_supervisors": runtime_payload,
            "reasoning_bridge": reasoning_bridge_payload,
            "bridge_status": bridge_payload,
            "rust_runtime_load": rust_payload,
            "tts_local_neural_bridge": tts_bridge_payload,
            "provider_credentials": provider_payload,
            "connector_diagnostics": connector_diagnostics,
            "launch_health": launch_health_summary,
            "route_policy_summary": route_policy_summary,
        }
        if bool(record_history):
            history_record = self._record_runtime_health_snapshot(payload, force=False)
            payload["history_record"] = history_record if isinstance(history_record, dict) else {}
        return payload

    def warm_vision_runtime(self, *, models: Optional[list[str]] = None, force_reload: bool = False) -> Dict[str, Any]:
        self._initialize_context_stack()
        vision_engine = getattr(self, "_vision_engine", None)
        if vision_engine is None:
            return {"status": "error", "message": self._context_error or "vision engine unavailable"}
        fn = getattr(vision_engine, "warm_models", None)
        if not callable(fn):
            return {"status": "unavailable", "message": "vision warmup unavailable"}
        try:
            payload = fn(
                models=[str(item or "").strip().lower() for item in (models or []) if str(item or "").strip()],
                force_reload=bool(force_reload),
            )
            return _to_jsonable(payload) if isinstance(payload, dict) else {"status": "error", "message": "invalid payload"}
        except Exception as exc:  # noqa: BLE001
            return {"status": "error", "message": str(exc)}

    def reset_vision_runtime(self, *, models: Optional[list[str]] = None, clear_cache: bool = False) -> Dict[str, Any]:
        self._initialize_context_stack()
        vision_engine = getattr(self, "_vision_engine", None)
        if vision_engine is None:
            return {"status": "error", "message": self._context_error or "vision engine unavailable"}
        fn = getattr(vision_engine, "reset_models", None)
        if not callable(fn):
            return {"status": "unavailable", "message": "vision reset unavailable"}
        try:
            payload = fn(
                models=[str(item or "").strip().lower() for item in (models or []) if str(item or "").strip()],
                clear_cache=bool(clear_cache),
            )
            return _to_jsonable(payload) if isinstance(payload, dict) else {"status": "error", "message": "invalid payload"}
        except Exception as exc:  # noqa: BLE001
            return {"status": "error", "message": str(exc)}

    @staticmethod
    def _route_bundle_local_path(route_bundle: Dict[str, Any], *, task: str, fallback: str = "") -> str:
        if not isinstance(route_bundle, dict):
            return str(fallback or "").strip()
        selected_paths = route_bundle.get("selected_local_paths", {})
        if isinstance(selected_paths, dict):
            candidate = str(selected_paths.get(str(task or "").strip().lower(), "") or "").strip()
            if candidate:
                return candidate
        items = route_bundle.get("items", [])
        if isinstance(items, list):
            for row in items:
                if not isinstance(row, dict):
                    continue
                if str(row.get("task", "")).strip().lower() != str(task or "").strip().lower():
                    continue
                if str(row.get("provider", "")).strip().lower() != "local":
                    continue
                candidate = str(row.get("selected_path", "") or "").strip()
                if candidate:
                    return candidate
        return str(fallback or "").strip()

    @staticmethod
    def _route_bundle_task_row(route_bundle: Dict[str, Any], *, task: str) -> Dict[str, Any]:
        if not isinstance(route_bundle, dict):
            return {}
        items = route_bundle.get("items", [])
        if not isinstance(items, list):
            return {}
        clean_task = str(task or "").strip().lower()
        for row in items:
            if not isinstance(row, dict):
                continue
            if str(row.get("task", "")).strip().lower() != clean_task:
                continue
            if str(row.get("status", "")).strip().lower() != "success":
                continue
            return dict(row)
        return {}

    @staticmethod
    def _route_policy_surface(
        route_bundle: Dict[str, Any],
        *,
        task: str,
        supported_providers: set[str],
    ) -> Dict[str, Any]:
        route_item = DesktopBackendService._route_bundle_task_row(route_bundle, task=task)
        route_policy = (
            route_item.get("route_policy", {})
            if isinstance(route_item.get("route_policy", {}), dict)
            else {}
        )
        route_warning = str(route_item.get("route_warning", "") or "").strip()
        selected_provider = str(route_item.get("provider", "") or "").strip().lower()
        fallback_candidates: list[str] = []
        seen: set[str] = set()
        for item in route_policy.get("cloud_fallback_candidates", []) if isinstance(route_policy.get("cloud_fallback_candidates", []), list) else []:
            clean = str(item or "").strip().lower()
            if clean not in supported_providers or clean in seen:
                continue
            seen.add(clean)
            fallback_candidates.append(clean)
        recommended_provider = str(route_policy.get("recommended_provider", "") or "").strip().lower()
        if recommended_provider not in supported_providers:
            if selected_provider in supported_providers and not bool(route_item.get("route_blocked", False)):
                recommended_provider = selected_provider
            elif fallback_candidates:
                recommended_provider = fallback_candidates[0]
            else:
                recommended_provider = ""
        return {
            "route_item": dict(route_item),
            "route_policy": dict(route_policy),
            "route_warning": route_warning,
            "route_adjusted": bool(route_item.get("route_adjusted", False)),
            "route_blocked": bool(route_item.get("route_blocked", False)),
            "selected_provider": selected_provider,
            "selected_model": str(route_item.get("model", "") or "").strip(),
            "recommended_provider": recommended_provider,
            "fallback_candidates": fallback_candidates,
            "local_route_viable": bool(route_policy.get("local_route_viable", selected_provider == "local")),
            "autonomy_safe": bool(route_policy.get("autonomy_safe", selected_provider == "local")),
            "autonomous_allowed": bool(route_policy.get("autonomous_allowed", True)),
            "review_required": bool(route_policy.get("review_required", False)),
            "blacklisted": bool(route_policy.get("blacklisted", False)),
            "suppressed": bool(route_policy.get("suppressed", False)),
            "demoted": bool(route_policy.get("demoted", False)),
            "recovery_pending": bool(route_policy.get("recovery_pending", False)),
            "cooldown_hint_s": max(0, int(route_policy.get("cooldown_hint_s", 0) or 0)),
            "reason_code": str(route_policy.get("reason_code", route_item.get("route_adjustment_reason", "")) or "").strip().lower(),
            "reason": str(route_policy.get("reason", "") or "").strip(),
            "policy_monitored": bool(route_policy.get("policy_monitored", False)),
            "summary": (
                dict(route_bundle.get("launch_policy_summary", {}))
                if isinstance(route_bundle.get("launch_policy_summary", {}), dict)
                else {}
            ),
        }

    @staticmethod
    def _route_policy_remediation_hints(
        *,
        task: str,
        route_surface: Dict[str, Any],
        remote_ready: bool,
    ) -> list[Dict[str, Any]]:
        clean_task = str(task or "").strip().lower() or "task"
        title_task = clean_task.upper()
        reason_code = str(route_surface.get("reason_code", "") or "").strip().lower()
        reason = str(route_surface.get("reason", "") or "").strip()
        recommended_provider = str(route_surface.get("recommended_provider", "") or "").strip().lower()
        fallback_candidates = list(route_surface.get("fallback_candidates", [])) if isinstance(route_surface.get("fallback_candidates", []), list) else []
        hints: list[Dict[str, Any]] = []
        if bool(route_surface.get("route_adjusted", False)) and recommended_provider:
            hints.append(
                {
                    "code": f"{clean_task}_route_policy_rerouted",
                    "severity": "low",
                    "message": reason or f"{title_task} route rerouted to {recommended_provider} due to local launcher policy.",
                    "recommended_provider": recommended_provider,
                    "reason_code": reason_code,
                }
            )
        if bool(route_surface.get("route_blocked", False)):
            hints.append(
                {
                    "code": f"{clean_task}_route_policy_blocked",
                    "severity": "high" if not remote_ready else "medium",
                    "message": reason or f"Local {clean_task} route is currently blocked by launcher policy.",
                    "recommended_provider": recommended_provider,
                    "fallback_candidates": fallback_candidates,
                    "reason_code": reason_code,
                }
            )
        elif bool(route_surface.get("blacklisted", False)):
            hints.append(
                {
                    "code": f"{clean_task}_local_route_blacklisted",
                    "severity": "medium",
                    "message": reason or f"Local {clean_task} route is blacklisted due to sustained launcher instability.",
                    "recommended_provider": recommended_provider,
                    "reason_code": reason_code,
                }
            )
        cooldown_hint_s = max(0, int(route_surface.get("cooldown_hint_s", 0) or 0))
        if cooldown_hint_s > 0:
            hints.append(
                {
                    "code": f"{clean_task}_route_policy_cooldown",
                    "severity": "low",
                    "message": f"Local {clean_task} route is in recovery for about {cooldown_hint_s}s.",
                    "cooldown_hint_s": cooldown_hint_s,
                    "reason_code": reason_code,
                }
            )
        return hints

    def _provider_credentials_snapshot(self, *, refresh: bool = False) -> Dict[str, Any]:
        manager = getattr(self, "provider_credentials", None)
        if manager is None:
            return {"status": "unavailable", "providers": {}}
        try:
            payload = manager.refresh(overwrite_env=False) if refresh else manager.snapshot()
            return _to_jsonable(payload) if isinstance(payload, dict) else {"status": "error", "message": "invalid payload"}
        except Exception as exc:  # noqa: BLE001
            return {"status": "error", "message": str(exc), "providers": {}}

    def _provider_credentials_with_manifest_requirements(
        self,
        *,
        manifest_payload: Dict[str, Any],
        refresh: bool = False,
    ) -> Dict[str, Any]:
        snapshot = self._provider_credentials_snapshot(refresh=refresh)
        providers = snapshot.get("providers", {}) if isinstance(snapshot.get("providers", {}), dict) else {}
        required_providers = [
            str(item).strip().lower()
            for item in manifest_payload.get("providers", [])
            if str(item).strip()
        ] if isinstance(manifest_payload, dict) else []
        required_set = set(required_providers)
        provider_names = sorted(set(str(name).strip().lower() for name in providers.keys()) | required_set)
        verifier = getattr(self, "provider_verifier", None)
        latest_verifications = (
            verifier.latest_map(provider_names)
            if verifier is not None and hasattr(verifier, "latest_map")
            else {}
        )

        normalized_rows: Dict[str, Any] = {}
        ready_required_count = 0
        missing_required_count = 0
        for provider_name in provider_names:
            source_row = providers.get(provider_name, {})
            row = dict(source_row) if isinstance(source_row, dict) else {}
            latest_verification = latest_verifications.get(provider_name, {}) if isinstance(latest_verifications, dict) else {}
            row["provider"] = provider_name
            row["required_by_manifest"] = provider_name in required_set
            row["optional"] = provider_name not in required_set
            if isinstance(latest_verification, dict) and latest_verification:
                row["last_verification"] = latest_verification
                row["verification_status"] = str(latest_verification.get("status", "") or "").strip()
                row["verification_verified"] = bool(latest_verification.get("verified", False))
                row["verification_checked_at"] = str(latest_verification.get("checked_at", "") or "").strip()
                row["verification_summary"] = str(latest_verification.get("summary", "") or latest_verification.get("message", "") or "").strip()
            normalized_rows[provider_name] = row
            if provider_name in required_set:
                if bool(row.get("ready", False)):
                    ready_required_count += 1
                else:
                    missing_required_count += 1

        updated = dict(snapshot) if isinstance(snapshot, dict) else {"status": "error", "providers": {}}
        updated["providers"] = normalized_rows
        updated["required_count"] = len(required_set)
        updated["ready_required_count"] = ready_required_count
        updated["missing_required_count"] = missing_required_count
        updated["manifest_required_providers"] = sorted(required_set)
        return updated

    def _requires_offline_reasoning(self) -> bool:
        self._provider_credentials_snapshot(refresh=True)
        snapshot_fn = getattr(self.model_registry, "provider_status_snapshot", None)
        status_map: Dict[str, Any] = {}
        if callable(snapshot_fn):
            try:
                payload = snapshot_fn()
                status_map = payload if isinstance(payload, dict) else {}
            except Exception:
                status_map = {}
        groq_ready = bool((status_map.get("groq", {}) if isinstance(status_map.get("groq", {}), dict) else {}).get("ready", False))
        nvidia_ready = bool((status_map.get("nvidia", {}) if isinstance(status_map.get("nvidia", {}), dict) else {}).get("ready", False))
        return not (groq_ready or nvidia_ready)

    def _model_connector_diagnostics(
        self,
        *,
        include_route_plan: bool = True,
        requires_offline: bool = False,
        privacy_mode: bool = False,
        mission_profile: str = "balanced",
    ) -> Dict[str, Any]:
        planner = getattr(self.kernel, "planner", None)
        if planner is None:
            return {"status": "unavailable"}
        planner_voice_policy = self._sync_planner_voice_route_policy_snapshot(force_refresh=False)
        planner_diag_fn = getattr(planner, "connector_diagnostics", None)
        if callable(planner_diag_fn):
            try:
                payload = planner_diag_fn(
                    include_route_plan=include_route_plan,
                    requires_offline=requires_offline,
                    privacy_mode=privacy_mode,
                    mission_profile=mission_profile,
                )
                if isinstance(payload, dict):
                    payload["voice_route_policy"] = planner_voice_policy
                    return _to_jsonable(payload)
            except Exception as exc:  # noqa: BLE001
                return {"status": "error", "message": str(exc)}
        payload: Dict[str, Any] = {"status": "success"}
        groq_client = getattr(planner, "groq_client", None)
        nvidia_client = getattr(planner, "nvidia_client", None)
        local_enabled = bool(getattr(planner, "local_reasoning_enabled", False))
        payload["local_reasoning_enabled"] = local_enabled
        payload["local_reasoning_timeout_s"] = float(getattr(planner, "local_reasoning_timeout_s", 0.0) or 0.0)
        payload["local_reasoning_max_new_tokens"] = int(getattr(planner, "local_reasoning_max_new_tokens", 0) or 0)
        payload["groq"] = self._safe_connector_diag(groq_client)
        payload["nvidia"] = self._safe_connector_diag(nvidia_client)
        candidate_fn = getattr(planner, "_local_reasoning_candidates", None)
        if callable(candidate_fn):
            try:
                candidates = candidate_fn(preferred_model_name="")
                payload["local_reasoning_candidates"] = [row for row in candidates[:8] if isinstance(row, dict)]
                payload["local_reasoning_candidate_count"] = len(candidates)
            except Exception as exc:  # noqa: BLE001
                payload["local_reasoning_candidates_error"] = str(exc)
        payload["voice_route_policy"] = planner_voice_policy
        return payload

    def model_connector_diagnostics(
        self,
        *,
        include_route_plan: bool = True,
        requires_offline: bool = False,
        privacy_mode: bool = False,
        mission_profile: str = "balanced",
    ) -> Dict[str, Any]:
        return self._model_connector_diagnostics(
            include_route_plan=include_route_plan,
            requires_offline=requires_offline,
            privacy_mode=privacy_mode,
            mission_profile=mission_profile,
        )

    def model_connector_route_plan(
        self,
        *,
        requires_offline: bool = False,
        privacy_mode: bool = False,
        mission_profile: str = "balanced",
    ) -> Dict[str, Any]:
        planner = getattr(self.kernel, "planner", None)
        if planner is None:
            return {"status": "unavailable"}
        fn = getattr(planner, "connector_route_plan", None)
        if callable(fn):
            try:
                payload = fn(
                    requires_offline=requires_offline,
                    privacy_mode=privacy_mode,
                    mission_profile=mission_profile,
                )
                if isinstance(payload, dict):
                    payload["voice_route_policy"] = self._sync_planner_voice_route_policy_snapshot(force_refresh=False)
                    return _to_jsonable(payload)
                return {"status": "error", "message": "invalid payload"}
            except Exception as exc:  # noqa: BLE001
                return {"status": "error", "message": str(exc)}
        return {"status": "unavailable", "message": "planner connector route plan is unavailable"}

    def probe_model_connectors(self, *, active_probe: bool = False, timeout_s: float = 4.0) -> Dict[str, Any]:
        planner = getattr(self.kernel, "planner", None)
        if planner is None:
            return {"status": "unavailable"}
        fn = getattr(planner, "probe_model_connectors", None)
        if callable(fn):
            try:
                payload = fn(active_probe=active_probe, timeout_s=timeout_s)
                return _to_jsonable(payload) if isinstance(payload, dict) else {"status": "error", "message": "invalid payload"}
            except Exception as exc:  # noqa: BLE001
                return {"status": "error", "message": str(exc)}
        return {"status": "unavailable", "message": "planner connector probe is unavailable"}

    def update_model_connector_policy(self, payload: Dict[str, Any]) -> Dict[str, Any]:
        planner = getattr(self.kernel, "planner", None)
        if planner is None:
            return {"status": "unavailable"}
        fn = getattr(planner, "update_connector_policy", None)
        if not callable(fn):
            return {"status": "unavailable", "message": "planner connector policy updates are unavailable"}
        try:
            result = fn(payload if isinstance(payload, dict) else {})
            return _to_jsonable(result) if isinstance(result, dict) else {"status": "error", "message": "invalid payload"}
        except Exception as exc:  # noqa: BLE001
            return {"status": "error", "message": str(exc)}

    @staticmethod
    def _safe_connector_diag(client: Any) -> Dict[str, Any]:
        if client is None:
            return {"status": "unconfigured", "ready": False}
        diag_fn = getattr(client, "diagnostics", None)
        if callable(diag_fn):
            try:
                payload = diag_fn()
                if isinstance(payload, dict):
                    return _to_jsonable(payload)
            except Exception as exc:  # noqa: BLE001
                return {"status": "error", "ready": False, "message": str(exc)}
        ready_fn = getattr(client, "is_ready", None)
        if callable(ready_fn):
            try:
                return {"status": "partial", "ready": bool(ready_fn())}
            except Exception as exc:  # noqa: BLE001
                return {"status": "error", "ready": False, "message": str(exc)}
        return {"status": "partial", "ready": False}

