    def list_telemetry_events(
        self,
        *,
        event: Optional[str] = None,
        after_id: int = 0,
        limit: int = 200,
    ) -> Dict[str, Any]:
        bounded_limit = max(1, min(int(limit), 1000))
        normalized_after = max(0, int(after_id))
        normalized_event = str(event or "").strip() or None
        return self.kernel.telemetry.list_events(event=normalized_event, after_id=normalized_after, limit=bounded_limit)

    def list_voice_stream_events(
        self,
        *,
        after_id: int = 0,
        limit: int = 200,
        events: Optional[list[str]] = None,
        include_action_events: bool = False,
    ) -> Dict[str, Any]:
        bounded_limit = max(1, min(int(limit), 1000))
        normalized_after = max(0, int(after_id))
        filters = [
            str(item or "").strip().lower()
            for item in (events if isinstance(events, list) else [])
            if str(item or "").strip()
        ]

        window_limit = max(bounded_limit * 6, 600)
        telemetry_payload = self.kernel.telemetry.list_events(
            event=None,
            after_id=max(0, normalized_after - 1),
            limit=min(window_limit, 5000),
        )
        rows = telemetry_payload.get("items", []) if isinstance(telemetry_payload, dict) else []
        if not isinstance(rows, list):
            rows = []

        def _match_event(name: str) -> bool:
            clean_name = str(name or "").strip().lower()
            if not clean_name:
                return False
            if filters:
                for pattern in filters:
                    if not pattern:
                        continue
                    if pattern.endswith("*"):
                        prefix = pattern[:-1]
                        if prefix and clean_name.startswith(prefix):
                            return True
                    elif clean_name == pattern:
                        return True
                return False
            if clean_name.startswith("voice."):
                return True
            if include_action_events and clean_name in {"action.executed", "action.blocked"}:
                return True
            return False

        selected: list[Dict[str, Any]] = []
        latest_event_id = int(telemetry_payload.get("latest_event_id", 0) or 0) if isinstance(telemetry_payload, dict) else 0
        for row in rows:
            if not isinstance(row, dict):
                continue
            event_id = int(row.get("event_id", 0) or 0)
            if event_id <= normalized_after:
                continue
            event_name = str(row.get("event", "")).strip().lower()
            if not _match_event(event_name):
                continue
            if event_name in {"action.executed", "action.blocked"}:
                payload = row.get("payload") if isinstance(row.get("payload"), dict) else {}
                source = str(payload.get("source", "")).strip().lower()
                goal_source = str(payload.get("goal_source", "")).strip().lower()
                if "voice" not in source and "voice" not in goal_source:
                    continue
            selected.append(row)

        selected = selected[-bounded_limit:]
        return {
            "status": "success",
            "items": selected,
            "count": len(selected),
            "latest_event_id": latest_event_id,
        }

