    def approve_approval(self, approval_id: str, note: str = "") -> Dict[str, Any]:
        ok, message, record = self.kernel.approval_gate.approve(approval_id, note=note)
        payload: Dict[str, Any] = {"status": "success" if ok else "error", "message": message}
        if record:
            payload["approval"] = record.to_dict()
        self.kernel.telemetry.emit(
            "approval.updated",
            {
                "approval_id": approval_id,
                "status": "approved" if ok else "error",
                "message": message,
            },
        )
        return payload

