    def query_memory(
        self,
        query: str = "",
        limit: int = 20,
        *,
        mode: str = "hybrid",
        status: str = "",
        source: str = "",
        min_score: float = 0.12,
        must_tags: Optional[list[str]] = None,
        prefer_tags: Optional[list[str]] = None,
        exclude_goal_ids: Optional[list[str]] = None,
        diversify_by_goal: bool = True,
    ) -> Dict[str, Any]:
        q = str(query or "").strip()
        bounded = max(1, min(int(limit), 200))
        mode_name = str(mode or "").strip().lower() or "hybrid"
        status_name = str(status or "").strip().lower()
        source_name = str(source or "").strip().lower()
        score_floor = max(-1.0, min(1.0, float(min_score)))
        must_tag_values = self._normalize_text_list(must_tags)
        prefer_tag_values = self._normalize_text_list(prefer_tags)
        excluded_goal_values = self._normalize_text_list(exclude_goal_ids)
        diversify = bool(diversify_by_goal)

        if mode_name not in {"hybrid", "lexical", "semantic"}:
            return {"status": "error", "message": "mode must be one of: hybrid, lexical, semantic"}

        semantic_limit = bounded if mode_name != "hybrid" else max(1, bounded)
        lexical_limit = bounded if mode_name != "hybrid" else max(1, bounded // 2)
        policy = {
            "min_score": score_floor,
            "status": status_name,
            "source": source_name,
            "must_tags": must_tag_values,
            "prefer_tags": prefer_tag_values,
            "exclude_goal_ids": excluded_goal_values,
            "diversify_by_goal": diversify,
        }

        if q:
            lexical = self.kernel.runtime_memory.search(q, limit=lexical_limit)
            semantic = self.kernel.episodic_memory.search_with_policy(
                q,
                limit=semantic_limit,
                policy=policy,
            )
        else:
            lexical = self.kernel.runtime_memory.recent_hints(limit=lexical_limit)
            semantic = self.kernel.episodic_memory.recent(limit=min(200, max(semantic_limit * 3, semantic_limit)))
            semantic = self._filter_semantic_memory_with_policy(
                semantic,
                status=status_name,
                source=source_name,
                must_tags=must_tag_values,
                prefer_tags=prefer_tag_values,
                exclude_goal_ids=excluded_goal_values,
                diversify_by_goal=diversify,
                limit=semantic_limit,
            )

        if mode_name == "lexical":
            items = [dict(item, memory_source="runtime_lexical") for item in lexical]
        elif mode_name == "semantic":
            items = [dict(item, memory_source="episodic_semantic") for item in semantic]
        else:
            items = self.kernel._merge_memory_hints(lexical, semantic, limit=bounded)  # noqa: SLF001

        return {
            "status": "success",
            "items": items[:bounded],
            "count": len(items[:bounded]),
            "query": q,
            "mode": mode_name,
            "stats": {
                "runtime_items": len(lexical),
                "episodic_items": len(semantic),
                "episodic_backend": self.kernel.episodic_memory.stats().get("embedding_backend", ""),
                "filters": {
                    "status": status_name,
                    "source": source_name,
                    "min_score": score_floor,
                    "must_tags": must_tag_values,
                    "prefer_tags": prefer_tag_values,
                    "exclude_goal_ids": excluded_goal_values,
                    "diversify_by_goal": diversify,
                },
            },
        }

    def memory_strategy(
        self,
        query: str = "",
        limit: int = 12,
        *,
        min_score: float = 0.08,
    ) -> Dict[str, Any]:
        q = str(query or "").strip()
        bounded = max(4, min(int(limit), 64))
        score_floor = max(-1.0, min(1.0, float(min_score)))
        return self.kernel.episodic_memory.strategy(
            q,
            limit=bounded,
            min_score=score_floor,
            include_failures=True,
        )

    @staticmethod
    def _normalize_text_list(value: Optional[list[str]]) -> list[str]:
        if not isinstance(value, list):
            return []
        out: list[str] = []
        seen: set[str] = set()
        for item in value:
            clean = str(item or "").strip().lower()
            if not clean or clean in seen:
                continue
            seen.add(clean)
            out.append(clean)
        return out

    @staticmethod
    def _filter_semantic_memory_with_policy(
        rows: list[Dict[str, Any]],
        *,
        status: str,
        source: str,
        must_tags: list[str],
        prefer_tags: list[str],
        exclude_goal_ids: list[str],
        diversify_by_goal: bool,
        limit: int,
    ) -> list[Dict[str, Any]]:
        must_tag_set = set(must_tags)
        prefer_tag_set = set(prefer_tags)
        excluded_goal_set = set(exclude_goal_ids)

        filtered: list[tuple[float, Dict[str, Any]]] = []
        for row in rows:
            row_status = str(row.get("status", "")).strip().lower()
            row_source = str(row.get("source", "")).strip().lower()
            row_goal_id = str(row.get("goal_id", "")).strip().lower()
            if status and row_status != status:
                continue
            if source and row_source != source:
                continue
            if row_goal_id and row_goal_id in excluded_goal_set:
                continue
            row_tags = {
                str(item or "").strip().lower()
                for item in row.get("tags", [])
                if isinstance(item, str) and str(item or "").strip()
            }
            if must_tag_set and not must_tag_set.issubset(row_tags):
                continue
            preference_score = float(len(row_tags.intersection(prefer_tag_set)))
            filtered.append((preference_score, row))

        filtered.sort(key=lambda item: item[0], reverse=True)
        ranked_rows = [row for _, row in filtered]
        if not diversify_by_goal:
            return ranked_rows[: max(1, min(int(limit), 200))]

        deduped: list[Dict[str, Any]] = []
        seen_goals: set[str] = set()
        for row in ranked_rows:
            goal_id = str(row.get("goal_id", "")).strip().lower()
            key = goal_id or str(row.get("memory_id", "")).strip().lower()
            if key and key in seen_goals:
                continue
            if key:
                seen_goals.add(key)
            deduped.append(row)
            if len(deduped) >= max(1, min(int(limit), 200)):
                break
        return deduped

