    def wait_for_goal(self, goal_id: str, timeout_s: float = 10.0, poll_s: float = 0.2) -> Optional[Dict[str, Any]]:
        clean_goal_id = str(goal_id or "").strip()
        if not clean_goal_id:
            return None
        timeout = max(0.5, min(float(timeout_s), 600.0))
        poll = max(0.05, min(float(poll_s), 2.0))
        deadline = time.time() + timeout

        goal_manager = getattr(self.kernel, "goal_manager", None)
        wait_for_terminal = getattr(goal_manager, "wait_for_terminal", None)
        promote_goal = getattr(goal_manager, "promote", None)
        promoted = False
        latest_goal = self.kernel.get_goal(clean_goal_id)

        while time.time() < deadline:
            remaining = max(0.01, deadline - time.time())
            wait_window = min(poll, remaining)
            goal = None
            if callable(wait_for_terminal):
                goal = wait_for_terminal(clean_goal_id, timeout_s=wait_window)
            else:
                goal = self.kernel.get_goal(clean_goal_id)
                if goal is not None and goal.status not in {
                    GoalStatus.COMPLETED,
                    GoalStatus.FAILED,
                    GoalStatus.BLOCKED,
                    GoalStatus.CANCELLED,
                }:
                    time.sleep(wait_window)
            if goal is not None:
                latest_goal = goal
                if goal.status in {GoalStatus.COMPLETED, GoalStatus.FAILED, GoalStatus.BLOCKED, GoalStatus.CANCELLED}:
                    return _to_jsonable(goal)
                if not promoted and callable(promote_goal) and goal.status == GoalStatus.PENDING and remaining > 1.0:
                    promoted = bool(promote_goal(clean_goal_id, temporary_priority=-3, reason="api_wait_for_goal"))

        if latest_goal is None:
            latest_goal = self.kernel.get_goal(clean_goal_id)
        payload = _to_jsonable(latest_goal) if latest_goal else None
        if isinstance(payload, dict):
            payload["wait_timed_out"] = True
            payload["wait_timeout_s"] = timeout
        return payload

