    @staticmethod
    def _normalize_external_provider_name(value: Any) -> str:
        clean = str(value or "").strip().lower()
        if not clean:
            return ""
        if clean in {"microsoft", "outlook"}:
            return "graph"
        return clean

    def _external_connector_mission_analysis_cached(self, *, force_refresh: bool = False) -> Dict[str, Any]:
        fetch = getattr(getattr(self, "kernel", None), "external_reliability_mission_analysis", None)
        if not callable(fetch):
            return {
                "status": "skip",
                "reason": "mission_analysis_unavailable",
                "mission_mode": "stable",
                "trend_mode": "stable",
                "volatility_mode": "stable",
                "trend_pressure": 0.0,
                "at_risk_ratio": 0.0,
                "recommendations": [],
            }

        now_monotonic = time.monotonic()
        ttl_s = max(
            5.0,
            min(
                float(getattr(self, "_external_connector_mission_analysis_cache_ttl_s", 45.0) or 45.0),
                300.0,
            ),
        )
        cache_row = getattr(self, "_external_connector_mission_analysis_cache", {})
        if (
            not force_refresh
            and isinstance(cache_row, dict)
            and isinstance(cache_row.get("payload"), dict)
            and (now_monotonic - float(cache_row.get("fetched_at_monotonic", 0.0) or 0.0)) < ttl_s
        ):
            return dict(cache_row.get("payload", {}))

        provider_limit = max(
            40,
            min(
                int(getattr(self, "_external_connector_mission_analysis_provider_limit", 140) or 140),
                1000,
            ),
        )
        history_limit = max(
            12,
            min(
                int(getattr(self, "_external_connector_mission_analysis_history_limit", 36) or 36),
                240,
            ),
        )
        record_enabled = bool(getattr(self, "_external_connector_mission_analysis_record_enabled", True))

        try:
            try:
                analysis = fetch(provider_limit=provider_limit, history_limit=history_limit, record=record_enabled)
            except TypeError:
                analysis = fetch(provider_limit=provider_limit, history_limit=history_limit)
        except Exception as exc:  # noqa: BLE001
            payload = {
                "status": "error",
                "reason": "mission_analysis_failed",
                "message": str(exc),
                "mission_mode": "stable",
                "trend_mode": "stable",
                "volatility_mode": "stable",
                "trend_pressure": 0.0,
                "at_risk_ratio": 0.0,
                "recommendations": [],
            }
            self._external_connector_mission_analysis_cache = {
                "fetched_at_monotonic": now_monotonic,
                "payload": payload,
            }
            return payload

        analysis_map = analysis if isinstance(analysis, dict) else {}
        mission_policy = analysis_map.get("mission_policy", {}) if isinstance(analysis_map.get("mission_policy", {}), dict) else {}
        trend = analysis_map.get("trend", {}) if isinstance(analysis_map.get("trend", {}), dict) else {}
        profile_history = (
            analysis_map.get("profile_history_analysis", {})
            if isinstance(analysis_map.get("profile_history_analysis", {}), dict)
            else {}
        )
        provider_risk = (
            analysis_map.get("provider_risk_analysis", {})
            if isinstance(analysis_map.get("provider_risk_analysis", {}), dict)
            else {}
        )
        mission_history_drift = (
            analysis_map.get("mission_history_drift", {})
            if isinstance(analysis_map.get("mission_history_drift", {}), dict)
            else {}
        )
        provider_policy_tuning = (
            analysis_map.get("provider_policy_tuning", {})
            if isinstance(analysis_map.get("provider_policy_tuning", {}), dict)
            else {}
        )
        recommendations_raw = analysis_map.get("recommendations", [])
        recommendations = recommendations_raw if isinstance(recommendations_raw, list) else []
        payload = {
            "status": str(analysis_map.get("status", "")).strip().lower() or "unknown",
            "mission_mode": str(mission_policy.get("mode", "stable")).strip().lower() or "stable",
            "mission_profile": str(mission_policy.get("profile", "balanced")).strip().lower() or "balanced",
            "trend_mode": str(trend.get("mode", "stable")).strip().lower() or "stable",
            "trend_pressure": max(0.0, min(float(trend.get("trend_pressure", 0.0) or 0.0), 1.0)),
            "volatility_mode": str(profile_history.get("volatility_mode", "stable")).strip().lower() or "stable",
            "volatility_index": max(0.0, min(float(profile_history.get("volatility_index", 0.0) or 0.0), 1.0)),
            "at_risk_ratio": max(0.0, min(float(provider_risk.get("at_risk_ratio", 0.0) or 0.0), 1.0)),
            "at_risk_count": max(0, int(provider_risk.get("at_risk_count", 0) or 0)),
            "provider_count": max(0, int(analysis_map.get("provider_count", 0) or 0)),
            "mission_drift_mode": str(mission_history_drift.get("mode", "stable")).strip().lower() or "stable",
            "mission_drift_score": max(0.0, min(float(mission_history_drift.get("drift_score", 0.0) or 0.0), 1.0)),
            "provider_policy_tuning_status": str(provider_policy_tuning.get("status", "")).strip().lower() or "unknown",
            "provider_policy_tuning_changed": bool(provider_policy_tuning.get("changed", False)),
            "provider_policy_tuning_updated_count": max(0, int(provider_policy_tuning.get("updated_count", 0) or 0)),
            "recommendations": recommendations[:6],
            "generated_at": str(analysis_map.get("generated_at", "")).strip(),
        }
        self._external_connector_mission_analysis_cache = {
            "fetched_at_monotonic": now_monotonic,
            "payload": payload,
        }
        return payload

    @staticmethod
    def _external_connector_build_retry_policy(
        *,
        reliability_pressure: float,
        recommended_delay_s: float,
        trend_mode: str,
        volatility_mode: str,
        blocked_by_reliability: bool,
    ) -> Dict[str, Any]:
        pressure = max(0.0, min(float(reliability_pressure), 1.0))
        clean_trend = str(trend_mode or "").strip().lower()
        clean_volatility = str(volatility_mode or "").strip().lower()

        mode = "immediate"
        if blocked_by_reliability and pressure >= 0.9:
            mode = "abort"
        elif pressure >= 0.75 or clean_trend in {"worsening", "degraded", "severe"}:
            mode = "stabilize"
        elif pressure >= 0.52 or clean_volatility in {"surging", "elevated"}:
            mode = "adaptive_backoff"
        elif pressure >= 0.3:
            mode = "probe_then_backoff"

        if mode == "abort":
            max_attempts = 0
        elif mode == "stabilize":
            max_attempts = 1
        elif mode == "adaptive_backoff":
            max_attempts = 3
        elif mode == "probe_then_backoff":
            max_attempts = 4
        else:
            max_attempts = 2

        base_delay = max(0.0, float(recommended_delay_s))
        if base_delay <= 0.0:
            if mode == "immediate":
                base_delay = 0.0
            else:
                base_delay = max(1.5, round(1.0 + (pressure * 7.5), 3))
        max_delay = max(4.0, min(300.0, round(max(base_delay, 1.0) * 8.0, 3)))
        jitter_s = round(min(8.0, max(0.2, 0.3 + (pressure * 2.4))), 3) if mode != "immediate" else 0.0

        schedule_s: list[float] = []
        if mode != "abort":
            attempts = max(1, int(max_attempts))
            for index in range(attempts):
                if mode == "immediate":
                    delay = 0.0 if index == 0 else min(max_delay, base_delay)
                elif mode == "probe_then_backoff":
                    if index == 0:
                        delay = 0.0
                    elif index == 1:
                        delay = base_delay
                    else:
                        delay = min(max_delay, base_delay * (2.0 ** float(index - 1)))
                elif mode == "adaptive_backoff":
                    delay = min(max_delay, base_delay * (1.65 ** float(index)))
                else:
                    delay = min(max_delay, base_delay * (2.2 ** float(index)))
                schedule_s.append(round(max(0.0, float(delay)), 3))

        return {
            "mode": mode,
            "max_attempts": int(max_attempts),
            "base_delay_s": round(base_delay, 3),
            "max_delay_s": round(max_delay, 3),
            "jitter_s": jitter_s,
            "schedule_s": schedule_s,
            "cooldown_override_required": bool(blocked_by_reliability and mode in {"abort", "stabilize"}),
        }

    def _external_connector_build_route_weight_advisor(
        self,
        *,
        action: str,
        requested_provider: str,
        recommended_provider: str,
        provider_route_plan: list[Dict[str, Any]],
        retry_policy: Dict[str, Any],
        mission_policy_decision: Dict[str, Any],
        reliability_pressure: float,
        runtime_lane: str,
        blocked_by_reliability: bool,
    ) -> Dict[str, Any]:
        clean_action = str(action or "").strip().lower()
        clean_requested = self._normalize_external_provider_name(requested_provider) or "auto"
        clean_recommended = self._normalize_external_provider_name(recommended_provider) or clean_requested
        clean_runtime_lane = str(runtime_lane or "").strip().lower() or "parallel"
        pressure = max(0.0, min(float(reliability_pressure or 0.0), 1.0))
        retry_mode = str(retry_policy.get("mode", "immediate")).strip().lower() or "immediate"
        base_delay = max(
            0.0,
            float(retry_policy.get("recommended_delay_s", retry_policy.get("base_delay_s", 0.0)) or 0.0),
        )
        trigger_band = "stable"
        if blocked_by_reliability or pressure >= 0.8:
            trigger_band = "critical"
        elif pressure >= 0.62 or clean_runtime_lane != "parallel":
            trigger_band = "elevated"
        elif pressure >= 0.38:
            trigger_band = "watch"

        weight_rows: list[Dict[str, Any]] = []
        weight_total = 0.0
        for row in provider_route_plan[:8]:
            if not isinstance(row, dict):
                continue
            row_provider = self._normalize_external_provider_name(row.get("provider", ""))
            if not row_provider:
                continue
            score = max(0.0, min(float(row.get("score", 0.0) or 0.0), 1.0))
            row_pressure = max(0.0, min(float(row.get("pressure", 0.0) or 0.0), 1.0))
            health_score = max(0.0, min(float(row.get("health_score", 0.0) or 0.0), 1.0))
            failure_ema = max(0.0, min(float(row.get("failure_ema", 0.0) or 0.0), 1.0))
            alignment = max(-1.0, min(float(row.get("mission_profile_alignment", 0.0) or 0.0), 1.0))
            tier = str(row.get("tier", "candidate")).strip().lower() or "candidate"
            cooldown_active = bool(row.get("cooldown_active", False))
            outage_active = bool(row.get("outage_active", False))
            route_block_threshold = max(0.2, min(float(row.get("route_block_threshold", 0.86) or 0.86), 1.0))
            preflight_block_threshold = max(0.2, min(float(row.get("preflight_block_threshold", 0.92) or 0.92), 1.0))
            retry_after_s = max(0.0, float(row.get("retry_after_s", 0.0) or 0.0))
            tier_bias = {
                "primary": 0.16,
                "fallback": 0.08,
                "probe": 0.03,
                "blocked": -0.22,
            }.get(tier, 0.0)
            block_penalty = 0.0
            if cooldown_active:
                block_penalty += 0.34
            if outage_active:
                block_penalty += 0.58
            if row_pressure >= route_block_threshold:
                block_penalty += 0.08
            if row_pressure >= preflight_block_threshold:
                block_penalty += 0.12
            raw_weight = max(
                0.0,
                min(
                    1.25,
                    (score * 0.52)
                    + (health_score * 0.14)
                    + ((1.0 - failure_ema) * 0.14)
                    + ((1.0 - row_pressure) * 0.2)
                    + (alignment * 0.07)
                    + tier_bias
                    - block_penalty,
                ),
            )
            recommended_contract_mode = retry_mode
            if outage_active or row_pressure >= preflight_block_threshold:
                recommended_contract_mode = "stabilize"
            elif cooldown_active or row_pressure >= route_block_threshold:
                recommended_contract_mode = "adaptive_backoff"
            elif pressure >= 0.34 and recommended_contract_mode == "immediate":
                recommended_contract_mode = "probe_then_backoff"
            weight_total += raw_weight
            weight_rows.append(
                {
                    "provider": row_provider,
                    "tier": tier,
                    "priority": int(row.get("priority", len(weight_rows) + 1) or (len(weight_rows) + 1)),
                    "eligible": bool(row.get("eligible", False)),
                    "score": round(score, 6),
                    "pressure": round(row_pressure, 6),
                    "health_score": round(health_score, 6),
                    "failure_ema": round(failure_ema, 6),
                    "mission_profile_alignment": round(alignment, 6),
                    "route_block_threshold": round(route_block_threshold, 6),
                    "preflight_block_threshold": round(preflight_block_threshold, 6),
                    "cooldown_active": cooldown_active,
                    "outage_active": outage_active,
                    "retry_after_s": round(retry_after_s, 3),
                    "raw_weight": round(raw_weight, 6),
                    "weight_bias": round(tier_bias - block_penalty + (alignment * 0.07), 6),
                    "recommended_contract_mode": recommended_contract_mode,
                    "blocking_cause": (
                        "outage"
                        if outage_active
                        else ("cooldown" if cooldown_active else ("threshold" if row_pressure >= route_block_threshold else "none"))
                    ),
                }
            )
        if weight_total > 0.0:
            for row in weight_rows:
                row["route_weight"] = round(float(row.get("raw_weight", 0.0) or 0.0) / weight_total, 6)
        else:
            for row in weight_rows:
                row["route_weight"] = 0.0
        weight_rows.sort(
            key=lambda row: (
                -float(row.get("route_weight", 0.0) or 0.0),
                int(not bool(row.get("eligible", False))),
                str(row.get("provider", "")),
            )
        )

        recommended_actions: list[Dict[str, Any]] = []
        for row in weight_rows:
            row_provider = self._normalize_external_provider_name(row.get("provider", ""))
            if not row_provider:
                continue
            if not bool(row.get("eligible", False)) and row_provider != clean_recommended:
                continue
            target_delay = max(
                float(row.get("retry_after_s", 0.0) or 0.0),
                base_delay,
            )
            target_risk = max(pressure, float(row.get("pressure", 0.0) or 0.0))
            target_profile = ""
            if blocked_by_reliability or clean_runtime_lane == "serial" or target_risk >= 0.72:
                target_profile = "automation_safe"
            elif target_risk <= 0.32 and clean_runtime_lane == "parallel":
                target_profile = "automation_power"
            metadata_patch: Dict[str, Any] = {
                "__external_retry_contract_mode": str(row.get("recommended_contract_mode", retry_mode)).strip().lower()
                or retry_mode,
                "__external_retry_contract_risk": round(target_risk, 6),
            }
            if target_delay > 0.0:
                metadata_patch["__external_retry_contract_cooldown_s"] = round(target_delay, 3)
            if target_profile:
                metadata_patch["policy_profile"] = target_profile
            recommended_actions.append(
                {
                    "id": f"reroute_preflight_{row_provider}",
                    "label": f"Rerun via {row_provider}",
                    "summary": (
                        f"Re-run preflight on '{row_provider}' under "
                        f"{metadata_patch['__external_retry_contract_mode']} contract."
                    ),
                    "preflight_action": clean_action,
                    "provider": row_provider,
                    "priority": int(row.get("priority", 0) or 0),
                    "tier": str(row.get("tier", "candidate")).strip().lower() or "candidate",
                    "reason": "recommended_provider" if row_provider == clean_recommended else "route_weight_shift",
                    "args_patch": {},
                    "metadata_patch": metadata_patch,
                    "policy_profile": target_profile,
                    "route_weight": round(float(row.get("route_weight", 0.0) or 0.0), 6),
                }
            )
            if len(recommended_actions) >= 3:
                break

        top_provider = clean_recommended
        top_weight = 0.0
        if weight_rows:
            top_provider = str(weight_rows[0].get("provider", clean_recommended)).strip().lower() or clean_recommended
            top_weight = max(0.0, min(float(weight_rows[0].get("route_weight", 0.0) or 0.0), 1.0))
        reason_codes = [
            code
            for code in (
                str(mission_policy_decision.get("reason", "")).strip().lower(),
                "runtime_lane_throttled" if clean_runtime_lane != "parallel" else "",
                "reliability_blocked" if blocked_by_reliability else "",
                "weighted_fallback_required" if clean_requested != top_provider else "",
            )
            if code
        ]
        summary = "No provider route weights available."
        if weight_rows:
            summary = (
                f"Route weighting favors '{top_provider}' at {round(top_weight * 100.0, 1)}% "
                f"under {retry_mode} retry mode on {clean_runtime_lane} lane."
            )
        return {
            "summary": summary,
            "trigger_band": trigger_band,
            "requested_provider": clean_requested,
            "recommended_provider": clean_recommended,
            "runtime_lane": clean_runtime_lane,
            "retry_mode": retry_mode,
            "reason_codes": reason_codes[:8],
            "weight_rows": weight_rows[:6],
            "recommended_actions": recommended_actions[:3],
        }

    def _external_connector_build_cooldown_outage_explainer(
        self,
        *,
        action: str,
        requested_provider: str,
        recommended_provider: str,
        selected_rows: list[Dict[str, Any]],
        provider_route_plan: list[Dict[str, Any]],
        retry_policy: Dict[str, Any],
        mission_policy_decision: Dict[str, Any],
        reliability_pressure: float,
        runtime_lane: str,
        blocked_by_reliability: bool,
    ) -> Dict[str, Any]:
        clean_action = str(action or "").strip().lower()
        clean_requested = self._normalize_external_provider_name(requested_provider) or "auto"
        clean_recommended = self._normalize_external_provider_name(recommended_provider) or clean_requested
        clean_runtime_lane = str(runtime_lane or "").strip().lower() or "parallel"
        pressure = max(0.0, min(float(reliability_pressure or 0.0), 1.0))
        retry_mode = str(retry_policy.get("mode", "immediate")).strip().lower() or "immediate"
        recommended_delay_s = max(
            0.0,
            float(retry_policy.get("recommended_delay_s", retry_policy.get("base_delay_s", 0.0)) or 0.0),
        )
        route_index = {
            self._normalize_external_provider_name(row.get("provider", "")): row
            for row in provider_route_plan
            if isinstance(row, dict) and self._normalize_external_provider_name(row.get("provider", ""))
        }

        def _row_pressure(row: Dict[str, Any]) -> float:
            route_row = route_index.get(self._normalize_external_provider_name(row.get("provider", "")) or "", {})
            if isinstance(route_row, dict) and "pressure" in route_row:
                return max(0.0, min(float(route_row.get("pressure", 0.0) or 0.0), 1.0))
            health = max(0.0, min(float(row.get("health_score", 0.0) or 0.0), 1.0))
            failure = max(0.0, min(float(row.get("failure_ema", 0.0) or 0.0), 1.0))
            inferred = max(failure, 1.0 - health)
            if bool(row.get("cooldown_active", False)):
                inferred = max(inferred, 0.78)
            if bool(row.get("outage_active", False)):
                inferred = max(inferred, 0.92)
            return max(0.0, min(inferred, 1.0))

        affected_rows: list[Dict[str, Any]] = []
        cooldown_count = 0
        outage_count = 0
        for row in selected_rows[:8]:
            if not isinstance(row, dict):
                continue
            provider_name = self._normalize_external_provider_name(row.get("provider", ""))
            if not provider_name:
                continue
            cooldown_active = bool(row.get("cooldown_active", False))
            outage_active = bool(row.get("outage_active", False))
            retry_after_s = max(0.0, float(row.get("retry_after_s", 0.0) or 0.0))
            route_block_threshold = max(0.2, min(float(row.get("route_block_threshold", 0.86) or 0.86), 1.0))
            preflight_block_threshold = max(0.2, min(float(row.get("preflight_block_threshold", 0.92) or 0.92), 1.0))
            row_pressure = _row_pressure(row)
            blocker_codes: list[str] = []
            if cooldown_active:
                blocker_codes.append("cooldown_active")
                cooldown_count += 1
            if outage_active:
                blocker_codes.append("outage_active")
                outage_count += 1
            if row_pressure >= route_block_threshold:
                blocker_codes.append("route_threshold_exceeded")
            if row_pressure >= preflight_block_threshold:
                blocker_codes.append("preflight_threshold_exceeded")
            if retry_after_s > 0.0:
                blocker_codes.append("retry_after_pending")
            if not blocker_codes:
                continue
            route_row = route_index.get(provider_name, {})
            eligible = bool(route_row.get("eligible", False)) if isinstance(route_row, dict) else False
            affected_rows.append(
                {
                    "provider": provider_name,
                    "severity": (
                        "critical"
                        if outage_active or row_pressure >= preflight_block_threshold
                        else ("high" if cooldown_active or row_pressure >= route_block_threshold else "medium")
                    ),
                    "pressure": round(row_pressure, 6),
                    "health_score": round(max(0.0, min(float(row.get("health_score", 0.0) or 0.0), 1.0)), 6),
                    "failure_ema": round(max(0.0, min(float(row.get("failure_ema", 0.0) or 0.0), 1.0)), 6),
                    "retry_after_s": round(retry_after_s, 3),
                    "cooldown_active": cooldown_active,
                    "outage_active": outage_active,
                    "eligible": eligible,
                    "tier": str(route_row.get("tier", "candidate")).strip().lower() if isinstance(route_row, dict) else "candidate",
                    "route_block_threshold": round(route_block_threshold, 6),
                    "preflight_block_threshold": round(preflight_block_threshold, 6),
                    "blocker_codes": blocker_codes[:6],
                    "summary": (
                        f"{provider_name} is {'in outage' if outage_active else ('in cooldown' if cooldown_active else 'above pressure thresholds')} "
                        f"with retry_after={round(retry_after_s, 3)}s."
                    ),
                }
            )
        affected_rows.sort(
            key=lambda row: (
                {"critical": 0, "high": 1, "medium": 2, "low": 3}.get(str(row.get("severity", "low")).strip().lower(), 4),
                -float(row.get("pressure", 0.0) or 0.0),
                str(row.get("provider", "")),
            )
        )
        trigger_band = "stable"
        if outage_count > 0 or blocked_by_reliability or pressure >= 0.78:
            trigger_band = "critical"
        elif cooldown_count > 0 or pressure >= 0.56 or clean_runtime_lane != "parallel":
            trigger_band = "elevated"
        elif affected_rows:
            trigger_band = "watch"

        recommended_actions: list[Dict[str, Any]] = []
        requested_row = next((row for row in affected_rows if str(row.get("provider", "")) == clean_requested), None)
        safe_profile = "automation_safe" if (blocked_by_reliability or clean_runtime_lane == "serial" or pressure >= 0.66) else ""
        if clean_recommended and clean_recommended != clean_requested:
            metadata_patch: Dict[str, Any] = {
                "__external_retry_contract_mode": "stabilize" if trigger_band == "critical" else retry_mode,
                "__external_retry_contract_risk": round(max(pressure, 0.0), 6),
            }
            if recommended_delay_s > 0.0:
                metadata_patch["__external_retry_contract_cooldown_s"] = round(recommended_delay_s, 3)
            if safe_profile:
                metadata_patch["policy_profile"] = safe_profile
            recommended_actions.append(
                {
                    "id": f"cooldown_shift_{clean_recommended}",
                    "label": f"Shift to {clean_recommended}",
                    "summary": f"Requested provider is constrained. Re-run preflight on '{clean_recommended}'.",
                    "preflight_action": clean_action,
                    "provider": clean_recommended,
                    "reason": "provider_shift",
                    "args_patch": {},
                    "metadata_patch": metadata_patch,
                    "policy_profile": safe_profile,
                }
            )
        if requested_row and bool(requested_row.get("cooldown_active", False)) and not bool(requested_row.get("outage_active", False)):
            manual_override_delay = max(
                recommended_delay_s,
                float(requested_row.get("retry_after_s", 0.0) or 0.0),
            )
            override_patch: Dict[str, Any] = {
                "external_cooldown_override": True,
                "__external_retry_contract_mode": "stabilize",
                "__external_retry_contract_risk": round(max(pressure, float(requested_row.get("pressure", 0.0) or 0.0)), 6),
                "__external_retry_contract_cooldown_s": round(manual_override_delay, 3),
                "policy_profile": "automation_safe",
            }
            recommended_actions.append(
                {
                    "id": f"cooldown_override_{clean_requested}",
                    "label": f"Manual override {clean_requested}",
                    "summary": (
                        f"Only use when urgency outweighs cooldown guardrails for '{clean_requested}'. "
                        "This re-runs preflight with explicit cooldown override."
                    ),
                    "preflight_action": clean_action,
                    "provider": clean_requested,
                    "reason": "manual_override",
                    "requires_attention": True,
                    "args_patch": {},
                    "metadata_patch": override_patch,
                    "policy_profile": "automation_safe",
                }
            )
        if trigger_band in {"critical", "elevated"} and clean_recommended:
            staged_patch: Dict[str, Any] = {
                "__external_retry_contract_mode": "stabilize" if trigger_band == "critical" else "adaptive_backoff",
                "__external_retry_contract_risk": round(max(pressure, 0.0), 6),
            }
            staged_delay = max(
                recommended_delay_s,
                max((float(row.get("retry_after_s", 0.0) or 0.0) for row in affected_rows), default=0.0),
            )
            if staged_delay > 0.0:
                staged_patch["__external_retry_contract_cooldown_s"] = round(staged_delay, 3)
            if safe_profile:
                staged_patch["policy_profile"] = safe_profile
            recommended_actions.append(
                {
                    "id": "staged_retry_contract",
                    "label": "Use staged retry contract",
                    "summary": "Re-run preflight with a staged retry contract and tighter reliability posture.",
                    "preflight_action": clean_action,
                    "provider": clean_recommended,
                    "reason": "staged_retry_contract",
                    "args_patch": {},
                    "metadata_patch": staged_patch,
                    "policy_profile": safe_profile,
                }
            )
        summary = "No active cooldown or outage constraints detected."
        if affected_rows:
            summary = (
                f"{len(affected_rows)} provider constraint(s) detected, including "
                f"{cooldown_count} cooldown and {outage_count} outage condition(s)."
            )
        return {
            "summary": summary,
            "trigger_band": trigger_band,
            "requested_provider": clean_requested,
            "recommended_provider": clean_recommended,
            "runtime_lane": clean_runtime_lane,
            "decision_reason": str(mission_policy_decision.get("reason", "")).strip().lower(),
            "cooldown_count": int(cooldown_count),
            "outage_count": int(outage_count),
            "affected_rows": affected_rows[:6],
            "recommended_actions": recommended_actions[:3],
        }

    def _external_connector_candidate_approval_preview(
        self,
        *,
        action: str,
        tool_action: Dict[str, Any],
        args_patch: Dict[str, Any],
        metadata_patch: Dict[str, Any],
        requires_compare: bool,
        requires_confirmation: bool,
        risk_score: float,
        risk_band: str,
    ) -> Dict[str, Any]:
        clean_action = str(
            tool_action.get("action", action) if isinstance(tool_action, dict) else action
        ).strip()
        definition = None
        try:
            definition = self.kernel.registry.get(clean_action) if clean_action else None
        except Exception:
            definition = None
        registry_risk = str(getattr(definition, "risk", "unknown") or "unknown").strip().lower() or "unknown"
        registry_requires_confirmation = bool(getattr(definition, "requires_confirmation", False))
        required_args = tuple(getattr(definition, "required_args", ()) or ())
        action_args = tool_action.get("args", {}) if isinstance(tool_action, dict) and isinstance(tool_action.get("args"), dict) else {}

        def _missing_value(value: Any) -> bool:
            if value is None:
                return True
            if isinstance(value, str):
                return not bool(value.strip())
            if isinstance(value, (list, tuple, set, dict)):
                return len(value) == 0
            return False

        missing_required = [key for key in required_args if key not in action_args or _missing_value(action_args.get(key))]
        registry_risk_floor = {
            "critical": 0.92,
            "high": 0.76,
            "medium": 0.54,
            "low": 0.24,
            "unknown": 0.36,
        }.get(registry_risk, 0.36)
        effective_risk = max(0.0, min(max(float(risk_score or 0.0), registry_risk_floor), 1.0))
        effective_band = (
            "critical"
            if effective_risk >= 0.84
            else ("high" if effective_risk >= 0.64 else ("medium" if effective_risk >= 0.38 else "low"))
        )
        approval_required = bool(registry_requires_confirmation or requires_confirmation)
        review_patch_count = (
            len(args_patch) if isinstance(args_patch, dict) else 0
        ) + (len(metadata_patch) if isinstance(metadata_patch, dict) else 0)
        gate_reasons: list[str] = []
        if missing_required:
            gate_reasons.append("missing_required_args")
        if requires_compare:
            gate_reasons.append("simulation_compare_required")
        if approval_required:
            gate_reasons.append("approval_ticket_required")
        if effective_risk >= 0.72:
            gate_reasons.append("elevated_risk")
        if review_patch_count > 0:
            gate_reasons.append("patch_review_required")

        ready_to_stage = not bool(missing_required)
        ready_to_execute = bool(ready_to_stage and not requires_compare and not approval_required)
        manual_review_required = bool(gate_reasons or review_patch_count > 0)
        posture = "ready"
        if missing_required:
            posture = "blocked_contract"
        elif requires_compare and approval_required:
            posture = "compare_then_approve"
        elif approval_required:
            posture = "approval_required"
        elif requires_compare:
            posture = "compare_required"
        elif manual_review_required:
            posture = "review_required"

        recommended_steps: list[str] = []
        if missing_required:
            recommended_steps.append(f"Fill required args: {', '.join(missing_required[:6])}.")
        if requires_compare:
            recommended_steps.append("Run advisor simulation compare before execution.")
        if approval_required:
            recommended_steps.append("Request and consume an approval ticket before execution.")
        if review_patch_count > 0:
            recommended_steps.append("Review staged args/metadata patches before running the action.")
        if not recommended_steps:
            recommended_steps.append("Candidate is ready for direct execution.")

        summary = "Candidate is ready for direct execution."
        if posture == "blocked_contract":
            summary = f"Candidate is blocked until required args are supplied: {', '.join(missing_required[:6])}."
        elif posture == "compare_then_approve":
            summary = "Candidate requires a simulation compare and an approval ticket before execution."
        elif posture == "approval_required":
            summary = "Candidate requires explicit approval before execution."
        elif posture == "compare_required":
            summary = "Candidate should be validated through simulation compare before execution."
        elif posture == "review_required":
            summary = "Candidate is stageable but needs patch review before direct execution."

        return {
            "status": "success",
            "posture": posture,
            "summary": summary,
            "registry_risk": registry_risk,
            "registry_requires_confirmation": registry_requires_confirmation,
            "candidate_risk_band": str(risk_band or "unknown").strip().lower() or "unknown",
            "candidate_risk_score": round(max(0.0, min(float(risk_score or 0.0), 1.0)), 6),
            "effective_risk_band": effective_band,
            "effective_risk_score": round(effective_risk, 6),
            "requires_compare": bool(requires_compare),
            "requires_approval_ticket": approval_required,
            "requires_confirmation": bool(requires_confirmation or registry_requires_confirmation),
            "ready_to_stage": ready_to_stage,
            "ready_to_execute": ready_to_execute,
            "manual_review_required": manual_review_required,
            "review_patch_count": int(review_patch_count),
            "missing_required_args": missing_required[:8],
            "gate_reasons": gate_reasons[:8],
            "recommended_steps": recommended_steps[:6],
        }

    def _external_connector_summarize_candidate_approvals(
        self,
        candidates: list[Dict[str, Any]],
    ) -> Dict[str, Any]:
        rows = [row for row in candidates if isinstance(row, dict)]
        candidate_count = len(rows)
        approval_required_count = 0
        compare_required_count = 0
        ready_stage_count = 0
        ready_execute_count = 0
        blocked_count = 0
        manual_review_count = 0
        risk_total = 0.0
        risk_max = 0.0
        for row in rows:
            preview = row.get("approval_preview", {}) if isinstance(row.get("approval_preview"), dict) else {}
            approval_required_count += 1 if bool(preview.get("requires_approval_ticket", False)) else 0
            compare_required_count += 1 if bool(preview.get("requires_compare", False)) else 0
            ready_stage_count += 1 if bool(preview.get("ready_to_stage", False)) else 0
            ready_execute_count += 1 if bool(preview.get("ready_to_execute", False)) else 0
            manual_review_count += 1 if bool(preview.get("manual_review_required", False)) else 0
            blocked_count += 1 if str(preview.get("posture", "")).strip().lower() == "blocked_contract" else 0
            try:
                risk_value = max(0.0, min(float(preview.get("effective_risk_score", 0.0) or 0.0), 1.0))
            except Exception:
                risk_value = 0.0
            risk_total += risk_value
            risk_max = max(risk_max, risk_value)

        posture = "ready"
        if blocked_count > 0:
            posture = "blocked_contract"
        elif approval_required_count > 0 and compare_required_count > 0:
            posture = "compare_then_approve"
        elif approval_required_count > 0:
            posture = "approval_required"
        elif compare_required_count > 0:
            posture = "compare_required"
        elif manual_review_count > 0:
            posture = "review_required"

        summary = "Execution candidates are ready for direct execution."
        if posture == "blocked_contract":
            summary = "At least one execution candidate is blocked by missing contract inputs."
        elif posture == "compare_then_approve":
            summary = "Execution candidates require compare validation and approval before execution."
        elif posture == "approval_required":
            summary = "Execution candidates require approval before execution."
        elif posture == "compare_required":
            summary = "Execution candidates should be compared before execution."
        elif posture == "review_required":
            summary = "Execution candidates are stageable but still require review."

        divisor = float(max(candidate_count, 1))
        return {
            "candidate_count": candidate_count,
            "approval_required_count": approval_required_count,
            "compare_required_count": compare_required_count,
            "ready_stage_count": ready_stage_count,
            "ready_execute_count": ready_execute_count,
            "blocked_count": blocked_count,
            "manual_review_count": manual_review_count,
            "approval_required_ratio": round(float(approval_required_count) / divisor, 6),
            "compare_required_ratio": round(float(compare_required_count) / divisor, 6),
            "ready_stage_ratio": round(float(ready_stage_count) / divisor, 6),
            "ready_execute_ratio": round(float(ready_execute_count) / divisor, 6),
            "manual_review_ratio": round(float(manual_review_count) / divisor, 6),
            "blocked_ratio": round(float(blocked_count) / divisor, 6),
            "average_risk": round(risk_total / divisor, 6),
            "max_risk": round(risk_max, 6),
            "posture": posture,
            "summary": summary,
        }

    def _external_connector_build_execution_handoff(
        self,
        *,
        action: str,
        base_args: Dict[str, Any],
        requested_provider: str,
        recommended_provider: str,
        route_weight_advisor: Dict[str, Any],
        cooldown_outage_explainer: Dict[str, Any],
        retry_policy: Dict[str, Any],
        mission_policy_decision: Dict[str, Any],
    ) -> Dict[str, Any]:
        clean_action = str(action or "").strip().lower()
        requested = self._normalize_external_provider_name(requested_provider) or "auto"
        recommended = self._normalize_external_provider_name(recommended_provider) or requested
        runtime_lane = str(mission_policy_decision.get("runtime_lane", "")).strip().lower() or "parallel"
        retry_mode = str(retry_policy.get("mode", "immediate")).strip().lower() or "immediate"
        reliability_pressure = max(
            0.0,
            min(float(mission_policy_decision.get("reliability_pressure", 0.0) or 0.0), 1.0),
        )
        mission_profile = str(mission_policy_decision.get("profile", "")).strip().lower() or "balanced"

        action_sources: list[Dict[str, Any]] = []
        for source_name, source_payload in (
            ("route_weight", route_weight_advisor),
            ("cooldown_outage", cooldown_outage_explainer),
        ):
            actions_raw = source_payload.get("recommended_actions", [])
            if not isinstance(actions_raw, list):
                continue
            for row in actions_raw:
                if isinstance(row, dict):
                    candidate = dict(row)
                    candidate["advisor_source"] = source_name
                    action_sources.append(candidate)

        candidates: list[Dict[str, Any]] = []
        seen_keys: set[str] = set()
        for index, row in enumerate(action_sources):
            provider_name = self._normalize_external_provider_name(row.get("provider", ""))
            if not provider_name:
                continue
            metadata_patch = dict(row.get("metadata_patch", {})) if isinstance(row.get("metadata_patch"), dict) else {}
            args_patch = dict(row.get("args_patch", {})) if isinstance(row.get("args_patch"), dict) else {}
            policy_profile = str(row.get("policy_profile", metadata_patch.get("policy_profile", ""))).strip().lower()
            if policy_profile and "policy_profile" not in metadata_patch:
                metadata_patch["policy_profile"] = policy_profile
            risk_value = max(
                0.0,
                min(float(metadata_patch.get("__external_retry_contract_risk", reliability_pressure) or reliability_pressure), 1.0),
            )
            requires_override = bool(metadata_patch.get("external_cooldown_override", False))
            requires_compare = bool(runtime_lane != "parallel" or risk_value >= 0.56 or requires_override)
            requires_confirmation = bool(requires_override or risk_value >= 0.72)
            candidate_key = "|".join(
                [
                    str(row.get("advisor_source", "")).strip().lower(),
                    provider_name,
                    str(metadata_patch.get("__external_retry_contract_mode", retry_mode)).strip().lower(),
                    "override" if requires_override else "normal",
                ]
            )
            if candidate_key in seen_keys:
                continue
            seen_keys.add(candidate_key)
            verification_steps = [
                "preflight contract clean",
                "provider route remains eligible",
                "retry contract accepted by kernel",
            ]
            if requires_compare:
                verification_steps.append("simulation compare verified")
            if requires_override:
                verification_steps.append("manual override explicitly reviewed")
            merged_args = {**base_args, **args_patch}
            tool_action = {
                "action": clean_action,
                "args": merged_args,
                "metadata": metadata_patch,
            }
            risk_band = (
                "critical" if risk_value >= 0.78 else ("high" if risk_value >= 0.6 else ("medium" if risk_value >= 0.36 else "low"))
            )
            approval_preview = self._external_connector_candidate_approval_preview(
                action=clean_action,
                tool_action=tool_action,
                args_patch=args_patch,
                metadata_patch=metadata_patch,
                requires_compare=requires_compare,
                requires_confirmation=requires_confirmation,
                risk_score=risk_value,
                risk_band=risk_band,
            )
            candidates.append(
                {
                    "candidate_id": str(row.get("id", f"execution_candidate_{index + 1}")).strip()
                    or f"execution_candidate_{index + 1}",
                    "label": str(row.get("label", row.get("summary", f"Execution Candidate {index + 1}"))).strip()
                    or f"Execution Candidate {index + 1}",
                    "summary": str(row.get("summary", "Execution candidate synthesized from preflight advisor.")).strip()
                    or "Execution candidate synthesized from preflight advisor.",
                    "advisor_source": str(row.get("advisor_source", "unknown")).strip().lower() or "unknown",
                    "provider": provider_name,
                    "policy_profile": policy_profile,
                    "requires_compare": requires_compare,
                    "requires_confirmation": requires_confirmation,
                    "risk_band": risk_band,
                    "risk_score": round(risk_value, 6),
                    "retry_contract_mode": str(
                        metadata_patch.get("__external_retry_contract_mode", retry_mode)
                    ).strip().lower()
                    or retry_mode,
                    "args_patch": args_patch,
                    "metadata_patch": metadata_patch,
                    "verification_steps": verification_steps,
                    "approval_preview": approval_preview,
                    "approval_posture": str(approval_preview.get("posture", "review_required")).strip().lower(),
                    "approval_required": bool(approval_preview.get("requires_approval_ticket", False)),
                    "tool_action": tool_action,
                }
            )
            if len(candidates) >= 4:
                break

        scenario_rows: list[Dict[str, Any]] = [
            {
                "id": "baseline",
                "description": "Baseline preflight simulation using current contract posture.",
                "providers": [requested] if requested not in {"", "auto"} else [recommended],
                "args_patch": {},
                "metadata_patch": {},
            }
        ]
        for row in candidates:
            provider_name = self._normalize_external_provider_name(row.get("provider", ""))
            if not provider_name:
                continue
            scenario_rows.append(
                {
                    "id": str(row.get("candidate_id", "candidate")).strip() or "candidate",
                    "description": str(row.get("summary", "")).strip() or "Advisor execution candidate simulation.",
                    "providers": [provider_name],
                    "provider": provider_name,
                    "args_patch": dict(row.get("args_patch", {})) if isinstance(row.get("args_patch"), dict) else {},
                    "metadata_patch": dict(row.get("metadata_patch", {})) if isinstance(row.get("metadata_patch"), dict) else {},
                    "candidate_id": str(row.get("candidate_id", "")).strip(),
                    "execution_candidate": True,
                    "external_cooldown_override": bool(
                        isinstance(row.get("metadata_patch"), dict)
                        and row.get("metadata_patch", {}).get("external_cooldown_override", False)
                    ),
                }
            )

        approval_summary = self._external_connector_summarize_candidate_approvals(candidates)
        advisor_context = {
            "source": "preflight_execution_handoff",
            "action": clean_action,
            "requested_provider": requested,
            "recommended_provider": recommended,
            "mission_profile": mission_profile,
            "runtime_lane": runtime_lane,
            "retry_mode": retry_mode,
            "candidate_ids": [str(row.get("candidate_id", "")).strip() for row in candidates if str(row.get("candidate_id", "")).strip()],
            "candidate_count": len(candidates),
            "reason_codes": [
                code
                for code in (
                    str(mission_policy_decision.get("reason", "")).strip().lower(),
                    "requires_compare" if any(bool(row.get("requires_compare", False)) for row in candidates) else "",
                    "requires_confirmation" if any(bool(row.get("requires_confirmation", False)) for row in candidates) else "",
                )
                if code
            ][:8],
            "approval_summary": approval_summary,
            "candidate_approval_map": {
                str(row.get("candidate_id", "")).strip(): dict(row.get("approval_preview", {}))
                for row in candidates
                if isinstance(row.get("approval_preview"), dict) and str(row.get("candidate_id", "")).strip()
            },
        }
        simulation_template = {
            "template_id": "advisor_execution_handoff",
            "name": "Advisor Execution Handoff",
            "description": "Replay advisor-selected candidates, compare with baseline, and verify execution-grade routing.",
            "payload": {
                "action": clean_action,
                "provider": requested,
                "providers": list(dict.fromkeys([requested, recommended] + [str(row.get("provider", "")).strip().lower() for row in candidates if str(row.get("provider", "")).strip()])),
                "args": dict(base_args),
                "max_runs": max(6, min(40, len(scenario_rows) * 4)),
                "result_limit": 120,
                "include_success": True,
                "scenarios": scenario_rows[:8],
                "advisor_context": advisor_context,
            },
        }
        return {
            "status": "success",
            "requested_provider": requested,
            "recommended_provider": recommended,
            "candidate_count": len(candidates),
            "requires_compare": any(bool(row.get("requires_compare", False)) for row in candidates),
            "requires_confirmation": any(bool(row.get("requires_confirmation", False)) for row in candidates),
            "candidates": candidates,
            "approval_summary": approval_summary,
            "advisor_context": advisor_context,
            "simulation_template": simulation_template,
        }

    def _external_connector_build_structured_preflight_contract(
        self,
        *,
        action: str,
        provider: str,
        output: Dict[str, Any],
        orchestration: Dict[str, Any],
    ) -> Dict[str, Any]:
        clean_action = str(action or "").strip().lower()
        clean_provider = self._normalize_external_provider_name(provider) or "auto"
        contract = output.get("contract_diagnostic", {}) if isinstance(output.get("contract_diagnostic"), dict) else {}
        code = str(contract.get("code", output.get("code", ""))).strip().lower()
        severity = str(contract.get("severity", "unknown")).strip().lower() or "unknown"
        severity_score = {
            "critical": 0.92,
            "high": 0.76,
            "medium": 0.52,
            "low": 0.28,
            "info": 0.12,
        }.get(severity, 0.38)

        reliability_pressure = max(0.0, min(float(orchestration.get("reliability_pressure", 0.0) or 0.0), 1.0))
        blocked_by_reliability = bool(orchestration.get("blocked_by_reliability", False))
        mission_analysis = orchestration.get("mission_analysis", {}) if isinstance(orchestration.get("mission_analysis"), dict) else {}
        trend_mode = str(mission_analysis.get("trend_mode", "stable")).strip().lower() or "stable"
        mission_mode = str(mission_analysis.get("mission_mode", "stable")).strip().lower() or "stable"

        risk_score = max(0.0, min((severity_score * 0.6) + (reliability_pressure * 0.4), 1.0))
        if str(output.get("status", "")).strip().lower() == "error":
            risk_score = max(risk_score, 0.58)
        if blocked_by_reliability:
            risk_score = max(risk_score, 0.82)
        if mission_mode in {"degraded", "severe"}:
            risk_score = max(risk_score, 0.72)
        if trend_mode == "worsening":
            risk_score = max(risk_score, 0.66)

        retry_policy = orchestration.get("retry_policy", {}) if isinstance(orchestration.get("retry_policy"), dict) else {}
        runtime_context = self._bridge_scheduler_runtime_context(force_refresh=False)
        rust_pressure_score = max(0.0, min(float(runtime_context.get("rust_pressure_score", 0.0) or 0.0), 1.0))
        rust_retry_mode = str(runtime_context.get("rust_retry_mode", "")).strip().lower()
        rust_recommended_cap = max(0, int(runtime_context.get("rust_recommended_parallel_cap", 0) or 0))
        rust_suggested_delay_s = max(0.0, float(runtime_context.get("rust_suggested_retry_delay_s", 0.0) or 0.0))
        if rust_pressure_score >= 0.72:
            risk_score = max(risk_score, 0.68)
        elif rust_pressure_score >= 0.56:
            risk_score = max(risk_score, 0.6)
        provider_route_plan_raw = orchestration.get("provider_route_plan", [])
        provider_route_plan = provider_route_plan_raw if isinstance(provider_route_plan_raw, list) else []
        recommended_provider = (
            self._normalize_external_provider_name(
                orchestration.get("recommended_provider", output.get("provider_recommended", clean_provider))
            )
            or clean_provider
        )

        failure_classes: list[str] = []
        if blocked_by_reliability:
            failure_classes.append("provider_reliability")
        if "auth" in code:
            failure_classes.append("auth_contract")
        if "provider" in code:
            failure_classes.append("provider_contract")
        if "contract" in code:
            failure_classes.append("payload_contract")
        if reliability_pressure >= 0.68:
            failure_classes.append("outage_pressure")
        if rust_pressure_score >= 0.56:
            failure_classes.append("rust_runtime_pressure")
        if not failure_classes:
            failure_classes.append("runtime_reliability")

        automation_tier = "automated"
        if risk_score >= 0.82:
            automation_tier = "manual"
        elif risk_score >= 0.54:
            automation_tier = "assisted"

        effective_retry_policy = dict(retry_policy)
        mode_rank = {
            "immediate": 0,
            "probe_then_backoff": 1,
            "adaptive_backoff": 2,
            "stabilize": 3,
            "abort": 4,
        }
        execution_mode = str(effective_retry_policy.get("mode", "immediate")).strip().lower() or "immediate"
        if execution_mode not in mode_rank:
            execution_mode = "immediate"
        if rust_retry_mode in mode_rank and rust_pressure_score >= 0.45:
            if mode_rank.get(rust_retry_mode, 0) > mode_rank.get(execution_mode, 0):
                execution_mode = rust_retry_mode
                effective_retry_policy["mode"] = execution_mode
                effective_retry_policy["mode_source"] = "rust_runtime_policy_hint"

        max_retry_attempts = max(0, int(effective_retry_policy.get("max_attempts", 0) or 0))
        if rust_pressure_score >= 0.78:
            max_retry_attempts = min(max_retry_attempts, 2)
        elif rust_pressure_score >= 0.62 and max_retry_attempts > 0:
            max_retry_attempts = min(max_retry_attempts, 3)
        recommended_delay_s = max(
            0.0,
            float(effective_retry_policy.get("recommended_delay_s", 0.0) or 0.0),
        )
        if rust_pressure_score >= 0.5 and rust_suggested_delay_s > 0.0:
            recommended_delay_s = max(recommended_delay_s, rust_suggested_delay_s)

        retry_schedule_raw = effective_retry_policy.get("schedule_s", [])
        retry_schedule = [
            round(max(0.0, float(item)), 3)
            for item in (retry_schedule_raw if isinstance(retry_schedule_raw, list) else [])
        ]
        if not retry_schedule and max_retry_attempts > 0:
            for index in range(max_retry_attempts):
                if execution_mode == "immediate":
                    delay = 0.0
                elif execution_mode == "probe_then_backoff":
                    if index == 0:
                        delay = 0.0
                    elif index == 1:
                        delay = max(1.0, recommended_delay_s)
                    else:
                        delay = max(1.0, recommended_delay_s) * (2.0 ** float(index - 1))
                elif execution_mode == "adaptive_backoff":
                    delay = max(1.0, recommended_delay_s) * (1.65 ** float(index))
                elif execution_mode == "stabilize":
                    delay = max(2.0, recommended_delay_s) * (2.2 ** float(index))
                else:
                    delay = max(6.0, recommended_delay_s)
                retry_schedule.append(round(min(300.0, max(0.0, delay)), 3))
        if rust_pressure_score >= 0.5 and retry_schedule:
            scale = 1.0 + (rust_pressure_score * 0.45)
            retry_schedule = [round(min(300.0, max(0.0, value * scale)), 3) for value in retry_schedule]

        execution_contract = {
            "mode": execution_mode,
            "risk_score": round(risk_score, 6),
            "max_retry_attempts": int(max_retry_attempts),
            "retry_schedule_s": retry_schedule[:8],
            "cooldown_override_required": bool(effective_retry_policy.get("cooldown_override_required", False)),
            "verify_after_retry": True,
            "enforce_contract_checks": True,
            "provider_route_plan": [
                item for item in provider_route_plan[:8] if isinstance(item, dict)
            ],
            "runtime_policy_hint": {
                "rust_pressure_score": round(rust_pressure_score, 6),
                "rust_retry_mode": rust_retry_mode,
                "rust_recommended_parallel_cap": int(rust_recommended_cap),
                "rust_suggested_retry_delay_s": round(rust_suggested_delay_s, 3),
            },
        }
        remediation_contract = {
            "version": 2,
            "automation_tier": automation_tier,
            "blocking_class": "reliability" if blocked_by_reliability else "contract",
            "estimated_recovery_s": int(
                max(
                    0.0,
                    max(
                        recommended_delay_s,
                        max(retry_schedule) if retry_schedule else 0.0,
                    ),
                )
            ),
            "action": clean_action,
            "provider": clean_provider,
            "recommended_provider": recommended_provider,
            "failure_classes": failure_classes,
            "execution_contract": execution_contract,
            "mission_context": {
                "mission_mode": mission_mode,
                "trend_mode": trend_mode,
                "reliability_pressure": round(reliability_pressure, 6),
                "rust_pressure_score": round(rust_pressure_score, 6),
                "rust_retry_mode": rust_retry_mode,
                "rust_recommended_parallel_cap": int(rust_recommended_cap),
            },
        }
        remediation_plan = [
            {
                "phase": "diagnose",
                "status": "pending",
                "summary": "Capture connector/provider reliability diagnostics before retry.",
                "tool_action": {"action": "external_connector_status", "args": {"provider": clean_provider}},
            },
            {
                "phase": "remediate",
                "status": "pending",
                "summary": "Apply provider routing patch and contract-safe argument updates.",
                "args_patch": {"provider": recommended_provider} if recommended_provider and recommended_provider != clean_provider else {},
            },
            {
                "phase": "retry_verify",
                "status": "pending",
                "summary": "Re-run preflight under retry contract and verify success criteria.",
                "tool_action": {"action": "external_connector_preflight", "args": {"action": clean_action, "provider": recommended_provider}},
            },
        ]
        remediation_hints = [
            {
                "id": "connector_preflight_contract",
                "severity": "high" if risk_score >= 0.72 else "medium",
                "message": (
                    f"Apply {automation_tier} remediation contract for '{clean_action}' "
                    f"(risk={round(risk_score, 3)}, retry_mode={execution_mode})."
                ),
                "args_patch": {"provider": recommended_provider} if recommended_provider and recommended_provider != clean_provider else {},
            }
        ]
        effective_retry_policy_output = dict(effective_retry_policy)
        effective_retry_policy_output["mode"] = execution_mode
        effective_retry_policy_output["max_attempts"] = int(max_retry_attempts)
        effective_retry_policy_output["recommended_delay_s"] = round(recommended_delay_s, 3)
        effective_retry_policy_output["schedule_s"] = retry_schedule[:8]
        effective_retry_policy_output["runtime_policy_hint"] = {
            "rust_pressure_score": round(rust_pressure_score, 6),
            "rust_retry_mode": rust_retry_mode,
            "rust_recommended_parallel_cap": int(rust_recommended_cap),
            "rust_suggested_retry_delay_s": round(rust_suggested_delay_s, 3),
        }
        return {
            "status": "success",
            "code": code or "preflight_contract",
            "severity": severity,
            "risk_score": round(risk_score, 6),
            "blocked_by_reliability": bool(blocked_by_reliability),
            "recommended_provider": recommended_provider,
            "failure_classes": failure_classes,
            "provider_route_plan": provider_route_plan[:8],
            "retry_policy": effective_retry_policy_output,
            "remediation_hints": remediation_hints,
            "remediation_plan": remediation_plan,
            "remediation_contract": remediation_contract,
        }

    def _external_connector_extract_orchestration_contract(
        self,
        *,
        output: Dict[str, Any],
        structured: Dict[str, Any],
    ) -> Dict[str, Any]:
        candidates: list[Dict[str, Any]] = []
        root_orchestration = output.get("preflight_orchestration", {})
        if isinstance(root_orchestration, dict):
            candidates.append(root_orchestration)
        contract_diag = output.get("contract_diagnostic", {})
        if isinstance(contract_diag, dict):
            diag_orchestration = contract_diag.get("orchestration_contract", {})
            if isinstance(diag_orchestration, dict):
                candidates.append(diag_orchestration)
        remediation_contract = output.get("remediation_contract", {})
        if isinstance(remediation_contract, dict):
            remediation_orchestration = remediation_contract.get("orchestration_contract", {})
            if isinstance(remediation_orchestration, dict):
                candidates.append(remediation_orchestration)
        structured_contract = structured.get("remediation_contract", {}) if isinstance(structured, dict) else {}
        if isinstance(structured_contract, dict):
            structured_orchestration = structured_contract.get("orchestration_contract", {})
            if isinstance(structured_orchestration, dict):
                candidates.append(structured_orchestration)

        for row in candidates:
            if not isinstance(row, dict):
                continue
            provider_rows = row.get("provider_rows", [])
            retry_schedule = row.get("retry_schedule", [])
            if (
                str(row.get("mode", "")).strip()
                or str(row.get("primary_provider", "")).strip()
                or isinstance(provider_rows, list)
                or isinstance(retry_schedule, list)
            ):
                return dict(row)
        return {}

    def _external_connector_contract_alignment_diagnostics(
        self,
        *,
        action: str,
        provider: str,
        output: Dict[str, Any],
        orchestration: Dict[str, Any],
        structured: Dict[str, Any],
    ) -> Dict[str, Any]:
        clean_action = str(action or "").strip().lower()
        clean_provider = self._normalize_external_provider_name(provider) or "auto"
        contract_orchestration = self._external_connector_extract_orchestration_contract(
            output=output,
            structured=structured,
        )

        structured_retry = structured.get("retry_policy", {}) if isinstance(structured.get("retry_policy", {}), dict) else {}
        output_retry = output.get("retry_policy", {}) if isinstance(output.get("retry_policy", {}), dict) else {}
        effective_retry_policy = dict(output_retry)
        if not effective_retry_policy and isinstance(structured_retry, dict):
            effective_retry_policy = dict(structured_retry)
        if isinstance(structured_retry, dict):
            for key, value in structured_retry.items():
                effective_retry_policy[key] = value

        route_plan_raw = structured.get("provider_route_plan", [])
        if not isinstance(route_plan_raw, list) or not route_plan_raw:
            route_plan_raw = orchestration.get("provider_route_plan", []) if isinstance(orchestration, dict) else []
        provider_route_plan = [row for row in route_plan_raw if isinstance(row, dict)] if isinstance(route_plan_raw, list) else []

        recommended_provider = (
            self._normalize_external_provider_name(
                structured.get(
                    "recommended_provider",
                    orchestration.get("recommended_provider", output.get("provider_recommended", clean_provider)),
                )
            )
            or clean_provider
        )
        contract_primary = (
            self._normalize_external_provider_name(contract_orchestration.get("primary_provider", ""))
            if isinstance(contract_orchestration, dict)
            else ""
        )
        contract_fallback = (
            self._normalize_external_provider_name(contract_orchestration.get("fallback_provider", ""))
            if isinstance(contract_orchestration, dict)
            else ""
        )
        runtime_pressure = max(0.0, min(float(orchestration.get("reliability_pressure", 0.0) or 0.0), 1.0))
        contract_pressure = (
            max(0.0, min(float(contract_orchestration.get("pressure", 0.0) or 0.0), 1.0))
            if isinstance(contract_orchestration, dict)
            else 0.0
        )
        pressure_drift = abs(runtime_pressure - contract_pressure) if isinstance(contract_orchestration, dict) else 0.0
        runtime_blocked = bool(orchestration.get("blocked_by_reliability", False))
        contract_blocked = False
        if isinstance(contract_orchestration, dict):
            contract_mode = str(contract_orchestration.get("mode", "")).strip().lower()
            contract_blocked = (
                contract_mode in {"severe", "blocked"}
                or contract_pressure >= 0.74
                or int(contract_orchestration.get("blocked_count", 0) or 0) > 0
                or int(contract_orchestration.get("outage_count", 0) or 0) > 0
            )

        checks: list[Dict[str, Any]] = []
        remediation_hints: list[Dict[str, Any]] = []

        def _check_row(*, check: str, status: str, severity: str, message: str, metrics: Dict[str, Any]) -> None:
            checks.append(
                {
                    "check": check,
                    "status": status,
                    "severity": severity,
                    "message": message,
                    "metrics": metrics,
                }
            )

        if contract_primary:
            if recommended_provider and recommended_provider != "auto" and contract_primary != recommended_provider:
                _check_row(
                    check="provider_primary_alignment",
                    status="failed",
                    severity="high",
                    message=(
                        f"Recommended provider '{recommended_provider}' differs from orchestration "
                        f"contract primary '{contract_primary}'."
                    ),
                    metrics={
                        "recommended_provider": recommended_provider,
                        "contract_primary_provider": contract_primary,
                        "contract_fallback_provider": contract_fallback,
                    },
                )
                remediation_hints.append(
                    {
                        "id": "contract_primary_provider_mismatch",
                        "severity": "high",
                        "message": "Contract primary provider is misaligned with runtime route recommendation.",
                        "args_patch": {"provider": recommended_provider},
                        "tool_action": {
                            "action": "external_connector_preflight",
                            "args": {"action": clean_action, "provider": recommended_provider},
                        },
                    }
                )
            else:
                _check_row(
                    check="provider_primary_alignment",
                    status="passed",
                    severity="low",
                    message="Orchestration primary provider aligns with runtime recommendation.",
                    metrics={
                        "recommended_provider": recommended_provider,
                        "contract_primary_provider": contract_primary,
                    },
                )
        else:
            _check_row(
                check="provider_primary_alignment",
                status="warning",
                severity="medium",
                message="Orchestration contract primary provider is missing.",
                metrics={"recommended_provider": recommended_provider},
            )
            remediation_hints.append(
                {
                    "id": "contract_primary_provider_missing",
                    "severity": "medium",
                    "message": "Orchestration contract did not provide a primary provider; refresh diagnostics.",
                    "tool_action": {
                        "action": "external_connector_status",
                        "args": {"provider": clean_provider},
                    },
                }
            )

        route_providers = {
            self._normalize_external_provider_name(row.get("provider", ""))
            for row in provider_route_plan
            if isinstance(row, dict)
        }
        route_providers.discard("")
        if recommended_provider and recommended_provider not in {"", "auto"} and recommended_provider not in route_providers:
            _check_row(
                check="provider_route_coverage",
                status="failed",
                severity="medium",
                message=f"Recommended provider '{recommended_provider}' is missing from provider_route_plan.",
                metrics={"route_provider_count": len(route_providers)},
            )
            remediation_hints.append(
                {
                    "id": "contract_route_missing_recommended",
                    "severity": "medium",
                    "message": "Provider route plan is missing the recommended provider; rebuild routing diagnostics.",
                    "tool_action": {
                        "action": "external_connector_status",
                        "args": {"provider": recommended_provider},
                    },
                }
            )
        else:
            _check_row(
                check="provider_route_coverage",
                status="passed",
                severity="low",
                message="Provider route plan contains the recommended provider lane.",
                metrics={"route_provider_count": len(route_providers)},
            )

        if contract_orchestration:
            pressure_status = "passed"
            pressure_severity = "low"
            pressure_message = "Runtime reliability pressure is aligned with orchestration pressure."
            if pressure_drift >= 0.3:
                pressure_status = "failed"
                pressure_severity = "high"
                pressure_message = "Reliability pressure drift is high between runtime and orchestration contract."
            elif pressure_drift >= 0.18:
                pressure_status = "warning"
                pressure_severity = "medium"
                pressure_message = "Reliability pressure drift is elevated; rerun preflight diagnostics."
            _check_row(
                check="pressure_alignment",
                status=pressure_status,
                severity=pressure_severity,
                message=pressure_message,
                metrics={
                    "runtime_reliability_pressure": round(runtime_pressure, 6),
                    "contract_reliability_pressure": round(contract_pressure, 6),
                    "pressure_drift": round(pressure_drift, 6),
                },
            )
            if pressure_status != "passed":
                remediation_hints.append(
                    {
                        "id": "contract_pressure_drift_detected",
                        "severity": pressure_severity,
                        "message": pressure_message,
                        "tool_action": {
                            "action": "external_connector_preflight",
                            "args": {"action": clean_action, "provider": recommended_provider or clean_provider},
                        },
                    }
                )
        else:
            _check_row(
                check="pressure_alignment",
                status="warning",
                severity="medium",
                message="No orchestration contract payload found for pressure alignment checks.",
                metrics={"runtime_reliability_pressure": round(runtime_pressure, 6)},
            )

        retry_schedule_raw = effective_retry_policy.get("schedule_s", [])
        retry_schedule = [
            round(max(0.0, float(item)), 3)
            for item in (retry_schedule_raw if isinstance(retry_schedule_raw, list) else [])
        ]
        expected_attempts = max(0, int(effective_retry_policy.get("max_attempts", len(retry_schedule)) or len(retry_schedule)))
        contract_retry_schedule = (
            contract_orchestration.get("retry_schedule", [])
            if isinstance(contract_orchestration.get("retry_schedule", []), list)
            else []
        ) if isinstance(contract_orchestration, dict) else []
        contract_retry_count = len([row for row in contract_retry_schedule if isinstance(row, dict)])
        retry_status = "passed"
        retry_severity = "low"
        retry_message = "Retry schedule and contract rows are aligned."
        if expected_attempts > 0 and contract_retry_count == 0:
            retry_status = "warning"
            retry_severity = "medium"
            retry_message = "Retry contract schedule is missing while retry attempts are expected."
        elif contract_retry_count > 0 and abs(contract_retry_count - expected_attempts) >= 2:
            retry_status = "warning"
            retry_severity = "medium"
            retry_message = "Retry contract schedule count drifts from effective retry attempts."
        _check_row(
            check="retry_contract_alignment",
            status=retry_status,
            severity=retry_severity,
            message=retry_message,
            metrics={
                "expected_attempts": int(expected_attempts),
                "effective_schedule_count": len(retry_schedule),
                "contract_schedule_count": int(contract_retry_count),
            },
        )
        if retry_status != "passed":
            remediation_hints.append(
                {
                    "id": "contract_retry_schedule_rebuild",
                    "severity": retry_severity,
                    "message": retry_message,
                    "tool_action": {
                        "action": "external_connector_preflight",
                        "args": {"action": clean_action, "provider": recommended_provider or clean_provider},
                    },
                }
            )

        if contract_orchestration:
            block_status = "passed" if runtime_blocked == contract_blocked else "failed"
            block_severity = "low" if block_status == "passed" else "high"
            block_message = (
                "Runtime and orchestration contract agree on reliability blocking state."
                if block_status == "passed"
                else "Runtime blocking state does not match orchestration contract severity."
            )
            _check_row(
                check="blocking_state_alignment",
                status=block_status,
                severity=block_severity,
                message=block_message,
                metrics={
                    "runtime_blocked": bool(runtime_blocked),
                    "contract_blocked": bool(contract_blocked),
                },
            )
            if block_status != "passed":
                remediation_hints.append(
                    {
                        "id": "contract_blocking_state_mismatch",
                        "severity": "high",
                        "message": block_message,
                        "tool_action": {
                            "action": "external_connector_status",
                            "args": {"provider": clean_provider},
                        },
                    }
                )

        severity_rank = {"low": 0, "medium": 1, "high": 2, "critical": 3}
        top_severity = "low"
        has_failed = False
        mismatch_score = 0.0
        for row in checks:
            status_value = str(row.get("status", "")).strip().lower()
            severity_value = str(row.get("severity", "low")).strip().lower() or "low"
            if severity_rank.get(severity_value, 0) > severity_rank.get(top_severity, 0):
                top_severity = severity_value
            if status_value == "failed":
                has_failed = True
                mismatch_score += 0.34 if severity_value in {"medium", "low"} else 0.52
            elif status_value == "warning":
                mismatch_score += 0.18 if severity_value == "medium" else 0.1
        mismatch_score = max(0.0, min(mismatch_score, 1.0))

        status = "success"
        if has_failed:
            status = "error"
        elif mismatch_score >= 0.16:
            status = "warning"

        return {
            "status": status,
            "severity": top_severity,
            "mismatch_score": round(mismatch_score, 6),
            "action": clean_action,
            "provider": clean_provider,
            "recommended_provider": recommended_provider,
            "contract_orchestration": contract_orchestration if isinstance(contract_orchestration, dict) else {},
            "checks": checks[:10],
            "remediation_hints": remediation_hints[:8],
            "summary": (
                "Connector preflight contract alignment checks passed."
                if status == "success"
                else "Connector preflight contract alignment detected drift and requires remediation."
            ),
        }

    def _external_connector_preflight_orchestration(
        self,
        *,
        action: str,
        provider: str,
    ) -> Dict[str, Any]:
        clean_action = str(action or "").strip().lower()
        clean_provider = self._normalize_external_provider_name(provider)
        fetch = getattr(getattr(self, "kernel", None), "external_reliability_status", None)
        if not callable(fetch):
            runtime_context = self._bridge_scheduler_runtime_context(force_refresh=False)
            return {
                "status": "success",
                "provider_requested": clean_provider or "auto",
                "provider_count": 0,
                "provider_health": [],
                "mission_outage_policy": {},
                "mission_analysis": self._external_connector_mission_analysis_cached(force_refresh=False),
                "runtime_context": runtime_context,
                "reliability_pressure": 0.0,
                "blocked_by_reliability": False,
                "recommended_provider": clean_provider or "auto",
                "provider_route_plan": [],
                "remediation_hints": [],
                "route_weight_advisor": {},
                "cooldown_outage_explainer": {},
                "retry_policy": {"recommended_delay_s": 0.0, "mode": "none"},
                "message": "External reliability orchestrator unavailable.",
            }
        try:
            snapshot = fetch(provider="" if clean_provider in {"", "auto"} else clean_provider, limit=180)
        except Exception as exc:  # noqa: BLE001
            runtime_context = self._bridge_scheduler_runtime_context(force_refresh=False)
            return {
                "status": "error",
                "provider_requested": clean_provider or "auto",
                "provider_count": 0,
                "provider_health": [],
                "mission_outage_policy": {},
                "mission_analysis": self._external_connector_mission_analysis_cached(force_refresh=False),
                "runtime_context": runtime_context,
                "reliability_pressure": 0.0,
                "blocked_by_reliability": False,
                "recommended_provider": clean_provider or "auto",
                "provider_route_plan": [],
                "remediation_hints": [
                    {
                        "id": "reliability_snapshot_failed",
                        "severity": "warning",
                        "message": f"Failed to load external reliability snapshot: {exc}",
                    }
                ],
                "route_weight_advisor": {},
                "cooldown_outage_explainer": {},
                "retry_policy": {"recommended_delay_s": 0.0, "mode": "none"},
                "message": "External reliability snapshot fetch failed.",
            }

        mission_policy = snapshot.get("mission_outage_policy", {}) if isinstance(snapshot, dict) else {}
        mission_analysis = self._external_connector_mission_analysis_cached(force_refresh=False)
        runtime_context = self._bridge_scheduler_runtime_context(force_refresh=False)
        rows = snapshot.get("items", []) if isinstance(snapshot, dict) else []
        provider_rows = rows if isinstance(rows, list) else []
        selected_rows: list[Dict[str, Any]] = []
        for row in provider_rows:
            if not isinstance(row, dict):
                continue
            row_provider = self._normalize_external_provider_name(row.get("provider", ""))
            if not row_provider:
                continue
            if clean_provider not in {"", "auto"} and row_provider != clean_provider:
                continue
            health_score = max(0.0, min(float(row.get("health_score", 0.0) or 0.0), 1.0))
            failure_ema = max(0.0, min(float(row.get("failure_ema", 0.0) or 0.0), 1.0))
            cooldown_active = bool(row.get("cooldown_active", False))
            outage_active = bool(row.get("outage_active", False))
            retry_after_s = max(0.0, float(row.get("retry_after_s", 0.0) or 0.0))
            selected_rows.append(
                {
                    "provider": row_provider,
                    "health_score": round(health_score, 6),
                    "failure_ema": round(failure_ema, 6),
                    "cooldown_active": cooldown_active,
                    "outage_active": outage_active,
                    "retry_after_s": round(retry_after_s, 3),
                    "outage_policy_bias": round(max(-1.0, min(float(row.get("outage_policy_bias", 0.0) or 0.0), 1.0)), 6),
                    "cooldown_bias": round(max(0.2, min(float(row.get("cooldown_bias", 1.0) or 1.0), 5.0)), 6),
                    "route_block_threshold": round(max(0.2, min(float(row.get("route_block_threshold", 0.86) or 0.86), 1.0)), 6),
                    "preflight_block_threshold": round(max(0.2, min(float(row.get("preflight_block_threshold", 0.92) or 0.92), 1.0)), 6),
                    "mission_profile_alignment": round(max(-1.0, min(float(row.get("mission_profile_alignment", 0.0) or 0.0), 1.0)), 6),
                    "mission_pressure": round(max(0.0, min(float(row.get("outage_mission_pressure", 0.0) or 0.0), 1.0)), 6),
                    "health_state": (
                        "degraded"
                        if cooldown_active or outage_active or failure_ema >= 0.6 or health_score <= 0.42
                        else "healthy"
                    ),
                }
            )
        selected_rows.sort(
            key=lambda item: (
                int(item.get("cooldown_active", False)),
                int(item.get("outage_active", False)),
                -float(item.get("health_score", 0.0) or 0.0),
                float(item.get("failure_ema", 0.0) or 0.0),
                str(item.get("provider", "")),
            )
        )

        def _row_pressure(row: Dict[str, Any]) -> float:
            health = max(0.0, min(float(row.get("health_score", 0.0) or 0.0), 1.0))
            failure = max(0.0, min(float(row.get("failure_ema", 0.0) or 0.0), 1.0))
            pressure = max(failure, 1.0 - health)
            if bool(row.get("cooldown_active", False)):
                pressure = max(pressure, 0.78)
            if bool(row.get("outage_active", False)):
                pressure = max(pressure, 0.92)
            return max(0.0, min(pressure, 1.0))

        pressure_rows = [_row_pressure(row) for row in selected_rows]
        provider_pressure = (sum(pressure_rows) / float(len(pressure_rows))) if pressure_rows else 0.0
        mode = str(mission_policy.get("mode", "")).strip().lower()
        analysis_mode = str(mission_analysis.get("mission_mode", "")).strip().lower()
        if analysis_mode:
            mode = analysis_mode
        trend_mode = str(mission_analysis.get("trend_mode", "")).strip().lower()
        volatility_mode = str(mission_analysis.get("volatility_mode", "")).strip().lower()
        trend_pressure = max(0.0, min(float(mission_analysis.get("trend_pressure", 0.0) or 0.0), 1.0))
        at_risk_ratio = max(0.0, min(float(mission_analysis.get("at_risk_ratio", 0.0) or 0.0), 1.0))
        volatility_index = max(0.0, min(float(mission_analysis.get("volatility_index", 0.0) or 0.0), 1.0))
        provider_policy_tuning_status = str(
            mission_analysis.get("provider_policy_tuning_status", "unknown")
        ).strip().lower() or "unknown"
        provider_policy_tuning_changed = bool(mission_analysis.get("provider_policy_tuning_changed", False))
        provider_policy_tuning_updated_count = max(
            0,
            int(mission_analysis.get("provider_policy_tuning_updated_count", 0) or 0),
        )
        rust_pressure_score = max(0.0, min(float(runtime_context.get("rust_pressure_score", 0.0) or 0.0), 1.0))
        rust_parallel_cap = max(0, int(runtime_context.get("rust_recommended_parallel_cap", 0) or 0))
        mode_pressure = 0.0
        if mode in {"degraded", "critical", "protective", "restricted"}:
            mode_pressure = 0.18
        trend_mode_pressure = 0.0
        if trend_mode in {"worsening", "degraded", "severe"}:
            trend_mode_pressure = 0.12
        elif trend_mode in {"improving"}:
            trend_mode_pressure = -0.04
        volatility_pressure = 0.0
        if volatility_mode in {"surging"}:
            volatility_pressure = 0.08
        elif volatility_mode in {"elevated"}:
            volatility_pressure = 0.04
        elif volatility_mode in {"calm"}:
            volatility_pressure = -0.03
        reliability_pressure = max(
            0.0,
            min(
                (provider_pressure * 0.64)
                + mode_pressure
                + (trend_pressure * 0.2)
                + (at_risk_ratio * 0.16)
                + trend_mode_pressure
                + volatility_pressure
                + (volatility_index * 0.05),
                1.0,
            ),
        )

        requested_row = next(
            (row for row in selected_rows if str(row.get("provider", "")) == clean_provider),
            None,
        ) if clean_provider not in {"", "auto"} else None
        healthy_alternatives = [
            row
            for row in selected_rows
            if not bool(row.get("cooldown_active", False))
            and not bool(row.get("outage_active", False))
            and float(row.get("health_score", 0.0) or 0.0) >= 0.45
        ]
        recommended_provider = clean_provider or "auto"
        if healthy_alternatives:
            recommended_provider = str(healthy_alternatives[0].get("provider", clean_provider or "auto"))
        runtime_lane = "parallel"
        if rust_pressure_score >= 0.78 or reliability_pressure >= 0.82:
            runtime_lane = "serial"
        elif rust_pressure_score >= 0.56 or reliability_pressure >= 0.62:
            runtime_lane = "limited_parallel"
        if rust_pressure_score >= 0.5:
            reliability_pressure = min(1.0, reliability_pressure + (0.06 * rust_pressure_score))
        blocked_by_reliability = False
        if requested_row is not None and (
            bool(requested_row.get("cooldown_active", False))
            or bool(requested_row.get("outage_active", False))
        ):
            blocked_by_reliability = True
        if clean_provider in {"", "auto"} and selected_rows and not healthy_alternatives and reliability_pressure >= 0.74:
            blocked_by_reliability = True
        if trend_mode in {"worsening", "degraded"} and reliability_pressure >= 0.78:
            blocked_by_reliability = True
        if runtime_lane == "serial" and reliability_pressure >= 0.76:
            blocked_by_reliability = True

        requested_pressure = _row_pressure(requested_row) if isinstance(requested_row, dict) else 0.0
        mission_policy_reason = "stable_operating_window"
        mission_policy_reasons: list[str] = []
        if requested_row is not None:
            route_block_threshold = max(0.2, min(float(requested_row.get("route_block_threshold", 0.86) or 0.86), 1.0))
            preflight_block_threshold = max(0.2, min(float(requested_row.get("preflight_block_threshold", 0.92) or 0.92), 1.0))
            if bool(requested_row.get("cooldown_active", False)):
                mission_policy_reasons.append("requested_provider_in_cooldown")
            if bool(requested_row.get("outage_active", False)):
                mission_policy_reasons.append("requested_provider_outage_active")
            if requested_pressure >= route_block_threshold:
                mission_policy_reasons.append("requested_provider_exceeds_route_block_threshold")
            if requested_pressure >= preflight_block_threshold:
                mission_policy_reasons.append("requested_provider_exceeds_preflight_block_threshold")
            if float(requested_row.get("mission_profile_alignment", 0.0) or 0.0) <= -0.2:
                mission_policy_reasons.append("requested_provider_misaligned_with_mission_profile")
        if blocked_by_reliability and clean_provider in {"", "auto"} and not healthy_alternatives:
            mission_policy_reasons.append("no_healthy_alternatives_under_current_profile")
        if runtime_lane == "serial" and reliability_pressure >= 0.76:
            mission_policy_reasons.append("runtime_lane_serial_due_to_combined_pressure")
        if trend_mode in {"worsening", "degraded"} and reliability_pressure >= 0.78:
            mission_policy_reasons.append("mission_trend_worsening_with_high_reliability_pressure")
        if mission_policy_reasons:
            mission_policy_reason = mission_policy_reasons[0]

        mission_policy_decision = {
            "mode": mode,
            "profile": str(mission_policy.get("profile", "")).strip().lower(),
            "bias": round(max(-1.0, min(float(mission_policy.get("bias", 0.0) or 0.0), 1.0)), 6),
            "analysis_mode": analysis_mode,
            "trend_mode": trend_mode,
            "volatility_mode": volatility_mode,
            "reliability_pressure": round(reliability_pressure, 6),
            "runtime_lane": runtime_lane,
            "blocked": bool(blocked_by_reliability),
            "reason": mission_policy_reason,
            "reasons": mission_policy_reasons[:8],
            "requested_provider": clean_provider or "auto",
            "recommended_provider": recommended_provider,
            "requested_provider_pressure": round(requested_pressure, 6),
            "thresholds": {
                "route_block_min": round(
                    min(float(row.get("route_block_threshold", 1.0) or 1.0) for row in selected_rows),
                    6,
                )
                if selected_rows
                else 0.0,
                "preflight_block_min": round(
                    min(float(row.get("preflight_block_threshold", 1.0) or 1.0) for row in selected_rows),
                    6,
                )
                if selected_rows
                else 0.0,
            },
            "provider_pressure_summary": [
                {
                    "provider": str(row.get("provider", "")).strip().lower(),
                    "pressure": round(_row_pressure(row), 6),
                    "route_block_threshold": round(float(row.get("route_block_threshold", 0.86) or 0.86), 6),
                    "preflight_block_threshold": round(float(row.get("preflight_block_threshold", 0.92) or 0.92), 6),
                    "outage_policy_bias": round(float(row.get("outage_policy_bias", 0.0) or 0.0), 6),
                    "cooldown_bias": round(float(row.get("cooldown_bias", 1.0) or 1.0), 6),
                    "mission_profile_alignment": round(float(row.get("mission_profile_alignment", 0.0) or 0.0), 6),
                }
                for row in selected_rows[:4]
            ],
        }

        provider_route_plan: list[Dict[str, Any]] = []
        for index, row in enumerate(selected_rows[:12]):
            row_provider = str(row.get("provider", "")).strip().lower()
            row_pressure = _row_pressure(row)
            row_health = max(0.0, min(float(row.get("health_score", 0.0) or 0.0), 1.0))
            row_failure = max(0.0, min(float(row.get("failure_ema", 0.0) or 0.0), 1.0))
            cooldown_active = bool(row.get("cooldown_active", False))
            outage_active = bool(row.get("outage_active", False))
            eligible = (not cooldown_active) and (not outage_active) and row_pressure < 0.88
            score = max(
                0.0,
                min(
                    1.0,
                    (row_health * 0.62)
                    + ((1.0 - row_failure) * 0.28)
                    + (0.1 if not cooldown_active and not outage_active else 0.0)
                    - (row_pressure * 0.15),
                ),
            )
            tier = "blocked"
            if eligible:
                if row_provider == recommended_provider:
                    tier = "primary"
                elif len([item for item in provider_route_plan if str(item.get("tier", "")) == "fallback"]) < 2:
                    tier = "fallback"
                else:
                    tier = "probe"
            provider_route_plan.append(
                {
                    "provider": row_provider,
                    "tier": tier,
                    "priority": index + 1,
                    "eligible": bool(eligible),
                    "score": round(score, 6),
                    "pressure": round(row_pressure, 6),
                    "health_score": round(row_health, 6),
                    "failure_ema": round(row_failure, 6),
                    "cooldown_active": cooldown_active,
                    "outage_active": outage_active,
                    "retry_after_s": round(max(0.0, float(row.get("retry_after_s", 0.0) or 0.0)), 3),
                    "outage_policy_bias": round(float(row.get("outage_policy_bias", 0.0) or 0.0), 6),
                    "cooldown_bias": round(float(row.get("cooldown_bias", 1.0) or 1.0), 6),
                    "route_block_threshold": round(float(row.get("route_block_threshold", 0.86) or 0.86), 6),
                    "preflight_block_threshold": round(float(row.get("preflight_block_threshold", 0.92) or 0.92), 6),
                    "mission_profile_alignment": round(float(row.get("mission_profile_alignment", 0.0) or 0.0), 6),
                    "reason": (
                        "recommended_provider"
                        if row_provider == recommended_provider
                        else ("degraded" if (cooldown_active or outage_active or row_pressure >= 0.7) else "candidate")
                    ),
                }
            )

        remediation_hints: list[Dict[str, Any]] = []
        if blocked_by_reliability:
            remediation_hints.append(
                {
                    "id": "provider_reliability_blocked",
                    "severity": "high",
                    "message": "Provider reliability conditions currently block safe execution.",
                    "tool_action": {
                        "action": "external_connector_status",
                        "args": {"provider": clean_provider or "auto"},
                    },
                }
            )
        if recommended_provider and clean_provider not in {"", "auto"} and recommended_provider != clean_provider:
            remediation_hints.append(
                {
                    "id": "switch_provider_recommended",
                    "severity": "medium",
                    "message": (
                        f"Requested provider '{clean_provider}' is degraded. "
                        f"Use provider '{recommended_provider}' for retries."
                    ),
                    "args_patch": {"provider": recommended_provider},
                }
            )
        if reliability_pressure >= 0.7:
            remediation_hints.append(
                {
                    "id": "retry_backoff_required",
                    "severity": "medium",
                    "message": "Increase retry backoff and run connector diagnostics before retry.",
                    "tool_action": {"action": "external_connector_preflight", "args": {"action": clean_action}},
                }
            )
        if trend_mode in {"worsening", "degraded"}:
            remediation_hints.append(
                {
                    "id": "mission_reliability_worsening",
                    "severity": "medium",
                    "message": (
                        "Mission reliability trend is worsening. "
                        "Run mission analysis and tighten connector retry profile before execution."
                    ),
                    "tool_action": {
                        "action": "external_connector_status",
                        "args": {"provider": clean_provider or "auto"},
                    },
                }
            )
        if not selected_rows:
            remediation_hints.append(
                {
                    "id": "provider_health_unavailable",
                    "severity": "low",
                    "message": "No provider health rows were available; run connector status diagnostics before retries.",
                    "tool_action": {"action": "external_connector_status", "args": {"provider": clean_provider or "auto"}},
                }
            )
        if provider_policy_tuning_changed and provider_policy_tuning_updated_count > 0:
            remediation_hints.append(
                {
                    "id": "mission_provider_policy_autotuned",
                    "severity": "medium",
                    "message": (
                        f"Mission provider policy recently autotuned ({provider_policy_tuning_updated_count} updates). "
                        "Re-run preflight with refreshed provider routing contract."
                    ),
                    "tool_action": {
                        "action": "external_connector_preflight",
                        "args": {"action": clean_action, "provider": recommended_provider or clean_provider or "auto"},
                    },
                }
            )
        if runtime_lane != "parallel":
            remediation_hints.append(
                {
                    "id": "runtime_lane_throttle_recommended",
                    "severity": "medium" if runtime_lane == "limited_parallel" else "high",
                    "message": (
                        f"Runtime lane is '{runtime_lane}' due to host pressure; reduce connector parallelism "
                        "and prefer staged retries."
                    ),
                    "runtime_lane": runtime_lane,
                    "recommended_parallel_cap": int(max(1, rust_parallel_cap) if rust_parallel_cap > 0 else (1 if runtime_lane == "serial" else 2)),
                }
            )
        if mission_policy_reasons:
            remediation_hints.append(
                {
                    "id": "mission_policy_decision_trace",
                    "severity": "medium" if not blocked_by_reliability else "high",
                    "message": (
                        f"Mission policy selected '{recommended_provider}' under profile "
                        f"'{mission_policy_decision['profile'] or 'balanced'}' because {mission_policy_reason}."
                    ),
                    "decision": mission_policy_decision,
                }
            )

        retry_after_rows = [float(row.get("retry_after_s", 0.0) or 0.0) for row in selected_rows]
        recommended_delay_s = max(retry_after_rows) if retry_after_rows else 0.0
        if recommended_delay_s <= 0.0 and reliability_pressure >= 0.52:
            recommended_delay_s = round(8.0 + (reliability_pressure * 24.0), 3)
        retry_policy = self._external_connector_build_retry_policy(
            reliability_pressure=reliability_pressure,
            recommended_delay_s=recommended_delay_s,
            trend_mode=trend_mode,
            volatility_mode=volatility_mode,
            blocked_by_reliability=blocked_by_reliability,
        )
        retry_policy["recommended_delay_s"] = round(max(0.0, float(recommended_delay_s)), 3)
        route_weight_advisor = self._external_connector_build_route_weight_advisor(
            action=clean_action,
            requested_provider=clean_provider or "auto",
            recommended_provider=recommended_provider,
            provider_route_plan=provider_route_plan,
            retry_policy=retry_policy,
            mission_policy_decision=mission_policy_decision,
            reliability_pressure=reliability_pressure,
            runtime_lane=runtime_lane,
            blocked_by_reliability=blocked_by_reliability,
        )
        cooldown_outage_explainer = self._external_connector_build_cooldown_outage_explainer(
            action=clean_action,
            requested_provider=clean_provider or "auto",
            recommended_provider=recommended_provider,
            selected_rows=selected_rows,
            provider_route_plan=provider_route_plan,
            retry_policy=retry_policy,
            mission_policy_decision=mission_policy_decision,
            reliability_pressure=reliability_pressure,
            runtime_lane=runtime_lane,
            blocked_by_reliability=blocked_by_reliability,
        )
        return {
            "status": "success",
            "provider_requested": clean_provider or "auto",
            "provider_count": len(selected_rows),
            "provider_health": selected_rows[:8],
            "mission_outage_policy": {
                "mode": mode,
                "bias": float(mission_policy.get("bias", 0.0) or 0.0),
                "pressure_ema": float(mission_policy.get("pressure_ema", 0.0) or 0.0),
                "profile": str(mission_policy.get("profile", "")).strip().lower(),
            },
            "mission_analysis": mission_analysis,
            "runtime_context": runtime_context,
            "reliability_pressure": round(reliability_pressure, 6),
            "blocked_by_reliability": bool(blocked_by_reliability),
            "recommended_provider": recommended_provider,
            "runtime_lane": runtime_lane,
            "recommended_parallel_cap": int(max(1, rust_parallel_cap) if rust_parallel_cap > 0 else (1 if runtime_lane == "serial" else 2)),
            "provider_policy_tuning": {
                "status": provider_policy_tuning_status,
                "changed": bool(provider_policy_tuning_changed),
                "updated_count": int(provider_policy_tuning_updated_count),
            },
            "mission_policy_decision": mission_policy_decision,
            "provider_route_plan": provider_route_plan,
            "route_weight_advisor": route_weight_advisor,
            "cooldown_outage_explainer": cooldown_outage_explainer,
            "remediation_hints": remediation_hints[:8],
            "retry_policy": retry_policy,
            "message": "Reliability diagnostics attached.",
        }

    def run_external_connector_preflight(
        self,
        args: Optional[Dict[str, Any]] = None,
        *,
        source: str = "desktop-ui",
        metadata: Optional[Dict[str, Any]] = None,
    ) -> Dict[str, Any]:
        payload = args if isinstance(args, dict) else {}
        runtime_meta = metadata if isinstance(metadata, dict) else {}
        result = self.execute_action("external_connector_preflight", payload, source=source, metadata=runtime_meta)
        if result.get("status") != "success" or not isinstance(result.get("output"), dict):
            return result

        output = dict(result["output"])
        action_name = str(output.get("action", payload.get("action", ""))).strip().lower()
        provider_name = self._normalize_external_provider_name(
            output.get("provider_selected", output.get("provider", payload.get("provider", "auto")))
        ) or "auto"
        orchestration = self._external_connector_preflight_orchestration(
            action=action_name,
            provider=provider_name,
        )
        output["orchestration_diagnostics"] = orchestration

        existing_hints = output.get("remediation_hints", [])
        merged_hints = existing_hints if isinstance(existing_hints, list) else []
        orchestration_hints = orchestration.get("remediation_hints", [])
        if isinstance(orchestration_hints, list):
            merged_hints.extend([item for item in orchestration_hints if isinstance(item, dict)])

        blocked_by_reliability = bool(orchestration.get("blocked_by_reliability", False))
        override_raw = runtime_meta.get("external_cooldown_override", False)
        if isinstance(override_raw, str):
            cooldown_override = override_raw.strip().lower() in {"1", "true", "yes", "on"}
        else:
            cooldown_override = bool(override_raw)
        if blocked_by_reliability and not cooldown_override:
            output["status"] = "error"
            output["preflight_ready"] = False
            output["message"] = str(output.get("message", "Connector preflight blocked by reliability policy.")).strip()
            if "blocked by reliability policy" not in output["message"].lower():
                output["message"] = (
                    f"{output['message']} Provider reliability policy is blocking execution. "
                    "Use metadata.external_cooldown_override=true only for urgent manual override."
                ).strip()
            contract = output.get("contract_diagnostic", {})
            if isinstance(contract, dict):
                updated_contract = dict(contract)
                updated_contract["code"] = "provider_reliability_blocked"
                updated_contract["severity"] = "high"
                updated_contract["message"] = str(output.get("message", updated_contract.get("message", "")))
                output["contract_diagnostic"] = updated_contract

        recommended_provider = str(orchestration.get("recommended_provider", "")).strip().lower()
        if recommended_provider and recommended_provider != provider_name:
            output["provider_recommended"] = recommended_provider

        execution_handoff = self._external_connector_build_execution_handoff(
            action=action_name,
            base_args=payload.get("args") if isinstance(payload.get("args"), dict) else {},
            requested_provider=provider_name,
            recommended_provider=recommended_provider or provider_name,
            route_weight_advisor=orchestration.get("route_weight_advisor", {})
            if isinstance(orchestration.get("route_weight_advisor"), dict)
            else {},
            cooldown_outage_explainer=orchestration.get("cooldown_outage_explainer", {})
            if isinstance(orchestration.get("cooldown_outage_explainer"), dict)
            else {},
            retry_policy=orchestration.get("retry_policy", {}) if isinstance(orchestration.get("retry_policy"), dict) else {},
            mission_policy_decision=orchestration.get("mission_policy_decision", {})
            if isinstance(orchestration.get("mission_policy_decision"), dict)
            else {},
        )
        orchestration["execution_handoff"] = execution_handoff
        output["execution_candidates"] = execution_handoff.get("candidates", []) if isinstance(execution_handoff.get("candidates"), list) else []
        if isinstance(execution_handoff.get("approval_summary"), dict):
            output["approval_summary"] = dict(execution_handoff.get("approval_summary", {}))
            orchestration["approval_summary"] = dict(execution_handoff.get("approval_summary", {}))
        if isinstance(execution_handoff.get("simulation_template"), dict):
            output["advisor_simulation_template"] = dict(execution_handoff.get("simulation_template", {}))
        if isinstance(execution_handoff.get("advisor_context"), dict):
            output["advisor_context"] = dict(execution_handoff.get("advisor_context", {}))

        structured = self._external_connector_build_structured_preflight_contract(
            action=action_name,
            provider=provider_name,
            output=output,
            orchestration=orchestration,
        )
        output["diagnostic_summary"] = structured
        provider_route_plan = structured.get("provider_route_plan", [])
        if isinstance(provider_route_plan, list) and provider_route_plan:
            output["provider_route_plan"] = provider_route_plan[:12]
        retry_policy = structured.get("retry_policy", {})
        if isinstance(retry_policy, dict) and retry_policy:
            output["retry_policy"] = retry_policy

        structured_hints = structured.get("remediation_hints", [])
        if isinstance(structured_hints, list):
            merged_hints.extend([item for item in structured_hints if isinstance(item, dict)])
        alignment = self._external_connector_contract_alignment_diagnostics(
            action=action_name,
            provider=provider_name,
            output=output,
            orchestration=orchestration,
            structured=structured,
        )
        output["orchestration_contract_diagnostics"] = alignment
        alignment_hints = alignment.get("remediation_hints", [])
        if isinstance(alignment_hints, list):
            merged_hints.extend([item for item in alignment_hints if isinstance(item, dict)])
        alignment_status = str(alignment.get("status", "")).strip().lower()
        if alignment_status == "error" and not cooldown_override:
            output["status"] = "error"
            output["preflight_ready"] = False
            base_message = str(output.get("message", "Connector preflight contract alignment failed.")).strip()
            if "contract alignment" not in base_message.lower():
                base_message = (
                    f"{base_message} Connector preflight contract alignment failed and requires diagnostics refresh."
                ).strip()
            output["message"] = base_message
            contract_row = output.get("contract_diagnostic", {})
            if isinstance(contract_row, dict):
                updated_contract = dict(contract_row)
                updated_contract["code"] = "preflight_contract_alignment_failed"
                updated_contract["severity"] = "high"
                updated_contract["message"] = base_message
                output["contract_diagnostic"] = updated_contract
        dedup_hints: list[Dict[str, Any]] = []
        seen_hint_ids: set[str] = set()
        for hint in merged_hints:
            if not isinstance(hint, dict):
                continue
            hint_id = str(hint.get("id", "") or hint.get("code", "") or hint.get("message", "")).strip().lower()
            if not hint_id or hint_id in seen_hint_ids:
                continue
            seen_hint_ids.add(hint_id)
            dedup_hints.append(hint)
        output["remediation_hints"] = dedup_hints[:20]

        structured_plan = structured.get("remediation_plan", [])
        root_plan = output.get("remediation_plan", [])
        merged_plan = []
        if isinstance(root_plan, list):
            merged_plan.extend([item for item in root_plan if isinstance(item, dict)])
        if isinstance(structured_plan, list):
            merged_plan.extend([item for item in structured_plan if isinstance(item, dict)])
        if merged_plan:
            dedup_plan: list[Dict[str, Any]] = []
            seen_phases: set[str] = set()
            for phase in merged_plan:
                phase_key = str(phase.get("phase", "") or phase.get("id", "") or phase.get("summary", "")).strip().lower()
                if not phase_key or phase_key in seen_phases:
                    continue
                seen_phases.add(phase_key)
                dedup_plan.append(phase)
            output["remediation_plan"] = dedup_plan[:16]

        structured_contract = structured.get("remediation_contract", {})
        if isinstance(structured_contract, dict) and structured_contract:
            root_contract = output.get("remediation_contract", {})
            merged_contract = dict(root_contract) if isinstance(root_contract, dict) else {}
            merged_contract.update(structured_contract)
            output["remediation_contract"] = merged_contract

        contract_row = output.get("contract_diagnostic", {})
        if isinstance(contract_row, dict):
            alignment_checks = alignment.get("checks", [])
            failed_checks = [
                row for row in alignment_checks if isinstance(row, dict) and str(row.get("status", "")).strip().lower() == "failed"
            ] if isinstance(alignment_checks, list) else []
            warning_checks = [
                row for row in alignment_checks if isinstance(row, dict) and str(row.get("status", "")).strip().lower() == "warning"
            ] if isinstance(alignment_checks, list) else []
            updated_contract = dict(contract_row)
            updated_contract["orchestration_contract_diagnostics"] = {
                "status": str(alignment.get("status", "")).strip().lower() or "unknown",
                "severity": str(alignment.get("severity", "")).strip().lower() or "unknown",
                "mismatch_score": float(alignment.get("mismatch_score", 0.0) or 0.0),
                "failed_check_count": len(failed_checks),
                "warning_check_count": len(warning_checks),
            }
            if failed_checks:
                updated_contract["orchestration_contract_failed_checks"] = failed_checks[:5]
            output["contract_diagnostic"] = updated_contract

        merged_contract = output.get("remediation_contract", {})
        if isinstance(merged_contract, dict):
            updated_remediation_contract = dict(merged_contract)
            contract_orchestration = alignment.get("contract_orchestration", {})
            if isinstance(contract_orchestration, dict) and contract_orchestration:
                updated_remediation_contract["orchestration_contract"] = contract_orchestration
                output["preflight_orchestration"] = contract_orchestration
            updated_remediation_contract["alignment_diagnostics"] = {
                "status": str(alignment.get("status", "")).strip().lower() or "unknown",
                "severity": str(alignment.get("severity", "")).strip().lower() or "unknown",
                "mismatch_score": float(alignment.get("mismatch_score", 0.0) or 0.0),
                "summary": str(alignment.get("summary", "")).strip(),
            }
            output["remediation_contract"] = updated_remediation_contract

        return output

    def simulate_external_connector_preflight(
        self,
        args: Optional[Dict[str, Any]] = None,
        *,
        source: str = "desktop-ui",
        metadata: Optional[Dict[str, Any]] = None,
    ) -> Dict[str, Any]:
        payload = args if isinstance(args, dict) else {}
        runtime_meta = metadata if isinstance(metadata, dict) else {}
        clean_action = str(payload.get("action", "")).strip().lower()
        if not clean_action:
            return {"status": "error", "message": "action is required"}

        def _bool(value: Any, default: bool = False) -> bool:
            if isinstance(value, bool):
                return value
            if isinstance(value, (int, float)):
                return bool(value)
            if isinstance(value, str):
                lowered = value.strip().lower()
                if lowered in {"1", "true", "yes", "on", "enabled"}:
                    return True
                if lowered in {"0", "false", "no", "off", "disabled"}:
                    return False
            return default

        def _float(value: Any, default: float = 0.0, *, minimum: float = 0.0, maximum: float = 1.0) -> float:
            try:
                parsed = float(value)
            except Exception:
                parsed = default
            if parsed < minimum:
                return minimum
            if parsed > maximum:
                return maximum
            return parsed

        def _int(value: Any, default: int = 0, *, minimum: int = 0, maximum: int = 200) -> int:
            try:
                parsed = int(value)
            except Exception:
                parsed = default
            if parsed < minimum:
                return minimum
            if parsed > maximum:
                return maximum
            return parsed

        def _provider_candidates(raw: Any) -> list[str]:
            rows: list[str] = []
            if isinstance(raw, list):
                for item in raw:
                    provider = self._normalize_external_provider_name(item)
                    if provider and provider not in rows:
                        rows.append(provider)
            elif isinstance(raw, str):
                for chunk in raw.split(","):
                    provider = self._normalize_external_provider_name(chunk)
                    if provider and provider not in rows:
                        rows.append(provider)
            return rows

        def _route_primary_provider(route_plan: list[Dict[str, Any]]) -> str:
            for row in route_plan:
                tier = str(row.get("tier", "")).strip().lower()
                provider = self._normalize_external_provider_name(row.get("provider", ""))
                if provider and tier == "primary":
                    return provider
            for row in route_plan:
                provider = self._normalize_external_provider_name(row.get("provider", ""))
                if provider:
                    return provider
            return ""

        def _route_fallback_chain(route_plan: list[Dict[str, Any]], primary_provider: str) -> list[str]:
            chain: list[str] = []
            clean_primary = self._normalize_external_provider_name(primary_provider)
            for row in route_plan:
                provider = self._normalize_external_provider_name(row.get("provider", ""))
                if not provider or provider == clean_primary or provider in chain:
                    continue
                tier = str(row.get("tier", "")).strip().lower()
                if tier in {"fallback", "probe", "candidate"}:
                    chain.append(provider)
                if len(chain) >= 5:
                    break
            return chain

        base_action_args = payload.get("args") if isinstance(payload.get("args"), dict) else {}
        include_raw = _bool(payload.get("include_raw", False), default=False)
        include_success = _bool(payload.get("include_success", True), default=True)
        include_override_scenario = _bool(payload.get("include_override_scenario", False), default=False)
        max_runs = _int(payload.get("max_runs", 20), default=20, minimum=1, maximum=180)
        result_limit = _int(payload.get("result_limit", 32), default=32, minimum=1, maximum=220)
        advisor_context = payload.get("advisor_context") if isinstance(payload.get("advisor_context"), dict) else {}
        advisor_candidate_approval_map = (
            advisor_context.get("candidate_approval_map", {})
            if isinstance(advisor_context.get("candidate_approval_map"), dict)
            else {}
        )
        compare_against_simulation_id = str(payload.get("compare_against_simulation_id", "") or "").strip()
        origin_preflight = payload.get("origin_preflight") if isinstance(payload.get("origin_preflight"), dict) else {}

        providers = _provider_candidates(payload.get("providers"))
        requested_provider = self._normalize_external_provider_name(payload.get("provider", ""))
        if requested_provider and requested_provider not in providers:
            providers.insert(0, requested_provider)
        if not providers:
            providers = ["auto", "google", "graph", "smtp"]

        raw_scenarios = payload.get("scenarios")
        scenarios: list[Dict[str, Any]] = []
        if isinstance(raw_scenarios, list):
            for index, row in enumerate(raw_scenarios):
                if not isinstance(row, dict):
                    continue
                scenario_id = str(row.get("id", row.get("name", f"scenario_{index + 1}"))).strip() or f"scenario_{index + 1}"
                scenario_provider = self._normalize_external_provider_name(row.get("provider", ""))
                scenario_providers = _provider_candidates(row.get("providers"))
                if scenario_provider and scenario_provider not in scenario_providers:
                    scenario_providers.insert(0, scenario_provider)
                args_patch = row.get("args_patch") if isinstance(row.get("args_patch"), dict) else {}
                metadata_patch = row.get("metadata_patch")
                if not isinstance(metadata_patch, dict):
                    metadata_patch = row.get("metadata") if isinstance(row.get("metadata"), dict) else {}
                scenarios.append(
                    {
                        "id": scenario_id,
                        "description": str(row.get("description", "")).strip(),
                        "providers": scenario_providers,
                        "provider": scenario_provider,
                        "args_patch": dict(args_patch),
                        "metadata_patch": dict(metadata_patch),
                        "candidate_id": str(row.get("candidate_id", row.get("execution_candidate_id", ""))).strip(),
                        "execution_candidate": _bool(row.get("execution_candidate", False), default=False),
                        "advisor_source": str(row.get("advisor_source", "")).strip().lower(),
                        "label": str(row.get("label", row.get("name", ""))).strip(),
                        "external_cooldown_override": _bool(
                            row.get("external_cooldown_override", row.get("cooldown_override", False)),
                            default=False,
                        ),
                    }
                )
        if not scenarios:
            scenarios = [
                {
                    "id": "baseline",
                    "description": "Baseline connector contract preflight.",
                    "providers": [],
                    "args_patch": {},
                    "metadata_patch": {},
                    "external_cooldown_override": False,
                }
            ]
            if include_override_scenario:
                scenarios.append(
                    {
                        "id": "override_cooldown",
                        "description": "Simulate urgent manual cooldown override path.",
                        "providers": [],
                        "args_patch": {},
                        "metadata_patch": {},
                        "external_cooldown_override": True,
                    }
                )

        simulation_id = f"sim_{uuid.uuid4().hex[:12]}"
        rows: list[Dict[str, Any]] = []
        truncated = False
        run_index = 0

        for scenario in scenarios:
            scenario_id = str(scenario.get("id", "scenario")).strip() or "scenario"
            scenario_description = str(scenario.get("description", "")).strip()
            scenario_providers_raw = scenario.get("providers")
            scenario_providers = (
                [str(item) for item in scenario_providers_raw if isinstance(item, str)]
                if isinstance(scenario_providers_raw, list)
                else []
            )
            scenario_provider_name = self._normalize_external_provider_name(scenario.get("provider", ""))
            if scenario_provider_name and scenario_provider_name not in scenario_providers:
                scenario_providers.insert(0, scenario_provider_name)
            active_providers = scenario_providers if scenario_providers else providers
            args_patch = scenario.get("args_patch") if isinstance(scenario.get("args_patch"), dict) else {}
            metadata_patch = scenario.get("metadata_patch") if isinstance(scenario.get("metadata_patch"), dict) else {}
            scenario_override = bool(scenario.get("external_cooldown_override", False))
            scenario_candidate_id = str(scenario.get("candidate_id", "")).strip()
            scenario_execution_candidate = bool(scenario.get("execution_candidate", False))
            scenario_advisor_source = str(scenario.get("advisor_source", "")).strip().lower()
            scenario_label = str(scenario.get("label", "")).strip()
            scenario_approval_preview = (
                dict(advisor_candidate_approval_map.get(scenario_candidate_id, {}))
                if scenario_candidate_id and isinstance(advisor_candidate_approval_map.get(scenario_candidate_id), dict)
                else {}
            )

            for provider in active_providers:
                clean_provider = self._normalize_external_provider_name(provider) or "auto"
                run_index += 1
                if run_index > max_runs:
                    truncated = True
                    break

                run_args = {
                    "action": clean_action,
                    "provider": clean_provider,
                    "args": {**base_action_args, **args_patch},
                }
                run_meta: Dict[str, Any] = dict(runtime_meta)
                run_meta.update(metadata_patch)
                run_meta["connector_preflight_simulation"] = True
                run_meta["connector_preflight_simulation_id"] = simulation_id
                run_meta["connector_preflight_simulation_scenario"] = scenario_id
                run_meta["connector_preflight_simulation_provider"] = clean_provider
                if scenario_override:
                    run_meta["external_cooldown_override"] = True

                started = time.perf_counter()
                result = self.run_external_connector_preflight(args=run_args, source=source, metadata=run_meta)
                duration_ms = max(0.0, (time.perf_counter() - started) * 1000.0)

                status = str(result.get("status", "")).strip().lower() or "error"
                preflight_ready = bool(result.get("preflight_ready", status == "success"))
                orchestration = result.get("orchestration_diagnostics", {}) if isinstance(result.get("orchestration_diagnostics"), dict) else {}
                summary = result.get("diagnostic_summary", {}) if isinstance(result.get("diagnostic_summary"), dict) else {}
                retry_policy = result.get("retry_policy", {}) if isinstance(result.get("retry_policy"), dict) else {}
                route_plan_raw = result.get("provider_route_plan", [])
                route_plan = [dict(item) for item in route_plan_raw if isinstance(item, dict)] if isinstance(route_plan_raw, list) else []
                hints = result.get("remediation_hints", [])
                hint_rows = [dict(item) for item in hints if isinstance(item, dict)] if isinstance(hints, list) else []
                plan_rows_raw = result.get("remediation_plan", [])
                plan_rows = [dict(item) for item in plan_rows_raw if isinstance(item, dict)] if isinstance(plan_rows_raw, list) else []
                failure_classes_raw = summary.get("failure_classes", [])
                failure_classes = [str(item).strip().lower() for item in failure_classes_raw if str(item).strip()] if isinstance(failure_classes_raw, list) else []

                reliability_pressure = _float(
                    orchestration.get("reliability_pressure", summary.get("reliability_pressure", 0.0)),
                    default=0.0,
                    minimum=0.0,
                    maximum=1.0,
                )
                risk_score = _float(summary.get("risk_score", reliability_pressure), default=reliability_pressure, minimum=0.0, maximum=1.0)
                blocked_by_reliability = bool(orchestration.get("blocked_by_reliability", False))
                provider_selected = self._normalize_external_provider_name(
                    result.get("provider_selected", result.get("provider", clean_provider))
                ) or clean_provider
                provider_recommended = self._normalize_external_provider_name(
                    result.get("provider_recommended", orchestration.get("recommended_provider", ""))
                )
                route_primary = _route_primary_provider(route_plan)
                if not provider_recommended and route_primary:
                    provider_recommended = route_primary
                retry_mode = str(retry_policy.get("mode", "")).strip().lower()
                retry_delay_s = _float(
                    retry_policy.get("recommended_delay_s", retry_policy.get("base_delay_s", 0.0)),
                    default=0.0,
                    minimum=0.0,
                    maximum=86400.0,
                )
                retry_attempts = _int(retry_policy.get("max_attempts", 0), default=0, minimum=0, maximum=50)
                route_fallback_chain = _route_fallback_chain(route_plan, route_primary)
                hint_preview: list[str] = []
                first_args_patch: Dict[str, Any] = {}
                first_tool_action: Dict[str, Any] = {}
                for hint in hint_rows[:8]:
                    text = str(hint.get("message", hint.get("code", ""))).strip()
                    if text:
                        hint_preview.append(text)
                    if not first_args_patch and isinstance(hint.get("args_patch"), dict):
                        first_args_patch = dict(hint.get("args_patch", {}))
                    if not first_tool_action and isinstance(hint.get("tool_action"), dict):
                        first_tool_action = dict(hint.get("tool_action", {}))

                if not scenario_approval_preview and scenario_candidate_id:
                    execution_candidates = result.get("execution_candidates", [])
                    if isinstance(execution_candidates, list):
                        for execution_candidate in execution_candidates:
                            if not isinstance(execution_candidate, dict):
                                continue
                            if str(execution_candidate.get("candidate_id", "")).strip() != scenario_candidate_id:
                                continue
                            if isinstance(execution_candidate.get("approval_preview"), dict):
                                scenario_approval_preview = dict(execution_candidate.get("approval_preview", {}))
                            break

                decision_score = (
                    (0.38 if preflight_ready else 0.0)
                    + (0.18 if not blocked_by_reliability else 0.0)
                    + ((1.0 - risk_score) * 0.26)
                    + ((1.0 - reliability_pressure) * 0.14)
                    + (0.04 if retry_mode in {"immediate", "light_retry"} else (-0.03 if retry_mode in {"stabilize", "adaptive_backoff"} else 0.0))
                    - min(0.2, float(len(hint_rows)) * 0.03)
                )
                decision_score = max(0.0, min(decision_score, 1.0))

                row: Dict[str, Any] = {
                    "run_index": run_index,
                    "scenario_id": scenario_id,
                    "scenario_description": scenario_description,
                    "provider_requested": clean_provider,
                    "provider_selected": provider_selected,
                    "provider_recommended": provider_recommended,
                    "scenario_label": scenario_label,
                    "advisor_candidate_id": scenario_candidate_id,
                    "execution_candidate": bool(scenario_execution_candidate),
                    "advisor_source": scenario_advisor_source,
                    "status": status,
                    "preflight_ready": bool(preflight_ready),
                    "blocked_by_reliability": bool(blocked_by_reliability),
                    "risk_score": round(risk_score, 6),
                    "reliability_pressure": round(reliability_pressure, 6),
                    "decision_score": round(decision_score, 6),
                    "retry_mode": retry_mode or "none",
                    "retry_delay_s": round(retry_delay_s, 3),
                    "retry_attempts": int(retry_attempts),
                    "route_primary": route_primary,
                    "route_fallback_chain": route_fallback_chain,
                    "failure_classes": failure_classes[:8],
                    "hint_count": len(hint_rows),
                    "plan_count": len(plan_rows),
                    "hint_preview": hint_preview[:4],
                    "recommended_args_patch": first_args_patch,
                    "recommended_tool_action": first_tool_action,
                    "message": str(result.get("message", "")).strip(),
                    "duration_ms": round(duration_ms, 3),
                }
                if scenario_approval_preview:
                    row["approval_preview"] = scenario_approval_preview
                    row["approval_posture"] = str(scenario_approval_preview.get("posture", "review_required")).strip().lower()
                    row["approval_required"] = bool(scenario_approval_preview.get("requires_approval_ticket", False))
                    row["approval_ready"] = bool(scenario_approval_preview.get("ready_to_execute", False))
                if include_raw:
                    row["preflight"] = result
                rows.append(row)
            if truncated:
                break

        if not include_success:
            rows = [row for row in rows if str(row.get("status", "")).strip().lower() != "success"]

        rows.sort(
            key=lambda item: (
                0 if bool(item.get("preflight_ready", False)) else 1,
                int(bool(item.get("blocked_by_reliability", False))),
                float(item.get("risk_score", 1.0) or 1.0),
                -float(item.get("decision_score", 0.0) or 0.0),
                float(item.get("reliability_pressure", 1.0) or 1.0),
                str(item.get("provider_selected", "")),
                str(item.get("scenario_id", "")),
            )
        )

        ready_rows = [
            row
            for row in rows
            if bool(row.get("preflight_ready", False)) and not bool(row.get("blocked_by_reliability", False))
        ]
        ranked_rows = sorted(rows, key=lambda item: float(item.get("decision_score", 0.0) or 0.0), reverse=True)
        recommended_row = ready_rows[0] if ready_rows else (ranked_rows[0] if ranked_rows else {})
        recommended_provider = self._normalize_external_provider_name(
            recommended_row.get("provider_recommended", recommended_row.get("provider_selected", ""))
        )
        if not recommended_provider and providers:
            recommended_provider = self._normalize_external_provider_name(providers[0]) or "auto"
        fallback_chain: list[str] = []
        for row in ranked_rows:
            provider_name = self._normalize_external_provider_name(row.get("provider_selected", ""))
            if not provider_name or provider_name == recommended_provider or provider_name in fallback_chain:
                continue
            fallback_chain.append(provider_name)
            if len(fallback_chain) >= 5:
                break

        top_score = float(recommended_row.get("decision_score", 0.0) or 0.0)
        second_score = 0.0
        for row in ranked_rows:
            provider_name = self._normalize_external_provider_name(row.get("provider_selected", ""))
            if provider_name and provider_name != recommended_provider:
                second_score = float(row.get("decision_score", 0.0) or 0.0)
                break
        confidence = max(0.0, min((top_score * 0.72) + (max(0.0, top_score - second_score) * 0.28), 1.0))

        remediation_hints: list[Dict[str, Any]] = []
        seen_hint_ids: set[str] = set()
        for row in rows[:10]:
            for text in row.get("hint_preview", []):
                hint_text = str(text).strip()
                if not hint_text:
                    continue
                hint_id = hint_text.lower()
                if hint_id in seen_hint_ids:
                    continue
                seen_hint_ids.add(hint_id)
                remediation_hints.append(
                    {
                        "id": f"simulation_hint_{len(remediation_hints) + 1}",
                        "severity": "high" if not bool(row.get("preflight_ready", False)) else "medium",
                        "message": hint_text[:300],
                        "provider": str(row.get("provider_selected", "")),
                        "scenario_id": str(row.get("scenario_id", "")),
                    }
                )
                if len(remediation_hints) >= 10:
                    break
            if len(remediation_hints) >= 10:
                break
        if recommended_provider and requested_provider and recommended_provider != requested_provider:
            remediation_hints.insert(
                0,
                {
                    "id": "simulation_recommended_provider_switch",
                    "severity": "medium",
                    "message": (
                        f"Requested provider '{requested_provider}' is suboptimal. "
                        f"Simulation recommends '{recommended_provider}'."
                    ),
                    "provider": recommended_provider,
                    "args_patch": {"provider": recommended_provider},
                },
            )

        execution_candidate_rows = [row for row in rows if bool(row.get("execution_candidate", False))]
        approval_summary = self._external_connector_summarize_candidate_approvals(
            [
                {
                    "candidate_id": str(row.get("advisor_candidate_id", "")).strip(),
                    "approval_preview": dict(row.get("approval_preview", {}))
                    if isinstance(row.get("approval_preview"), dict)
                    else {},
                }
                for row in execution_candidate_rows
                if isinstance(row.get("approval_preview"), dict)
            ]
        )
        if approval_summary.get("candidate_count", 0) <= 0 and isinstance(advisor_context.get("approval_summary"), dict):
            approval_summary = dict(advisor_context.get("approval_summary", {}))

        created_at = self._utc_now_iso()
        response = {
            "status": "success",
            "simulation_id": simulation_id,
            "created_at": created_at,
            "action": clean_action,
            "source": source,
            "requested_provider": requested_provider or "auto",
            "providers": providers,
            "scenario_count": len(scenarios),
            "provider_count": len(providers),
            "total_runs": len(rows),
            "ready_count": sum(1 for row in rows if bool(row.get("preflight_ready", False))),
            "blocked_count": sum(1 for row in rows if bool(row.get("blocked_by_reliability", False))),
            "error_count": sum(1 for row in rows if str(row.get("status", "")).strip().lower() == "error"),
            "truncated": bool(truncated),
            "recommended_provider": recommended_provider or "auto",
            "fallback_chain": fallback_chain,
            "recommendation_confidence": round(confidence, 6),
            "recommended_args_patch": dict(recommended_row.get("recommended_args_patch", {}))
            if isinstance(recommended_row.get("recommended_args_patch"), dict)
            else {},
            "recommended_tool_action": dict(recommended_row.get("recommended_tool_action", {}))
            if isinstance(recommended_row.get("recommended_tool_action"), dict)
            else {},
            "best_run": recommended_row if isinstance(recommended_row, dict) else {},
            "remediation_hints": remediation_hints[:12],
            "results": rows[:result_limit],
            "count": min(len(rows), result_limit),
            "approval_summary": approval_summary,
            "advisor_candidate_count": len(
                {
                    str(row.get("advisor_candidate_id", "")).strip()
                    for row in rows
                    if str(row.get("advisor_candidate_id", "")).strip()
                }
            ),
            "execution_candidate_count": sum(1 for row in rows if bool(row.get("execution_candidate", False))),
        }
        history_row = {
            "simulation_id": simulation_id,
            "created_at": created_at,
            "action": clean_action,
            "source": source,
            "requested_provider": requested_provider or "auto",
            "providers": providers,
            "scenario_count": len(scenarios),
            "provider_count": len(providers),
            "total_runs": int(response.get("total_runs", 0) or 0),
            "ready_count": int(response.get("ready_count", 0) or 0),
            "blocked_count": int(response.get("blocked_count", 0) or 0),
            "error_count": int(response.get("error_count", 0) or 0),
            "truncated": bool(response.get("truncated", False)),
            "recommended_provider": str(response.get("recommended_provider", "")).strip().lower(),
            "fallback_chain": list(response.get("fallback_chain", []))
            if isinstance(response.get("fallback_chain", []), list)
            else [],
            "recommendation_confidence": float(response.get("recommendation_confidence", 0.0) or 0.0),
            "recommended_args_patch": dict(response.get("recommended_args_patch", {}))
            if isinstance(response.get("recommended_args_patch", {}), dict)
            else {},
            "recommended_tool_action": dict(response.get("recommended_tool_action", {}))
            if isinstance(response.get("recommended_tool_action", {}), dict)
            else {},
            "best_run": dict(response.get("best_run", {})) if isinstance(response.get("best_run", {}), dict) else {},
            "results": list(response.get("results", [])) if isinstance(response.get("results", []), list) else [],
            "approval_summary": dict(approval_summary),
            "advisor_context": dict(advisor_context),
            "origin_preflight": dict(origin_preflight),
            "compare_against_simulation_id": compare_against_simulation_id,
            "advisor_candidate_count": len(
                {
                    str(row.get("advisor_candidate_id", "")).strip()
                    for row in rows
                    if str(row.get("advisor_candidate_id", "")).strip()
                }
            ),
            "execution_candidate_count": sum(1 for row in rows if bool(row.get("execution_candidate", False))),
        }
        self._record_connector_simulation_history(history_row)
        response["history_recorded"] = True
        if advisor_context:
            response["advisor_context"] = dict(advisor_context)
        if origin_preflight:
            response["origin_preflight"] = dict(origin_preflight)
        compare_payload: Dict[str, Any] = {}
        if compare_against_simulation_id:
            response["compare_against_simulation_id"] = compare_against_simulation_id
            compare_payload = self.compare_external_connector_preflight_simulations(
                left_id=compare_against_simulation_id,
                right_id=simulation_id,
            )
            if isinstance(compare_payload, dict) and str(compare_payload.get("status", "")).strip().lower() == "success":
                response["comparison"] = compare_payload.get("comparison", {})
                response["compare_left"] = compare_payload.get("left", {})
                response["compare_right"] = compare_payload.get("right", {})

        promotion_preview = self._external_connector_build_simulation_promotion_preview(
            simulation=response,
            comparison=compare_payload if compare_payload else None,
            require_compare=bool(approval_summary.get("compare_required_count", 0)),
        )
        response["promotion_preview"] = promotion_preview
        self._update_connector_simulation_history_row(
            simulation_id,
            {
                "approval_summary": dict(approval_summary),
                "promotion_preview": dict(promotion_preview),
            },
        )

        autotune_enabled = _bool(payload.get("policy_autotune", True), default=True)
        if autotune_enabled and self._connector_remediation_policy_external_action_managed(clean_action):
            mission_mode_name = self._connector_remediation_policy_runtime_mission_mode(runtime_meta)
            autotune_provider = recommended_provider or requested_provider or "auto"
            response["policy_autotune"] = self.external_connector_remediation_policy_autotune(
                action=clean_action,
                provider=autotune_provider,
                mission_mode=mission_mode_name,
                source=f"{source}:simulation",
                reason="simulation_matrix",
                force=_bool(payload.get("policy_autotune_force", False), default=False),
                dry_run=_bool(payload.get("policy_autotune_dry_run", True), default=True),
                limit=_int(payload.get("policy_autotune_limit", 320), default=320, minimum=20, maximum=5000),
                recent_window=_int(
                    payload.get("policy_autotune_recent_window", 16),
                    default=16,
                    minimum=4,
                    maximum=400,
                ),
                baseline_window=_int(
                    payload.get("policy_autotune_baseline_window", 72),
                    default=72,
                    minimum=8,
                    maximum=1200,
                ),
                status=str(payload.get("policy_autotune_status", "") or "").strip(),
            )

        promotion_enabled = _bool(payload.get("policy_promotion", False), default=False)
        if promotion_enabled and self._connector_remediation_policy_external_action_managed(clean_action):
            response["policy_promotion"] = self.external_connector_preflight_simulation_promote(
                simulation_id=simulation_id,
                compare_against_simulation_id=compare_against_simulation_id,
                source=str(payload.get("policy_promotion_source", f"{source}:simulation")).strip() or f"{source}:simulation",
                reason=str(payload.get("policy_promotion_reason", "simulation_matrix_auto") or "simulation_matrix_auto").strip(),
                dry_run=_bool(payload.get("policy_promotion_dry_run", True), default=True),
                force=_bool(payload.get("policy_promotion_force", False), default=False),
                require_compare=_bool(
                    payload.get("policy_promotion_require_compare", bool(approval_summary.get("compare_required_count", 0))),
                    default=bool(approval_summary.get("compare_required_count", 0)),
                ),
                require_improvement=_bool(payload.get("policy_promotion_require_improvement", True), default=True),
                mission_mode=self._connector_remediation_policy_runtime_mission_mode(runtime_meta),
                limit=_int(payload.get("policy_promotion_limit", 320), default=320, minimum=20, maximum=5000),
                recent_window=_int(
                    payload.get("policy_promotion_recent_window", payload.get("policy_autotune_recent_window", 16)),
                    default=16,
                    minimum=4,
                    maximum=400,
                ),
                baseline_window=_int(
                    payload.get("policy_promotion_baseline_window", payload.get("policy_autotune_baseline_window", 72)),
                    default=72,
                    minimum=8,
                    maximum=1200,
                ),
                status=str(payload.get("policy_promotion_status", payload.get("policy_autotune_status", "")) or "").strip(),
            )

        try:
            self.kernel.telemetry.emit(
                "external.connector_preflight_simulated",
                {
                    "simulation_id": simulation_id,
                    "action": clean_action,
                    "total_runs": int(response.get("total_runs", 0) or 0),
                    "ready_count": int(response.get("ready_count", 0) or 0),
                    "blocked_count": int(response.get("blocked_count", 0) or 0),
                    "recommended_provider": str(response.get("recommended_provider", "")),
                    "confidence": float(response.get("recommendation_confidence", 0.0) or 0.0),
                },
            )
        except Exception:
            pass
        return response

    def external_connector_preflight_simulation_templates(
        self,
        *,
        action: str,
        provider: str = "auto",
    ) -> Dict[str, Any]:
        clean_action = str(action or "").strip().lower()
        if not clean_action:
            return {"status": "error", "message": "action is required"}
        clean_provider = self._normalize_external_provider_name(provider) or "auto"

        default_args: Dict[str, Dict[str, Any]] = {
            "external_email_send": {
                "to": ["alice@example.com"],
                "subject": "JARVIS update",
                "body": "Automated update from JARVIS.",
            },
            "external_calendar_create_event": {
                "title": "JARVIS work session",
                "start_at": "2026-03-06T09:00:00Z",
                "end_at": "2026-03-06T09:30:00Z",
            },
            "external_calendar_update_event": {
                "event_id": "evt-123",
                "title": "JARVIS updated event",
            },
            "external_task_create": {
                "title": "JARVIS follow-up task",
                "notes": "Created by automation pipeline.",
            },
            "external_task_update": {
                "task_id": "task-123",
                "status": "completed",
            },
            "external_document_create": {
                "title": "JARVIS notes",
                "content": "Automation summary.",
            },
            "external_document_append": {
                "document_id": "doc-123",
                "content": "Appended by JARVIS.",
            },
        }
        missing_contract_patch: Dict[str, Dict[str, Any]] = {
            "external_email_send": {"to": [], "subject": ""},
            "external_calendar_create_event": {"title": "", "start_at": "", "end_at": ""},
            "external_calendar_update_event": {"event_id": ""},
            "external_task_create": {"title": ""},
            "external_task_update": {"task_id": ""},
            "external_document_create": {"title": ""},
            "external_document_append": {"document_id": ""},
        }
        baseline_args = dict(default_args.get(clean_action, {}))
        degradation_patch = dict(missing_contract_patch.get(clean_action, {}))
        if not degradation_patch:
            degradation_patch = {"title": "", "subject": ""}

        orchestration = self._external_connector_preflight_orchestration(
            action=clean_action,
            provider=clean_provider,
        )
        route_plan_raw = orchestration.get("provider_route_plan", [])
        route_plan = [dict(item) for item in route_plan_raw if isinstance(item, dict)] if isinstance(route_plan_raw, list) else []
        provider_candidates: list[str] = []
        for row in route_plan:
            name = self._normalize_external_provider_name(row.get("provider", ""))
            if name and name not in provider_candidates:
                provider_candidates.append(name)
        if clean_provider not in {"", "auto"} and clean_provider not in provider_candidates:
            provider_candidates.insert(0, clean_provider)
        if not provider_candidates:
            provider_candidates = ["auto", "google", "graph", "smtp"]

        reliability_pressure = max(
            0.0,
            min(float(orchestration.get("reliability_pressure", 0.0) or 0.0), 1.0),
        )
        blocked = bool(orchestration.get("blocked_by_reliability", False))
        execution_handoff = self._external_connector_build_execution_handoff(
            action=clean_action,
            base_args=baseline_args,
            requested_provider=clean_provider,
            recommended_provider=str(orchestration.get("recommended_provider", clean_provider)).strip().lower() or clean_provider,
            route_weight_advisor=orchestration.get("route_weight_advisor", {})
            if isinstance(orchestration.get("route_weight_advisor"), dict)
            else {},
            cooldown_outage_explainer=orchestration.get("cooldown_outage_explainer", {})
            if isinstance(orchestration.get("cooldown_outage_explainer"), dict)
            else {},
            retry_policy=orchestration.get("retry_policy", {}) if isinstance(orchestration.get("retry_policy"), dict) else {},
            mission_policy_decision=orchestration.get("mission_policy_decision", {})
            if isinstance(orchestration.get("mission_policy_decision"), dict)
            else {},
        )

        templates = [
            {
                "template_id": "baseline_matrix",
                "name": "Baseline Provider Matrix",
                "description": "Run baseline preflight across all provider candidates and rank reliability.",
                "provider_candidates": provider_candidates,
                "payload": {
                    "action": clean_action,
                    "provider": clean_provider,
                    "providers": provider_candidates,
                    "args": baseline_args,
                    "max_runs": max(8, min(30, len(provider_candidates) * 4)),
                    "result_limit": 80,
                    "include_override_scenario": False,
                    "include_success": True,
                    "scenarios": [{"id": "baseline", "description": "Baseline contract and routing diagnostics."}],
                },
            },
            {
                "template_id": "contract_gap_drill",
                "name": "Contract Gap Drill",
                "description": "Inject missing-required-field scenarios to verify remediation quality.",
                "provider_candidates": provider_candidates,
                "payload": {
                    "action": clean_action,
                    "provider": clean_provider,
                    "providers": provider_candidates,
                    "args": baseline_args,
                    "max_runs": max(10, min(40, len(provider_candidates) * 5)),
                    "result_limit": 120,
                    "include_success": True,
                    "scenarios": [
                        {"id": "baseline", "description": "Baseline contract validation."},
                        {
                            "id": "missing_required_contract",
                            "description": "Missing required field injection for remediation synthesis.",
                            "args_patch": degradation_patch,
                        },
                    ],
                },
            },
            {
                "template_id": "reliability_stress",
                "name": "Reliability Stress + Override",
                "description": "Stress reliability policy and compare strict versus manual override routing.",
                "provider_candidates": provider_candidates,
                "payload": {
                    "action": clean_action,
                    "provider": clean_provider,
                    "providers": provider_candidates,
                    "args": baseline_args,
                    "max_runs": max(12, min(60, len(provider_candidates) * 6)),
                    "result_limit": 150,
                    "include_success": True,
                    "include_override_scenario": False,
                    "scenarios": [
                        {"id": "strict", "description": "Strict reliability policy execution."},
                        {
                            "id": "override_cooldown",
                            "description": "Manual urgency override path.",
                            "external_cooldown_override": True,
                        },
                    ],
                },
            },
            {
                "template_id": "privacy_hardening",
                "name": "Privacy/Offline Hardening",
                "description": "Evaluate connector behavior under stricter privacy/offline policy metadata.",
                "provider_candidates": provider_candidates,
                "payload": {
                    "action": clean_action,
                    "provider": clean_provider,
                    "providers": provider_candidates,
                    "args": baseline_args,
                    "max_runs": max(8, min(24, len(provider_candidates) * 4)),
                    "result_limit": 80,
                    "include_success": True,
                    "scenarios": [
                        {"id": "baseline", "description": "Normal policy profile."},
                        {
                            "id": "privacy_mode_strict",
                            "description": "Strict privacy + offline-required policy.",
                            "metadata_patch": {
                                "privacy_mode": True,
                                "requires_offline": True,
                                "policy_profile": "privacy",
                                "risk_level": "high",
                            },
                        },
                    ],
                },
            },
        ]
        simulation_template = execution_handoff.get("simulation_template", {})
        if isinstance(simulation_template, dict) and isinstance(simulation_template.get("payload"), dict):
            template_row = dict(simulation_template)
            template_row["provider_candidates"] = provider_candidates
            templates.append(template_row)

        recommended_template_id = "baseline_matrix"
        if isinstance(simulation_template, dict) and isinstance(simulation_template.get("payload"), dict):
            recommended_template_id = str(simulation_template.get("template_id", "advisor_execution_handoff")).strip() or "advisor_execution_handoff"
        elif blocked or reliability_pressure >= 0.72:
            recommended_template_id = "reliability_stress"
        elif reliability_pressure >= 0.46:
            recommended_template_id = "contract_gap_drill"

        return {
            "status": "success",
            "action": clean_action,
            "provider": clean_provider,
            "recommended_template_id": recommended_template_id,
            "provider_candidates": provider_candidates,
            "reliability_pressure": round(reliability_pressure, 6),
            "blocked_by_reliability": bool(blocked),
            "orchestration": {
                "provider_requested": str(orchestration.get("provider_requested", "")).strip().lower(),
                "recommended_provider": str(orchestration.get("recommended_provider", "")).strip().lower(),
                "runtime_lane": str(orchestration.get("runtime_lane", "")).strip().lower(),
            },
            "execution_handoff": execution_handoff,
            "templates": templates,
            "count": len(templates),
        }

    def external_connector_preflight_simulation_history(
        self,
        *,
        limit: int = 60,
        action: str = "",
        provider: str = "",
        status: str = "",
        include_results: bool = False,
    ) -> Dict[str, Any]:
        self._load_connector_simulation_history()
        bounded = max(1, min(int(limit), 5000))
        action_filter = str(action or "").strip().lower()
        provider_filter = self._normalize_external_provider_name(provider)
        status_filter = str(status or "").strip().lower()

        with self._connector_simulation_history_lock:
            rows = list(self._connector_simulation_history)

        rows.sort(key=lambda row: str(row.get("created_at", "")), reverse=True)
        filtered: list[Dict[str, Any]] = []
        for row in rows:
            if not isinstance(row, dict):
                continue
            row_action = str(row.get("action", "")).strip().lower()
            if action_filter and row_action != action_filter:
                continue
            if provider_filter:
                row_provider = self._normalize_external_provider_name(
                    row.get("recommended_provider", row.get("requested_provider", ""))
                )
                if row_provider != provider_filter:
                    continue
            if status_filter:
                status_value = "success"
                if int(row.get("error_count", 0) or 0) > 0:
                    status_value = "error"
                elif int(row.get("blocked_count", 0) or 0) > 0:
                    status_value = "blocked"
                elif int(row.get("ready_count", 0) or 0) <= 0:
                    status_value = "warning"
                if status_value != status_filter:
                    continue
            item = dict(row)
            if not include_results:
                item.pop("results", None)
            filtered.append(_to_jsonable(item))
            if len(filtered) >= bounded:
                break

        return {
            "status": "success",
            "items": filtered,
            "count": len(filtered),
            "total": len(rows),
            "limit": bounded,
            "filters": {
                "action": action_filter,
                "provider": provider_filter,
                "status": status_filter,
                "include_results": bool(include_results),
            },
        }

    def _external_connector_build_simulation_promotion_preview(
        self,
        *,
        simulation: Dict[str, Any],
        comparison: Optional[Dict[str, Any]] = None,
        trends: Optional[Dict[str, Any]] = None,
        require_compare: bool = True,
    ) -> Dict[str, Any]:
        simulation_id = str(simulation.get("simulation_id", "")).strip()
        total_runs = max(1, int(simulation.get("total_runs", 0) or 0))
        ready_count = int(simulation.get("ready_count", 0) or 0)
        error_count = int(simulation.get("error_count", 0) or 0)
        blocked_count = int(simulation.get("blocked_count", 0) or 0)
        ready_ratio = max(0.0, min(float(ready_count) / float(total_runs), 1.0))
        error_ratio = max(0.0, min(float(error_count) / float(total_runs), 1.0))
        blocked_ratio = max(0.0, min(float(blocked_count) / float(total_runs), 1.0))
        confidence = max(0.0, min(float(simulation.get("recommendation_confidence", 0.0) or 0.0), 1.0))
        best_run = simulation.get("best_run", {}) if isinstance(simulation.get("best_run"), dict) else {}
        try:
            best_risk = max(0.0, min(float(best_run.get("risk_score", 1.0) or 1.0), 1.0))
        except Exception:
            best_risk = 1.0
        approval_summary = (
            dict(simulation.get("approval_summary", {}))
            if isinstance(simulation.get("approval_summary"), dict)
            else {}
        )
        execution_candidate_count = int(
            simulation.get("execution_candidate_count", approval_summary.get("candidate_count", 0)) or 0
        )
        approval_ready_ratio = max(
            0.0,
            min(
                float(
                    approval_summary.get(
                        "ready_execute_ratio",
                        1.0 if execution_candidate_count <= 0 else 0.0,
                    )
                    or 0.0
                ),
                1.0,
            ),
        )
        approval_required_ratio = max(
            0.0,
            min(float(approval_summary.get("approval_required_ratio", 0.0) or 0.0), 1.0),
        )
        compare_required_ratio = max(
            0.0,
            min(float(approval_summary.get("compare_required_ratio", 0.0) or 0.0), 1.0),
        )
        posture = str(approval_summary.get("posture", "ready")).strip().lower() or "ready"

        trend_recent = trends.get("recent", {}) if isinstance(trends, dict) and isinstance(trends.get("recent"), dict) else {}
        trend_stability = trends.get("stability", {}) if isinstance(trends, dict) and isinstance(trends.get("stability"), dict) else {}
        trend_profile = (
            self._connector_remediation_policy_normalize_profile(str(trends.get("recommended_profile", "")))
            if isinstance(trends, dict)
            else "balanced"
        )
        if not trend_profile:
            trend_profile = "balanced"
        trend_controls = (
            trends.get("recommended_controls", {})
            if isinstance(trends, dict) and isinstance(trends.get("recommended_controls"), dict)
            else {}
        )
        stability_score = max(0.0, min(float(trend_stability.get("score", 0.0) or 0.0), 1.0))
        recent_composite = max(0.0, min(float(trend_recent.get("composite_score", 0.0) or 0.0), 1.0))

        compare_payload = comparison if isinstance(comparison, dict) else {}
        compare_summary = compare_payload.get("comparison", compare_payload)
        compare_left = compare_payload.get("left", {}) if isinstance(compare_payload.get("left"), dict) else {}
        compare_right = compare_payload.get("right", {}) if isinstance(compare_payload.get("right"), dict) else {}
        compare_status = "not_required"
        compare_winner = "tie"
        compare_score_gap = 0.0
        compare_improved = not require_compare
        compare_target = ""
        if require_compare:
            compare_status = "missing"
        if isinstance(compare_summary, dict) and str(compare_payload.get("status", "success")).strip().lower() == "success":
            compare_status = "available"
            compare_winner = str(compare_summary.get("winner", "tie")).strip().lower() or "tie"
            compare_score_gap = max(0.0, min(float(compare_summary.get("score_gap", 0.0) or 0.0), 1.0))
            left_id = str(compare_left.get("simulation_id", "")).strip()
            right_id = str(compare_right.get("simulation_id", "")).strip()
            compare_target = left_id if right_id == simulation_id else right_id
            if right_id == simulation_id:
                compare_improved = compare_winner == "right" or (compare_winner == "tie" and compare_score_gap <= 0.03)
            elif left_id == simulation_id:
                compare_improved = compare_winner == "left" or (compare_winner == "tie" and compare_score_gap <= 0.03)
            else:
                compare_improved = compare_winner == "tie"

        gate_reasons: list[str] = []
        if execution_candidate_count <= 0:
            gate_reasons.append("no_execution_candidates")
        if posture == "blocked_contract" or approval_ready_ratio <= 0.0:
            gate_reasons.append("approval_not_ready")
        if require_compare and compare_status == "missing":
            gate_reasons.append("compare_missing")
        elif require_compare and not compare_improved:
            gate_reasons.append("compare_not_improved")
        if ready_ratio < 0.42:
            gate_reasons.append("low_readiness")
        if confidence < 0.44:
            gate_reasons.append("low_confidence")
        if error_ratio > 0.3:
            gate_reasons.append("elevated_error_ratio")
        if stability_score and stability_score < 0.46:
            gate_reasons.append("unstable_trend")

        recommended_profile = trend_profile
        if not isinstance(trend_controls, dict) or not trend_controls:
            if best_risk >= 0.72 or approval_required_ratio >= 0.34 or error_ratio >= 0.24:
                recommended_profile = "strict"
            elif ready_ratio >= 0.82 and confidence >= 0.76 and approval_required_ratio <= 0.1:
                recommended_profile = "aggressive"
            else:
                recommended_profile = "balanced"
        recommended_controls = self._connector_remediation_policy_sanitize_controls(
            profile=recommended_profile,
            controls=trend_controls if isinstance(trend_controls, dict) else {},
        )
        if compare_required_ratio > 0.0 or require_compare:
            recommended_controls["require_compare"] = True
        if approval_required_ratio >= 0.25 or best_risk >= 0.7:
            recommended_controls["allow_high_risk"] = False
            recommended_controls["stop_on_blocked"] = True
            recommended_controls["max_steps"] = min(int(recommended_controls.get("max_steps", 8) or 8), 6)
        elif approval_ready_ratio >= 0.9 and ready_ratio >= 0.8 and error_ratio <= 0.08:
            recommended_controls["max_steps"] = max(int(recommended_controls.get("max_steps", 8) or 8), 10)

        promotion_score = (
            (ready_ratio * 0.26)
            + (confidence * 0.2)
            + ((1.0 - error_ratio) * 0.16)
            + ((1.0 - blocked_ratio) * 0.08)
            + ((1.0 - best_risk) * 0.1)
            + (approval_ready_ratio * 0.08)
            + (stability_score * 0.06)
            + (recent_composite * 0.04)
            + (0.06 if compare_improved else 0.0)
        )
        if require_compare and compare_status == "missing":
            promotion_score -= 0.1
        elif require_compare and not compare_improved:
            promotion_score -= 0.06
        promotion_score = max(0.0, min(promotion_score, 1.0))
        eligible = bool(
            execution_candidate_count > 0
            and ready_ratio >= 0.34
            and confidence >= 0.38
            and error_ratio <= 0.48
            and approval_summary.get("ready_stage_count", execution_candidate_count) not in {0, None}
        )
        recommended_apply = bool(eligible and len(gate_reasons) == 0 and promotion_score >= 0.56)

        summary = "Simulation is not yet ready for policy promotion."
        if recommended_apply:
            summary = "Simulation is promotion-ready and can be persisted as the active remediation policy."
        elif "compare_missing" in gate_reasons or "compare_not_improved" in gate_reasons:
            summary = "Promotion is gated on compare evidence proving the new simulation path beats the baseline."
        elif "approval_not_ready" in gate_reasons:
            summary = "Promotion is blocked until the execution candidate is stageable and approval-ready."
        elif "low_readiness" in gate_reasons or "low_confidence" in gate_reasons:
            summary = "Promotion is deferred until readiness/confidence improve."

        return {
            "status": "success",
            "simulation_id": simulation_id,
            "compare_against_simulation_id": compare_target,
            "eligible": eligible,
            "recommended_apply": recommended_apply,
            "require_compare": bool(require_compare),
            "compare_status": compare_status,
            "compare_winner": compare_winner,
            "compare_score_gap": round(compare_score_gap, 6),
            "compare_improved": bool(compare_improved),
            "recommended_profile": recommended_profile,
            "recommended_controls": recommended_controls,
            "approval_ready_ratio": round(approval_ready_ratio, 6),
            "approval_required_ratio": round(approval_required_ratio, 6),
            "compare_required_ratio": round(compare_required_ratio, 6),
            "execution_candidate_count": execution_candidate_count,
            "ready_ratio": round(ready_ratio, 6),
            "error_ratio": round(error_ratio, 6),
            "confidence": round(confidence, 6),
            "best_risk": round(best_risk, 6),
            "stability_score": round(stability_score, 6),
            "promotion_score": round(promotion_score, 6),
            "gate_reasons": gate_reasons[:8],
            "summary": summary,
        }

    def compare_external_connector_preflight_simulations(
        self,
        *,
        left_id: str,
        right_id: str,
    ) -> Dict[str, Any]:
        left_key = str(left_id or "").strip()
        right_key = str(right_id or "").strip()
        if not left_key or not right_key:
            return {"status": "error", "message": "left_id and right_id are required"}

        self._load_connector_simulation_history()
        with self._connector_simulation_history_lock:
            rows = list(self._connector_simulation_history)

        index: Dict[str, Dict[str, Any]] = {}
        for row in rows:
            if not isinstance(row, dict):
                continue
            sim_id = str(row.get("simulation_id", "")).strip()
            if sim_id:
                index[sim_id] = row
        left = index.get(left_key)
        right = index.get(right_key)
        if not isinstance(left, dict):
            return {"status": "error", "message": f"left simulation '{left_key}' was not found"}
        if not isinstance(right, dict):
            return {"status": "error", "message": f"right simulation '{right_key}' was not found"}

        def _safe_int(row: Dict[str, Any], key: str) -> int:
            try:
                return int(row.get(key, 0) or 0)
            except Exception:
                return 0

        def _safe_float(row: Dict[str, Any], key: str) -> float:
            try:
                return float(row.get(key, 0.0) or 0.0)
            except Exception:
                return 0.0

        def _snapshot(row: Dict[str, Any]) -> Dict[str, Any]:
            total = max(1, _safe_int(row, "total_runs"))
            ready = _safe_int(row, "ready_count")
            blocked = _safe_int(row, "blocked_count")
            errors = _safe_int(row, "error_count")
            confidence = max(0.0, min(_safe_float(row, "recommendation_confidence"), 1.0))
            best_run = row.get("best_run", {})
            best_risk = 1.0
            if isinstance(best_run, dict):
                try:
                    best_risk = max(0.0, min(float(best_run.get("risk_score", 1.0) or 1.0), 1.0))
                except Exception:
                    best_risk = 1.0
            ready_ratio = max(0.0, min(float(ready) / float(total), 1.0))
            blocked_ratio = max(0.0, min(float(blocked) / float(total), 1.0))
            error_ratio = max(0.0, min(float(errors) / float(total), 1.0))
            score = max(
                0.0,
                min(
                    1.0,
                    (confidence * 0.36)
                    + (ready_ratio * 0.34)
                    + ((1.0 - blocked_ratio) * 0.14)
                    + ((1.0 - error_ratio) * 0.08)
                    + ((1.0 - best_risk) * 0.08),
                ),
            )
            return {
                "simulation_id": str(row.get("simulation_id", "")).strip(),
                "created_at": str(row.get("created_at", "")).strip(),
                "action": str(row.get("action", "")).strip().lower(),
                "recommended_provider": str(row.get("recommended_provider", "")).strip().lower(),
                "total_runs": total,
                "ready_count": ready,
                "blocked_count": blocked,
                "error_count": errors,
                "ready_ratio": round(ready_ratio, 6),
                "blocked_ratio": round(blocked_ratio, 6),
                "error_ratio": round(error_ratio, 6),
                "recommendation_confidence": round(confidence, 6),
                "best_risk": round(best_risk, 6),
                "composite_score": round(score, 6),
                "advisor_candidate_count": _safe_int(row, "advisor_candidate_count"),
                "execution_candidate_count": _safe_int(row, "execution_candidate_count"),
                "advisor_context": dict(row.get("advisor_context", {})) if isinstance(row.get("advisor_context"), dict) else {},
            }

        left_view = _snapshot(left)
        right_view = _snapshot(right)
        left_score = float(left_view.get("composite_score", 0.0) or 0.0)
        right_score = float(right_view.get("composite_score", 0.0) or 0.0)
        winner = "tie"
        if abs(left_score - right_score) > 0.01:
            winner = "left" if left_score > right_score else "right"
        provider_change = (
            str(left_view.get("recommended_provider", "")).strip().lower()
            != str(right_view.get("recommended_provider", "")).strip().lower()
        )
        advisor_candidate_delta = int(right_view.get("advisor_candidate_count", 0) or 0) - int(
            left_view.get("advisor_candidate_count", 0) or 0
        )
        execution_candidate_delta = int(right_view.get("execution_candidate_count", 0) or 0) - int(
            left_view.get("execution_candidate_count", 0) or 0
        )
        return {
            "status": "success",
            "left": left_view,
            "right": right_view,
            "comparison": {
                "winner": winner,
                "score_gap": round(abs(left_score - right_score), 6),
                "provider_changed": bool(provider_change),
                "left_provider": str(left_view.get("recommended_provider", "")).strip().lower(),
                "right_provider": str(right_view.get("recommended_provider", "")).strip().lower(),
                "left_newer": str(left_view.get("created_at", "")) > str(right_view.get("created_at", "")),
                "advisor_candidate_delta": advisor_candidate_delta,
                "execution_candidate_delta": execution_candidate_delta,
                "advisor_replay": bool(
                    bool(left_view.get("advisor_candidate_count", 0)) or bool(right_view.get("advisor_candidate_count", 0))
                ),
                "summary": (
                    "No material difference between the selected simulation runs."
                    if winner == "tie"
                    else (
                        f"{winner.capitalize()} run has stronger readiness/reliability tradeoff "
                        "based on composite simulation score."
                    )
                ),
            },
        }

    def external_connector_preflight_simulation_trends(
        self,
        *,
        limit: int = 260,
        action: str = "",
        provider: str = "",
        status: str = "",
        recent_window: int = 16,
        baseline_window: int = 72,
    ) -> Dict[str, Any]:
        self._load_connector_simulation_history()
        bounded_limit = max(20, min(int(limit), 5000))
        bounded_recent = max(4, min(int(recent_window), 400))
        bounded_baseline = max(bounded_recent + 4, min(int(baseline_window), 1200))
        action_filter = str(action or "").strip().lower()
        provider_filter = self._normalize_external_provider_name(provider)
        status_filter = str(status or "").strip().lower()

        with self._connector_simulation_history_lock:
            rows = list(self._connector_simulation_history)

        rows.sort(key=lambda row: str(row.get("created_at", "")), reverse=True)

        def _safe_int(row: Dict[str, Any], key: str) -> int:
            try:
                return int(row.get(key, 0) or 0)
            except Exception:
                return 0

        def _safe_float(row: Dict[str, Any], key: str) -> float:
            try:
                return float(row.get(key, 0.0) or 0.0)
            except Exception:
                return 0.0

        def _status_value(row: Dict[str, Any]) -> str:
            if _safe_int(row, "error_count") > 0:
                return "error"
            if _safe_int(row, "blocked_count") > 0:
                return "blocked"
            if _safe_int(row, "ready_count") <= 0:
                return "warning"
            return "success"

        snapshots: list[Dict[str, Any]] = []
        for row in rows:
            if not isinstance(row, dict):
                continue
            row_action = str(row.get("action", "")).strip().lower()
            if action_filter and row_action != action_filter:
                continue
            if provider_filter:
                row_provider = self._normalize_external_provider_name(
                    row.get("recommended_provider", row.get("requested_provider", ""))
                )
                if row_provider != provider_filter:
                    continue
            row_status = _status_value(row)
            if status_filter and row_status != status_filter:
                continue

            total = max(1, _safe_int(row, "total_runs"))
            ready = _safe_int(row, "ready_count")
            blocked = _safe_int(row, "blocked_count")
            errors = _safe_int(row, "error_count")
            ready_ratio = max(0.0, min(float(ready) / float(total), 1.0))
            blocked_ratio = max(0.0, min(float(blocked) / float(total), 1.0))
            error_ratio = max(0.0, min(float(errors) / float(total), 1.0))
            confidence = max(0.0, min(_safe_float(row, "recommendation_confidence"), 1.0))
            best_run = row.get("best_run", {})
            best_risk = 1.0
            if isinstance(best_run, dict):
                try:
                    best_risk = max(0.0, min(float(best_run.get("risk_score", 1.0) or 1.0), 1.0))
                except Exception:
                    best_risk = 1.0
            composite = max(
                0.0,
                min(
                    1.0,
                    (confidence * 0.36)
                    + (ready_ratio * 0.34)
                    + ((1.0 - blocked_ratio) * 0.14)
                    + ((1.0 - error_ratio) * 0.08)
                    + ((1.0 - best_risk) * 0.08),
                ),
            )
            snapshots.append(
                {
                    "simulation_id": str(row.get("simulation_id", "")).strip(),
                    "created_at": str(row.get("created_at", "")).strip(),
                    "action": row_action,
                    "status": row_status,
                    "recommended_provider": self._normalize_external_provider_name(
                        row.get("recommended_provider", row.get("requested_provider", ""))
                    )
                    or "auto",
                    "total_runs": total,
                    "ready_ratio": round(ready_ratio, 6),
                    "blocked_ratio": round(blocked_ratio, 6),
                    "error_ratio": round(error_ratio, 6),
                    "confidence": round(confidence, 6),
                    "best_risk": round(best_risk, 6),
                    "composite_score": round(composite, 6),
                    "advisor_candidate_count": _safe_int(row, "advisor_candidate_count"),
                    "execution_candidate_count": _safe_int(row, "execution_candidate_count"),
                    "advisor_context": dict(row.get("advisor_context", {}))
                    if isinstance(row.get("advisor_context"), dict)
                    else {},
                    "approval_summary": dict(row.get("approval_summary", {}))
                    if isinstance(row.get("approval_summary"), dict)
                    else {},
                    "promotion_preview": dict(row.get("promotion_preview", {}))
                    if isinstance(row.get("promotion_preview"), dict)
                    else {},
                }
            )
            if len(snapshots) >= bounded_limit:
                break

        snapshots.sort(key=lambda item: str(item.get("created_at", "")))
        count = len(snapshots)
        recent = snapshots[-bounded_recent:] if snapshots else []
        baseline = snapshots[-(bounded_recent + bounded_baseline) : -bounded_recent] if len(snapshots) > bounded_recent else []

        def _avg(rows_in: list[Dict[str, Any]], key: str) -> float:
            if not rows_in:
                return 0.0
            total = 0.0
            for item in rows_in:
                try:
                    total += float(item.get(key, 0.0) or 0.0)
                except Exception:
                    continue
            return total / max(len(rows_in), 1)

        recent_ready = _avg(recent, "ready_ratio")
        recent_error = _avg(recent, "error_ratio")
        recent_confidence = _avg(recent, "confidence")
        recent_composite = _avg(recent, "composite_score")
        baseline_ready = _avg(baseline, "ready_ratio") if baseline else recent_ready
        baseline_error = _avg(baseline, "error_ratio") if baseline else recent_error
        baseline_confidence = _avg(baseline, "confidence") if baseline else recent_confidence
        baseline_composite = _avg(baseline, "composite_score") if baseline else recent_composite

        delta_ready = recent_ready - baseline_ready
        delta_error = recent_error - baseline_error
        delta_confidence = recent_confidence - baseline_confidence
        delta_composite = recent_composite - baseline_composite

        provider_mix: Dict[str, int] = {}
        providers_in_recent: list[str] = []
        for item in recent:
            provider_name = str(item.get("recommended_provider", "")).strip().lower() or "auto"
            providers_in_recent.append(provider_name)
            provider_mix[provider_name] = provider_mix.get(provider_name, 0) + 1

        switch_count = 0
        for index in range(1, len(providers_in_recent)):
            if providers_in_recent[index] != providers_in_recent[index - 1]:
                switch_count += 1
        switch_rate = float(switch_count) / float(max(1, len(providers_in_recent) - 1))

        confidence_volatility = 0.0
        if recent:
            center = recent_confidence
            for item in recent:
                try:
                    confidence_volatility += abs(float(item.get("confidence", 0.0) or 0.0) - center)
                except Exception:
                    continue
            confidence_volatility = confidence_volatility / max(len(recent), 1)
        confidence_volatility = max(0.0, min(confidence_volatility, 1.0))

        drift_pressure = (
            (max(0.0, -delta_ready) * 0.28)
            + (max(0.0, delta_error) * 0.34)
            + (max(0.0, -delta_confidence) * 0.24)
            + (switch_rate * 0.14)
        )
        instability_pressure = (
            (recent_error * 0.46)
            + (confidence_volatility * 0.2)
            + (switch_rate * 0.18)
            + (max(0.0, 1.0 - recent_composite) * 0.16)
        )
        stability_score = max(0.0, min(1.0, 1.0 - instability_pressure))

        recommended_profile = "balanced"
        if (
            recent_error >= 0.34
            or delta_error >= 0.14
            or stability_score <= 0.44
            or drift_pressure >= 0.46
        ):
            recommended_profile = "strict"
        elif (
            recent_ready >= 0.78
            and recent_confidence >= 0.76
            and recent_error <= 0.12
            and stability_score >= 0.72
            and delta_confidence >= -0.02
        ):
            recommended_profile = "aggressive"

        profile_controls = {
            "strict": {
                "allow_high_risk": False,
                "max_steps": 4,
                "require_compare": True,
                "stop_on_blocked": True,
            },
            "balanced": {
                "allow_high_risk": False,
                "max_steps": 8,
                "require_compare": False,
                "stop_on_blocked": True,
            },
            "aggressive": {
                "allow_high_risk": True,
                "max_steps": 12,
                "require_compare": False,
                "stop_on_blocked": False,
            },
        }

        provider_rows = sorted(
            [
                {
                    "provider": name,
                    "count": value,
                    "share": round(float(value) / float(max(1, len(recent))), 6),
                }
                for name, value in provider_mix.items()
            ],
            key=lambda item: (-int(item.get("count", 0)), str(item.get("provider", ""))),
        )
        recent_replay_ratio = 0.0
        baseline_replay_ratio = 0.0
        recent_candidate_density = 0.0
        baseline_candidate_density = 0.0
        recent_execution_density = 0.0
        baseline_execution_density = 0.0
        recent_compare_required = 0.0
        baseline_compare_required = 0.0
        recent_approval_required = 0.0
        baseline_approval_required = 0.0
        recent_ready_execute = 0.0
        baseline_ready_execute = 0.0
        recent_manual_review = 0.0
        baseline_manual_review = 0.0
        recent_promotion_score = 0.0
        baseline_promotion_score = 0.0
        recent_promotion_ready = 0.0
        baseline_promotion_ready = 0.0
        recent_source_mix: Dict[str, int] = {}
        recent_rows = recent if isinstance(recent, list) else []
        baseline_rows = baseline if isinstance(baseline, list) else []
        if recent_rows:
            recent_replay_ratio = sum(1.0 for item in recent_rows if float(item.get("advisor_candidate_count", 0) or 0) > 0.0) / float(
                max(1, len(recent_rows))
            )
            recent_candidate_density = sum(float(item.get("advisor_candidate_count", 0) or 0) for item in recent_rows) / float(
                max(1, len(recent_rows))
            )
            recent_execution_density = sum(float(item.get("execution_candidate_count", 0) or 0) for item in recent_rows) / float(
                max(1, len(recent_rows))
            )
            recent_compare_required = sum(
                float(
                    (
                        item.get("approval_summary", {})
                        if isinstance(item.get("approval_summary"), dict)
                        else {}
                    ).get("compare_required_ratio", 0.0)
                    or 0.0
                )
                for item in recent_rows
            ) / float(max(1, len(recent_rows)))
            recent_approval_required = sum(
                float(
                    (
                        item.get("approval_summary", {})
                        if isinstance(item.get("approval_summary"), dict)
                        else {}
                    ).get("approval_required_ratio", 0.0)
                    or 0.0
                )
                for item in recent_rows
            ) / float(max(1, len(recent_rows)))
            recent_ready_execute = sum(
                float(
                    (
                        item.get("approval_summary", {})
                        if isinstance(item.get("approval_summary"), dict)
                        else {}
                    ).get("ready_execute_ratio", 0.0)
                    or 0.0
                )
                for item in recent_rows
            ) / float(max(1, len(recent_rows)))
            recent_manual_review = sum(
                float(
                    (
                        item.get("approval_summary", {})
                        if isinstance(item.get("approval_summary"), dict)
                        else {}
                    ).get("manual_review_ratio", 0.0)
                    or 0.0
                )
                for item in recent_rows
            ) / float(max(1, len(recent_rows)))
            recent_promotion_score = sum(
                float(
                    (
                        item.get("promotion_preview", {})
                        if isinstance(item.get("promotion_preview"), dict)
                        else {}
                    ).get("promotion_score", 0.0)
                    or 0.0
                )
                for item in recent_rows
            ) / float(max(1, len(recent_rows)))
            recent_promotion_ready = sum(
                1.0
                for item in recent_rows
                if bool(
                    (
                        item.get("promotion_preview", {})
                        if isinstance(item.get("promotion_preview"), dict)
                        else {}
                    ).get("recommended_apply", False)
                )
            ) / float(max(1, len(recent_rows)))
            for item in recent_rows:
                advisor_context_row = item.get("advisor_context", {}) if isinstance(item.get("advisor_context"), dict) else {}
                source_name = str(advisor_context_row.get("source", "manual")).strip().lower() or "manual"
                recent_source_mix[source_name] = recent_source_mix.get(source_name, 0) + 1
        if baseline_rows:
            baseline_replay_ratio = sum(
                1.0 for item in baseline_rows if float(item.get("advisor_candidate_count", 0) or 0) > 0.0
            ) / float(max(1, len(baseline_rows)))
            baseline_candidate_density = sum(
                float(item.get("advisor_candidate_count", 0) or 0) for item in baseline_rows
            ) / float(max(1, len(baseline_rows)))
            baseline_execution_density = sum(
                float(item.get("execution_candidate_count", 0) or 0) for item in baseline_rows
            ) / float(max(1, len(baseline_rows)))
            baseline_compare_required = sum(
                float(
                    (
                        item.get("approval_summary", {})
                        if isinstance(item.get("approval_summary"), dict)
                        else {}
                    ).get("compare_required_ratio", 0.0)
                    or 0.0
                )
                for item in baseline_rows
            ) / float(max(1, len(baseline_rows)))
            baseline_approval_required = sum(
                float(
                    (
                        item.get("approval_summary", {})
                        if isinstance(item.get("approval_summary"), dict)
                        else {}
                    ).get("approval_required_ratio", 0.0)
                    or 0.0
                )
                for item in baseline_rows
            ) / float(max(1, len(baseline_rows)))
            baseline_ready_execute = sum(
                float(
                    (
                        item.get("approval_summary", {})
                        if isinstance(item.get("approval_summary"), dict)
                        else {}
                    ).get("ready_execute_ratio", 0.0)
                    or 0.0
                )
                for item in baseline_rows
            ) / float(max(1, len(baseline_rows)))
            baseline_manual_review = sum(
                float(
                    (
                        item.get("approval_summary", {})
                        if isinstance(item.get("approval_summary"), dict)
                        else {}
                    ).get("manual_review_ratio", 0.0)
                    or 0.0
                )
                for item in baseline_rows
            ) / float(max(1, len(baseline_rows)))
            baseline_promotion_score = sum(
                float(
                    (
                        item.get("promotion_preview", {})
                        if isinstance(item.get("promotion_preview"), dict)
                        else {}
                    ).get("promotion_score", 0.0)
                    or 0.0
                )
                for item in baseline_rows
            ) / float(max(1, len(baseline_rows)))
            baseline_promotion_ready = sum(
                1.0
                for item in baseline_rows
                if bool(
                    (
                        item.get("promotion_preview", {})
                        if isinstance(item.get("promotion_preview"), dict)
                        else {}
                    ).get("recommended_apply", False)
                )
            ) / float(max(1, len(baseline_rows)))
        approval_band = "ready"
        if recent_approval_required >= 0.5 or recent_compare_required >= 0.5:
            approval_band = "guarded"
        elif recent_manual_review >= 0.34:
            approval_band = "review"
        execution_mode = "manual_gate"
        if recent_ready_execute >= 0.7 and recent_approval_required <= 0.16 and recent_compare_required <= 0.16:
            execution_mode = "direct_execute"
        elif recent_ready_execute >= 0.34:
            execution_mode = "stage_then_compare"
        promotion_trend_context = {
            "recent": {
                "count": len(recent),
                "ready_ratio": round(recent_ready, 6),
                "error_ratio": round(recent_error, 6),
                "confidence": round(recent_confidence, 6),
                "composite_score": round(recent_composite, 6),
            },
            "baseline": {
                "count": len(baseline),
                "ready_ratio": round(baseline_ready, 6),
                "error_ratio": round(baseline_error, 6),
                "confidence": round(baseline_confidence, 6),
                "composite_score": round(baseline_composite, 6),
            },
            "stability": {
                "score": round(stability_score, 6),
                "drift_pressure": round(drift_pressure, 6),
                "switch_rate": round(switch_rate, 6),
                "confidence_volatility": round(confidence_volatility, 6),
            },
            "recommended_profile": recommended_profile,
            "recommended_controls": dict(profile_controls.get(recommended_profile, profile_controls["balanced"])),
        }
        promotion_readiness: Dict[str, Any] = {
            "status": "success",
            "eligible": False,
            "recommended_apply": False,
            "summary": "No recent simulation is available for promotion analysis.",
        }
        if snapshots:
            latest_row = self._find_connector_simulation_history_row(str(snapshots[-1].get("simulation_id", "")))
            if isinstance(latest_row, dict):
                promotion_readiness = self._external_connector_build_simulation_promotion_preview(
                    simulation=latest_row,
                    trends=promotion_trend_context,
                    require_compare=bool(
                        (
                            latest_row.get("approval_summary", {})
                            if isinstance(latest_row.get("approval_summary"), dict)
                            else {}
                        ).get("compare_required_count", 0)
                    ),
                )
        snapshots_tail = [
            {
                "simulation_id": str(item.get("simulation_id", "")),
                "created_at": str(item.get("created_at", "")),
                "recommended_provider": str(item.get("recommended_provider", "")),
                "status": str(item.get("status", "")),
                "ready_ratio": float(item.get("ready_ratio", 0.0) or 0.0),
                "error_ratio": float(item.get("error_ratio", 0.0) or 0.0),
                "confidence": float(item.get("confidence", 0.0) or 0.0),
                "composite_score": float(item.get("composite_score", 0.0) or 0.0),
                "advisor_candidate_count": int(item.get("advisor_candidate_count", 0) or 0),
                "execution_candidate_count": int(item.get("execution_candidate_count", 0) or 0),
            }
            for item in snapshots[-40:]
        ]

        return {
            "status": "success",
            "count": count,
            "limit": bounded_limit,
            "recent_window": bounded_recent,
            "baseline_window": bounded_baseline,
            "filters": {
                "action": action_filter,
                "provider": provider_filter,
                "status": status_filter,
            },
            "recent": {
                "count": len(recent),
                "ready_ratio": round(recent_ready, 6),
                "error_ratio": round(recent_error, 6),
                "confidence": round(recent_confidence, 6),
                "composite_score": round(recent_composite, 6),
            },
            "baseline": {
                "count": len(baseline),
                "ready_ratio": round(baseline_ready, 6),
                "error_ratio": round(baseline_error, 6),
                "confidence": round(baseline_confidence, 6),
                "composite_score": round(baseline_composite, 6),
            },
            "deltas": {
                "ready_ratio": round(delta_ready, 6),
                "error_ratio": round(delta_error, 6),
                "confidence": round(delta_confidence, 6),
                "composite_score": round(delta_composite, 6),
            },
            "stability": {
                "score": round(stability_score, 6),
                "drift_pressure": round(drift_pressure, 6),
                "switch_rate": round(switch_rate, 6),
                "confidence_volatility": round(confidence_volatility, 6),
            },
            "advisor_usage": {
                "recent": {
                    "replay_ratio": round(recent_replay_ratio, 6),
                    "candidate_density": round(recent_candidate_density, 6),
                    "execution_density": round(recent_execution_density, 6),
                    "compare_required_ratio": round(recent_compare_required, 6),
                    "approval_required_ratio": round(recent_approval_required, 6),
                },
                "baseline": {
                    "replay_ratio": round(baseline_replay_ratio, 6),
                    "candidate_density": round(baseline_candidate_density, 6),
                    "execution_density": round(baseline_execution_density, 6),
                    "compare_required_ratio": round(baseline_compare_required, 6),
                    "approval_required_ratio": round(baseline_approval_required, 6),
                },
                "deltas": {
                    "replay_ratio": round(recent_replay_ratio - baseline_replay_ratio, 6),
                    "candidate_density": round(recent_candidate_density - baseline_candidate_density, 6),
                    "execution_density": round(recent_execution_density - baseline_execution_density, 6),
                    "compare_required_ratio": round(recent_compare_required - baseline_compare_required, 6),
                    "approval_required_ratio": round(recent_approval_required - baseline_approval_required, 6),
                },
                "source_mix": [
                    {
                        "source": name,
                        "count": count_value,
                        "share": round(float(count_value) / float(max(1, len(recent_rows))), 6),
                    }
                    for name, count_value in sorted(recent_source_mix.items(), key=lambda item: (-item[1], item[0]))
                ],
            },
            "approval_pressure": {
                "status": approval_band,
                "recent": {
                    "approval_required_ratio": round(recent_approval_required, 6),
                    "compare_required_ratio": round(recent_compare_required, 6),
                    "manual_review_ratio": round(recent_manual_review, 6),
                    "ready_execute_ratio": round(recent_ready_execute, 6),
                },
                "baseline": {
                    "approval_required_ratio": round(baseline_approval_required, 6),
                    "compare_required_ratio": round(baseline_compare_required, 6),
                    "manual_review_ratio": round(baseline_manual_review, 6),
                    "ready_execute_ratio": round(baseline_ready_execute, 6),
                },
                "deltas": {
                    "approval_required_ratio": round(recent_approval_required - baseline_approval_required, 6),
                    "compare_required_ratio": round(recent_compare_required - baseline_compare_required, 6),
                    "manual_review_ratio": round(recent_manual_review - baseline_manual_review, 6),
                    "ready_execute_ratio": round(recent_ready_execute - baseline_ready_execute, 6),
                },
            },
            "execution_readiness": {
                "mode": execution_mode,
                "recent": {
                    "ready_execute_ratio": round(recent_ready_execute, 6),
                    "execution_density": round(recent_execution_density, 6),
                    "promotion_score": round(recent_promotion_score, 6),
                },
                "baseline": {
                    "ready_execute_ratio": round(baseline_ready_execute, 6),
                    "execution_density": round(baseline_execution_density, 6),
                    "promotion_score": round(baseline_promotion_score, 6),
                },
                "deltas": {
                    "ready_execute_ratio": round(recent_ready_execute - baseline_ready_execute, 6),
                    "execution_density": round(recent_execution_density - baseline_execution_density, 6),
                    "promotion_score": round(recent_promotion_score - baseline_promotion_score, 6),
                },
            },
            "promotion_readiness": {
                **promotion_readiness,
                "recent_apply_ratio": round(recent_promotion_ready, 6),
                "baseline_apply_ratio": round(baseline_promotion_ready, 6),
                "apply_ratio_delta": round(recent_promotion_ready - baseline_promotion_ready, 6),
            },
            "provider_mix": provider_rows,
            "recommended_profile": recommended_profile,
            "recommended_controls": dict(profile_controls.get(recommended_profile, profile_controls["balanced"])),
            "profile_controls": profile_controls,
            "snapshots": snapshots_tail,
        }

    def external_connector_preflight_simulation_promotions(
        self,
        *,
        limit: int = 80,
        action: str = "",
        provider: str = "",
        mission_mode: str = "",
        status: str = "",
        applied_only: bool = False,
    ) -> Dict[str, Any]:
        self._load_connector_simulation_history()
        bounded = max(1, min(int(limit), 5000))
        action_filter = str(action or "").strip().lower()
        provider_filter = self._normalize_external_provider_name(provider)
        mission_mode_filter = (
            self._connector_remediation_policy_normalize_mission_mode(mission_mode, wildcard_default=True)
            if str(mission_mode or "").strip()
            else ""
        )
        status_filter = str(status or "").strip().lower()
        with self._connector_simulation_history_lock:
            rows = list(self._connector_simulation_history)
        rows.sort(key=lambda row: str(row.get("created_at", "")), reverse=True)

        items: list[Dict[str, Any]] = []
        for row in rows:
            if not isinstance(row, dict):
                continue
            action_name = str(row.get("action", "")).strip().lower()
            if action_filter and action_name != action_filter:
                continue
            provider_name = self._normalize_external_provider_name(
                row.get("recommended_provider", row.get("requested_provider", ""))
            ) or "auto"
            if provider_filter and provider_name != provider_filter:
                continue
            policy_promotion = row.get("policy_promotion", {}) if isinstance(row.get("policy_promotion"), dict) else {}
            if not policy_promotion:
                continue
            promotion_status = str(policy_promotion.get("status", "")).strip().lower() or "unknown"
            if status_filter and promotion_status != status_filter:
                continue
            applied = bool(policy_promotion.get("applied", False))
            if applied_only and not applied:
                continue
            promotion = policy_promotion.get("promotion", {}) if isinstance(policy_promotion.get("promotion"), dict) else {}
            apply_payload = policy_promotion.get("apply", {}) if isinstance(policy_promotion.get("apply"), dict) else {}
            entry = policy_promotion.get("entry", {}) if isinstance(policy_promotion.get("entry"), dict) else {}
            if not entry and isinstance(apply_payload.get("entry"), dict):
                entry = dict(apply_payload.get("entry", {}))
            history_event = (
                apply_payload.get("history_event", {}) if isinstance(apply_payload.get("history_event"), dict) else {}
            )
            mission_mode_name = self._connector_remediation_policy_normalize_mission_mode(
                policy_promotion.get(
                    "mission_mode",
                    entry.get("mission_mode", history_event.get("mission_mode", "*")),
                ),
                wildcard_default=True,
            )
            if mission_mode_filter and mission_mode_name != mission_mode_filter:
                continue
            item = {
                "simulation_id": str(row.get("simulation_id", "")).strip(),
                "created_at": str(row.get("created_at", "")).strip(),
                "action": action_name,
                "requested_provider": self._normalize_external_provider_name(row.get("requested_provider", "")) or "auto",
                "recommended_provider": provider_name,
                "compare_against_simulation_id": str(
                    policy_promotion.get("compare_against_simulation_id", row.get("compare_against_simulation_id", ""))
                ).strip(),
                "promotion_status": promotion_status,
                "applied": applied,
                "mission_mode": mission_mode_name,
                "promotion_score": float(promotion.get("promotion_score", 0.0) or 0.0),
                "recommended_profile": self._connector_remediation_policy_normalize_profile(
                    str(promotion.get("recommended_profile", entry.get("profile", "balanced")))
                ),
                "gate_reasons": [
                    str(item).strip().lower()
                    for item in (promotion.get("gate_reasons", []) if isinstance(promotion.get("gate_reasons"), list) else [])
                    if str(item).strip()
                ][:8],
                "summary": str(
                    policy_promotion.get("message", promotion.get("summary", "Connector promotion event recorded."))
                ).strip()
                or "Connector promotion event recorded.",
                "scope_key": str(
                    entry.get("scope_key", apply_payload.get("scope_key", history_event.get("scope_key", "")))
                ).strip().lower(),
                "event_id": int(
                    apply_payload.get("event_id", history_event.get("event_id", 0)) or 0
                ),
                "entry_version": int(entry.get("version", 0) or 0),
                "policy_entry": _to_jsonable(entry),
                "history_event": _to_jsonable(history_event),
                "policy_promotion": _to_jsonable(policy_promotion),
                "promotion_preview": _to_jsonable(row.get("promotion_preview", {}))
                if isinstance(row.get("promotion_preview"), dict)
                else {},
            }
            items.append(item)
            if len(items) >= bounded:
                break
        return {
            "status": "success",
            "items": items,
            "count": len(items),
            "limit": bounded,
            "filters": {
                "action": action_filter,
                "provider": provider_filter,
                "mission_mode": mission_mode_filter,
                "status": status_filter,
                "applied_only": bool(applied_only),
            },
        }

    @staticmethod
    def _connector_remediation_policy_diff_summary(
        current_entry: Dict[str, Any],
        target_row: Dict[str, Any],
    ) -> Dict[str, Any]:
        current_profile = str(current_entry.get("profile", "balanced")).strip().lower() or "balanced"
        target_profile = str(target_row.get("profile", "balanced")).strip().lower() or "balanced"
        current_controls = current_entry.get("controls", {}) if isinstance(current_entry.get("controls"), dict) else {}
        target_controls = target_row.get("controls", {}) if isinstance(target_row.get("controls"), dict) else {}
        changed_controls: list[Dict[str, Any]] = []
        keys = sorted(set(current_controls.keys()) | set(target_controls.keys()))
        for key in keys:
            before = current_controls.get(key)
            after = target_controls.get(key)
            if before == after:
                continue
            changed_controls.append(
                {
                    "key": str(key),
                    "before": _to_jsonable(before),
                    "after": _to_jsonable(after),
                }
            )
        return {
            "profile_changed": current_profile != target_profile,
            "before_profile": current_profile,
            "after_profile": target_profile,
            "changed_control_count": len(changed_controls),
            "changed_controls": changed_controls[:12],
            "summary": (
                "Selected policy event matches the current persisted configuration."
                if current_profile == target_profile and not changed_controls
                else (
                    f"Restoring this event will switch profile from '{current_profile}' to '{target_profile}' "
                    f"and change {len(changed_controls)} control field(s)."
                )
            ),
        }

    def external_connector_remediation_policy_restore(
        self,
        *,
        event_id: int = 0,
        action: str = "",
        provider: str = "",
        mission_mode: str = "",
        source: str = "desktop-ui",
        reason: str = "",
        dry_run: bool = True,
        force: bool = False,
    ) -> Dict[str, Any]:
        self._load_connector_remediation_policy_state()
        requested_event_id = int(event_id or 0)
        action_filter = str(action or "").strip().lower()
        provider_filter = self._normalize_external_provider_name(provider)
        mission_mode_filter = (
            self._connector_remediation_policy_normalize_mission_mode(mission_mode, wildcard_default=True)
            if str(mission_mode or "").strip()
            else ""
        )
        with self._connector_remediation_policy_lock:
            state = self._connector_remediation_policy_state if isinstance(self._connector_remediation_policy_state, dict) else {}
            history_rows = [dict(item) for item in state.get("history", []) if isinstance(item, dict)]
        target_row: Dict[str, Any] = {}
        for row in reversed(history_rows):
            row_event_id = int(row.get("event_id", 0) or 0)
            if requested_event_id and row_event_id != requested_event_id:
                continue
            scope_meta = self._connector_remediation_policy_parse_scope_key(row.get("scope_key", ""))
            row_action = str(row.get("action", scope_meta["action"])).strip().lower()
            row_provider = self._normalize_external_provider_name(row.get("provider", scope_meta["provider"])) or "auto"
            row_mode = self._connector_remediation_policy_normalize_mission_mode(
                row.get("mission_mode", scope_meta["mission_mode"]),
                wildcard_default=True,
            )
            if action_filter and row_action != action_filter:
                continue
            if provider_filter and row_provider != provider_filter:
                continue
            if mission_mode_filter and row_mode != mission_mode_filter:
                continue
            target_row = dict(row)
            target_row["action"] = row_action
            target_row["provider"] = row_provider
            target_row["mission_mode"] = row_mode
            break
        if not target_row:
            return {"status": "error", "message": "matching remediation policy history event was not found"}

        current = self.external_connector_remediation_policy_status(
            action=str(target_row.get("action", "")).strip().lower(),
            provider=str(target_row.get("provider", "auto")).strip().lower() or "auto",
            mission_mode=str(target_row.get("mission_mode", "*")).strip().lower() or "*",
            include_history=False,
            include_alerts=False,
        )
        current_entry = current.get("entry", {}) if isinstance(current.get("entry"), dict) else {}
        diff_summary = self._connector_remediation_policy_diff_summary(current_entry, target_row)
        restore_metadata = {
            "restore_event_id": int(target_row.get("event_id", 0) or 0),
            "restore_scope_key": str(target_row.get("scope_key", "")).strip().lower(),
            "restore_created_at": str(target_row.get("created_at", "")).strip(),
            "restore_source": str(target_row.get("source", "")).strip().lower(),
            "restore_reason": str(target_row.get("reason", "")).strip(),
            "restore_previous_entry": _to_jsonable(current_entry),
            "restore_diff": _to_jsonable(diff_summary),
        }
        if dry_run:
            return {
                "status": "dry_run",
                "applied": False,
                "event_id": int(target_row.get("event_id", 0) or 0),
                "target": _to_jsonable(target_row),
                "current": _to_jsonable(current_entry),
                "diff": diff_summary,
                "message": str(diff_summary.get("summary", "Policy restore preview completed.")).strip()
                or "Policy restore preview completed.",
            }
        if not force and not bool(diff_summary.get("profile_changed", False)) and int(diff_summary.get("changed_control_count", 0) or 0) <= 0:
            return {
                "status": "skip",
                "applied": False,
                "event_id": int(target_row.get("event_id", 0) or 0),
                "target": _to_jsonable(target_row),
                "current": _to_jsonable(current_entry),
                "diff": diff_summary,
                "message": "Selected policy event already matches the current persisted configuration.",
            }
        apply_payload = self.external_connector_remediation_policy_apply(
            action=str(target_row.get("action", "")).strip().lower(),
            provider=str(target_row.get("provider", "auto")).strip().lower() or "auto",
            mission_mode=str(target_row.get("mission_mode", "*")).strip().lower() or "*",
            profile=str(target_row.get("profile", "balanced")).strip().lower() or "balanced",
            controls=target_row.get("controls", {}) if isinstance(target_row.get("controls"), dict) else {},
            source=str(source or "desktop-ui").strip().lower() or "desktop-ui",
            reason=str(reason or "restore_history_event").strip() or "restore_history_event",
            metadata=restore_metadata,
            use_recommendation=False,
        )
        if str(apply_payload.get("status", "")).strip().lower() != "success":
            return apply_payload
        return {
            "status": "applied",
            "applied": True,
            "event_id": int(target_row.get("event_id", 0) or 0),
            "target": _to_jsonable(target_row),
            "current": _to_jsonable(current_entry),
            "diff": diff_summary,
            "apply": apply_payload,
            "entry": _to_jsonable(apply_payload.get("entry", {})),
            "message": str(
                apply_payload.get("message", "Policy restore applied from history event.")
            ).strip()
            or "Policy restore applied from history event.",
        }

    def _connector_execution_contract_candidate_summary(
        self,
        simulation: Dict[str, Any],
    ) -> list[Dict[str, Any]]:
        results = simulation.get("results", []) if isinstance(simulation.get("results"), list) else []
        rows: list[Dict[str, Any]] = []
        for index, row in enumerate(results):
            if not isinstance(row, dict):
                continue
            candidate_id = str(
                row.get("advisor_candidate_id", row.get("candidate_id", row.get("execution_candidate_id", "")))
            ).strip()
            if not bool(row.get("execution_candidate", False)) and not candidate_id:
                continue
            provider_selected = self._normalize_external_provider_name(
                row.get("provider_selected", row.get("provider_requested", ""))
            ) or "auto"
            provider_requested = self._normalize_external_provider_name(
                row.get("provider_requested", provider_selected)
            ) or provider_selected
            approval_preview = row.get("approval_preview", {}) if isinstance(row.get("approval_preview"), dict) else {}
            posture = (
                str(approval_preview.get("posture", row.get("approval_posture", "review_required"))).strip().lower()
                or "review_required"
            )
            ready_to_execute = bool(approval_preview.get("ready_to_execute", row.get("approval_ready", False)))
            approval_required = bool(
                approval_preview.get("requires_approval_ticket", row.get("approval_required", False))
            )
            requires_compare = posture in {"compare_required", "compare_then_approve"} or bool(
                approval_preview.get("requires_compare", False)
            )
            rows.append(
                {
                    "candidate_id": candidate_id or f"candidate_{index + 1}",
                    "scenario_id": str(row.get("scenario_id", row.get("id", ""))).strip(),
                    "provider_selected": provider_selected,
                    "provider_requested": provider_requested,
                    "status": str(row.get("status", "unknown")).strip().lower() or "unknown",
                    "risk_score": round(float(row.get("risk_score", 0.0) or 0.0), 6),
                    "reliability_pressure": round(float(row.get("reliability_pressure", 0.0) or 0.0), 6),
                    "decision_score": round(float(row.get("decision_score", 0.0) or 0.0), 6),
                    "approval_posture": posture,
                    "approval_required": approval_required,
                    "requires_compare": requires_compare,
                    "ready_to_execute": ready_to_execute,
                    "route_signature": f"{provider_selected}:{candidate_id or f'candidate_{index + 1}'}",
                }
            )
        rows.sort(
            key=lambda row: (
                0 if bool(row.get("ready_to_execute", False)) else 1,
                -float(row.get("decision_score", 0.0) or 0.0),
                float(row.get("risk_score", 0.0) or 0.0),
            )
        )
        return rows[:8]

    def _connector_execution_contract_entry_payload_from_simulation(
        self,
        *,
        simulation: Dict[str, Any],
        provider_name: str,
        compare_target: str,
        promotion: Optional[Dict[str, Any]] = None,
        trend_summary: Optional[Dict[str, Any]] = None,
        remediation_apply: Optional[Dict[str, Any]] = None,
    ) -> Dict[str, Any]:
        promotion_payload = promotion if isinstance(promotion, dict) else {}
        trend_payload = trend_summary if isinstance(trend_summary, dict) else {}
        remediation_payload = remediation_apply if isinstance(remediation_apply, dict) else {}
        remediation_entry = (
            remediation_payload.get("entry", {}) if isinstance(remediation_payload.get("entry"), dict) else {}
        )
        approval_summary = (
            dict(simulation.get("approval_summary", {}))
            if isinstance(simulation.get("approval_summary"), dict)
            else {}
        )
        advisor_context = (
            dict(simulation.get("advisor_context", {}))
            if isinstance(simulation.get("advisor_context"), dict)
            else {}
        )
        recommended_tool_action = (
            dict(simulation.get("recommended_tool_action", {}))
            if isinstance(simulation.get("recommended_tool_action"), dict)
            else {}
        )
        recommended_args_patch = (
            dict(simulation.get("recommended_args_patch", {}))
            if isinstance(simulation.get("recommended_args_patch"), dict)
            else {}
        )
        best_run = dict(simulation.get("best_run", {})) if isinstance(simulation.get("best_run"), dict) else {}
        candidate_summary = self._connector_execution_contract_candidate_summary(simulation)
        profile = self._connector_remediation_policy_normalize_profile(
            str(remediation_entry.get("profile", promotion_payload.get("recommended_profile", "balanced")))
        )
        controls = self._connector_remediation_policy_sanitize_controls(
            profile=profile,
            controls=remediation_entry.get("controls", promotion_payload.get("recommended_controls", {}))
            if isinstance(
                remediation_entry.get("controls", promotion_payload.get("recommended_controls", {})),
                dict,
            )
            else {},
        )
        route_signature = "none"
        if candidate_summary:
            route_signature = " -> ".join(
                str(item.get("route_signature", "")).strip()
                for item in candidate_summary
                if str(item.get("route_signature", "")).strip()
            ) or route_signature
        elif provider_name:
            route_signature = provider_name
        promotion_summary = {
            "eligible": bool(promotion_payload.get("eligible", False)),
            "recommended_apply": bool(promotion_payload.get("recommended_apply", False)),
            "compare_improved": bool(promotion_payload.get("compare_improved", False)),
            "gate_reasons": [
                str(item).strip().lower()
                for item in (
                    promotion_payload.get("gate_reasons", [])
                    if isinstance(promotion_payload.get("gate_reasons"), list)
                    else []
                )
                if str(item).strip()
            ][:8],
            "summary": str(promotion_payload.get("summary", "")).strip(),
        }
        return {
            "simulation_id": str(simulation.get("simulation_id", "")).strip(),
            "compare_against_simulation_id": str(compare_target or simulation.get("compare_against_simulation_id", "") or "").strip(),
            "selected_provider": provider_name,
            "recommended_provider": self._normalize_external_provider_name(
                simulation.get("recommended_provider", provider_name)
            ) or provider_name,
            "profile": profile,
            "controls": controls,
            "promotion_score": round(float(promotion_payload.get("promotion_score", 0.0) or 0.0), 6),
            "promotion": _to_jsonable(promotion_summary),
            "approval_summary": _to_jsonable(approval_summary),
            "candidate_summary": _to_jsonable(candidate_summary),
            "candidate_count": max(
                len(candidate_summary),
                int(simulation.get("execution_candidate_count", approval_summary.get("candidate_count", 0)) or 0),
            ),
            "ready_execute_count": sum(1 for item in candidate_summary if bool(item.get("ready_to_execute", False))),
            "recommended_tool_action": _to_jsonable(recommended_tool_action),
            "recommended_args_patch": _to_jsonable(recommended_args_patch),
            "fallback_chain": _to_jsonable(
                list(simulation.get("fallback_chain", []))
                if isinstance(simulation.get("fallback_chain"), list)
                else []
            ),
            "best_run": _to_jsonable(
                {
                    "provider_selected": self._normalize_external_provider_name(
                        best_run.get("provider_selected", best_run.get("provider_requested", provider_name))
                    )
                    or provider_name,
                    "status": str(best_run.get("status", "unknown")).strip().lower() or "unknown",
                    "risk_score": round(float(best_run.get("risk_score", 0.0) or 0.0), 6),
                    "reliability_pressure": round(float(best_run.get("reliability_pressure", 0.0) or 0.0), 6),
                    "decision_score": round(float(best_run.get("decision_score", 0.0) or 0.0), 6),
                }
            ),
            "advisor_context": _to_jsonable(
                {
                    "source": str(advisor_context.get("source", "manual")).strip().lower() or "manual",
                    "candidate_count": int(advisor_context.get("candidate_count", 0) or 0),
                    "runtime_lane": str(advisor_context.get("runtime_lane", "parallel")).strip().lower() or "parallel",
                    "requested_provider": self._normalize_external_provider_name(
                        advisor_context.get("requested_provider", simulation.get("requested_provider", provider_name))
                    )
                    or provider_name,
                }
            ),
            "trend_summary": _to_jsonable(
                {
                    "recent": trend_payload.get("recent", {}) if isinstance(trend_payload.get("recent"), dict) else {},
                    "deltas": trend_payload.get("deltas", {}) if isinstance(trend_payload.get("deltas"), dict) else {},
                    "stability": trend_payload.get("stability", {})
                    if isinstance(trend_payload.get("stability"), dict)
                    else {},
                }
            ),
            "route_signature": route_signature,
        }

    @staticmethod
    def _connector_execution_contract_entry_payload_from_history_row(row: Dict[str, Any]) -> Dict[str, Any]:
        keys = {
            "simulation_id",
            "compare_against_simulation_id",
            "selected_provider",
            "recommended_provider",
            "profile",
            "controls",
            "promotion_score",
            "promotion",
            "approval_summary",
            "candidate_summary",
            "candidate_count",
            "ready_execute_count",
            "recommended_tool_action",
            "recommended_args_patch",
            "fallback_chain",
            "best_run",
            "advisor_context",
            "trend_summary",
            "route_signature",
        }
        payload: Dict[str, Any] = {}
        for key in keys:
            if key in row:
                payload[key] = _to_jsonable(row.get(key))
        return payload

    def _connector_execution_contract_write_entry(
        self,
        *,
        action: str,
        provider: str = "auto",
        mission_mode: str = "*",
        entry_payload: Optional[Dict[str, Any]] = None,
        source: str = "desktop-ui",
        reason: str = "",
        metadata: Optional[Dict[str, Any]] = None,
        event_type: str = "apply",
    ) -> Dict[str, Any]:
        scope = self._connector_remediation_policy_scope(
            action=action,
            provider=provider,
            mission_mode=mission_mode,
        )
        payload = entry_payload if isinstance(entry_payload, dict) else {}
        clean_source = str(source or "desktop-ui").strip().lower() or "desktop-ui"
        metadata_payload = metadata if isinstance(metadata, dict) else {}
        profile = self._connector_remediation_policy_normalize_profile(str(payload.get("profile", "balanced")))
        controls = self._connector_remediation_policy_sanitize_controls(
            profile=profile,
            controls=payload.get("controls", {}) if isinstance(payload.get("controls"), dict) else {},
        )
        candidate_summary = (
            payload.get("candidate_summary", [])
            if isinstance(payload.get("candidate_summary"), list)
            else []
        )
        now_iso = self._utc_now_iso()

        self._load_connector_execution_contract_state()
        with self._connector_execution_contract_lock:
            state = (
                self._connector_execution_contract_state
                if isinstance(self._connector_execution_contract_state, dict)
                else self._connector_execution_contract_default_state()
            )
            contracts = state.get("contracts", {}) if isinstance(state.get("contracts"), dict) else {}
            history = state.get("history", []) if isinstance(state.get("history"), list) else []
            previous = contracts.get(scope["scope_key"], {}) if isinstance(contracts.get(scope["scope_key"]), dict) else {}
            next_version = int(previous.get("version", 0) or 0) + 1
            event_id = int(history[-1].get("event_id", 0) or 0) + 1 if history and isinstance(history[-1], dict) else 1

            entry = {
                "scope_key": scope["scope_key"],
                "legacy_scope_key": scope["legacy_scope_key"],
                "action": scope["action"],
                "provider": scope["provider"],
                "mission_mode": scope["mission_mode"],
                "simulation_id": str(payload.get("simulation_id", "")).strip(),
                "compare_against_simulation_id": str(payload.get("compare_against_simulation_id", "")).strip(),
                "selected_provider": self._normalize_external_provider_name(
                    payload.get("selected_provider", scope["provider"])
                )
                or scope["provider"],
                "recommended_provider": self._normalize_external_provider_name(
                    payload.get("recommended_provider", payload.get("selected_provider", scope["provider"]))
                )
                or scope["provider"],
                "profile": profile,
                "controls": controls,
                "promotion_score": round(float(payload.get("promotion_score", 0.0) or 0.0), 6),
                "promotion": _to_jsonable(payload.get("promotion", {}) if isinstance(payload.get("promotion"), dict) else {}),
                "approval_summary": _to_jsonable(
                    payload.get("approval_summary", {}) if isinstance(payload.get("approval_summary"), dict) else {}
                ),
                "candidate_summary": _to_jsonable(
                    [dict(item) for item in candidate_summary if isinstance(item, dict)][:8]
                ),
                "candidate_count": int(payload.get("candidate_count", len(candidate_summary)) or len(candidate_summary)),
                "ready_execute_count": int(payload.get("ready_execute_count", 0) or 0),
                "recommended_tool_action": _to_jsonable(
                    payload.get("recommended_tool_action", {})
                    if isinstance(payload.get("recommended_tool_action"), dict)
                    else {}
                ),
                "recommended_args_patch": _to_jsonable(
                    payload.get("recommended_args_patch", {})
                    if isinstance(payload.get("recommended_args_patch"), dict)
                    else {}
                ),
                "fallback_chain": _to_jsonable(
                    payload.get("fallback_chain", []) if isinstance(payload.get("fallback_chain"), list) else []
                ),
                "best_run": _to_jsonable(payload.get("best_run", {}) if isinstance(payload.get("best_run"), dict) else {}),
                "advisor_context": _to_jsonable(
                    payload.get("advisor_context", {})
                    if isinstance(payload.get("advisor_context"), dict)
                    else {}
                ),
                "trend_summary": _to_jsonable(
                    payload.get("trend_summary", {}) if isinstance(payload.get("trend_summary"), dict) else {}
                ),
                "route_signature": str(payload.get("route_signature", "")).strip(),
                "version": next_version,
                "updated_at": now_iso,
                "updated_by_source": clean_source,
                "reason": str(reason or "").strip(),
                "metadata": _to_jsonable(metadata_payload),
            }
            contracts[scope["scope_key"]] = _to_jsonable(entry)
            state["contracts"] = contracts

            history_event = {
                "event_id": event_id,
                "created_at": now_iso,
                "event_type": str(event_type or "apply").strip().lower() or "apply",
                **entry,
            }
            history.append(_to_jsonable(history_event))
            max_history = max(40, int(getattr(self, "_connector_execution_contract_history_max", 1200) or 1200))
            if len(history) > max_history:
                history = history[-max_history:]
            state["history"] = history
            state["updated_at"] = now_iso
            state["version"] = str(state.get("version", "1.0") or "1.0")
            self._connector_execution_contract_state = state
            self._connector_execution_contract_dirty = True

        self._persist_connector_execution_contract_state(force=False)
        try:
            self.kernel.telemetry.emit(
                "external.connector_execution_contract_applied",
                {
                    "scope_key": scope["scope_key"],
                    "action": scope["action"],
                    "provider": scope["provider"],
                    "mission_mode": scope["mission_mode"],
                    "selected_provider": str(entry.get("selected_provider", scope["provider"])),
                    "simulation_id": str(entry.get("simulation_id", "")),
                    "event_type": str(event_type or "apply").strip().lower() or "apply",
                    "source": clean_source,
                },
            )
        except Exception:
            pass
        return {
            "status": "success",
            "action": scope["action"],
            "provider": scope["provider"],
            "mission_mode": scope["mission_mode"],
            "scope_key": scope["scope_key"],
            "event_id": event_id,
            "entry": _to_jsonable(entry),
            "history_event": _to_jsonable(history_event),
            "message": f"Execution contract updated for {scope['scope_key']}.",
        }

    def external_connector_execution_contract_apply_from_simulation(
        self,
        *,
        simulation_id: str,
        action: str,
        provider: str = "auto",
        mission_mode: str = "*",
        source: str = "desktop-ui",
        reason: str = "",
        compare_against_simulation_id: str = "",
        promotion: Optional[Dict[str, Any]] = None,
        trend_summary: Optional[Dict[str, Any]] = None,
        remediation_apply: Optional[Dict[str, Any]] = None,
        metadata: Optional[Dict[str, Any]] = None,
    ) -> Dict[str, Any]:
        clean_id = str(simulation_id or "").strip()
        if not clean_id:
            return {"status": "error", "message": "simulation_id is required"}
        simulation = self._find_connector_simulation_history_row(clean_id)
        if not isinstance(simulation, dict):
            return {"status": "error", "message": f"simulation '{clean_id}' was not found"}
        provider_name = self._normalize_external_provider_name(provider) or "auto"
        mission_mode_name = self._connector_remediation_policy_normalize_mission_mode(
            mission_mode,
            wildcard_default=True,
        )
        payload = self._connector_execution_contract_entry_payload_from_simulation(
            simulation=simulation,
            provider_name=provider_name,
            compare_target=compare_against_simulation_id,
            promotion=promotion,
            trend_summary=trend_summary,
            remediation_apply=remediation_apply,
        )
        return self._connector_execution_contract_write_entry(
            action=action,
            provider=provider_name,
            mission_mode=mission_mode_name,
            entry_payload=payload,
            source=source,
            reason=reason,
            metadata=metadata if isinstance(metadata, dict) else {},
            event_type="promotion",
        )

    def external_connector_execution_contract_status(
        self,
        *,
        action: str,
        provider: str = "auto",
        mission_mode: str = "",
        include_history: bool = False,
        history_limit: int = 30,
    ) -> Dict[str, Any]:
        action_name = str(action or "").strip().lower()
        if not action_name:
            return {"status": "error", "message": "action is required"}
        provider_name = self._normalize_external_provider_name(provider) or "auto"
        mission_mode_name = self._connector_remediation_policy_normalize_mission_mode(
            mission_mode,
            wildcard_default=False,
        )
        self._load_connector_execution_contract_state()
        scope_candidates = self._connector_remediation_policy_scope_candidates(
            action=action_name,
            provider=provider_name,
            mission_mode=mission_mode_name,
        )
        with self._connector_execution_contract_lock:
            state = (
                self._connector_execution_contract_state
                if isinstance(self._connector_execution_contract_state, dict)
                else self._connector_execution_contract_default_state()
            )
            contracts = state.get("contracts", {}) if isinstance(state.get("contracts"), dict) else {}
            history_rows = state.get("history", []) if isinstance(state.get("history"), list) else []

        entry: Dict[str, Any] = {}
        matched_scope_key = ""
        for scope_key in scope_candidates:
            row = contracts.get(scope_key)
            if isinstance(row, dict):
                entry = dict(row)
                matched_scope_key = scope_key
                break

        payload: Dict[str, Any] = {
            "status": "success",
            "action": action_name,
            "provider": provider_name,
            "mission_mode": mission_mode_name,
            "scope_key": f"{action_name}|{provider_name}|{mission_mode_name}",
            "scope_candidates": scope_candidates,
            "matched_scope_key": matched_scope_key,
            "entry": _to_jsonable(entry),
            "selected_provider": str(entry.get("selected_provider", provider_name)).strip().lower() or provider_name,
            "profile": str(entry.get("profile", "balanced")).strip().lower() or "balanced",
            "candidate_count": int(entry.get("candidate_count", 0) or 0),
            "ready_execute_count": int(entry.get("ready_execute_count", 0) or 0),
            "state_updated_at": str(state.get("updated_at", "")).strip(),
        }
        if include_history:
            bounded_history = max(1, min(int(history_limit), 1000))
            candidate_set = {str(item).strip().lower() for item in scope_candidates if str(item).strip()}
            scoped = [
                _to_jsonable(dict(item))
                for item in history_rows
                if isinstance(item, dict)
                and str(item.get("scope_key", "")).strip().lower() in candidate_set
            ]
            scoped.sort(key=lambda item: int(item.get("event_id", 0) or 0), reverse=True)
            payload["history"] = scoped[:bounded_history]
            payload["history_count"] = min(len(scoped), bounded_history)
            payload["history_total"] = len(scoped)
        return payload

    @staticmethod
    def _connector_execution_contract_diff_summary(
        current_entry: Dict[str, Any],
        target_row: Dict[str, Any],
    ) -> Dict[str, Any]:
        tracked_fields = [
            "simulation_id",
            "compare_against_simulation_id",
            "selected_provider",
            "recommended_provider",
            "profile",
            "controls",
            "recommended_tool_action",
            "recommended_args_patch",
            "fallback_chain",
            "candidate_summary",
            "approval_summary",
            "route_signature",
        ]
        changed_fields: list[Dict[str, Any]] = []
        for key in tracked_fields:
            before = current_entry.get(key)
            after = target_row.get(key)
            if before == after:
                continue
            changed_fields.append(
                {
                    "key": key,
                    "before": _to_jsonable(before),
                    "after": _to_jsonable(after),
                }
            )
        return {
            "selected_provider_changed": str(current_entry.get("selected_provider", "")).strip().lower()
            != str(target_row.get("selected_provider", "")).strip().lower(),
            "before_route_signature": str(current_entry.get("route_signature", "")).strip(),
            "after_route_signature": str(target_row.get("route_signature", "")).strip(),
            "changed_field_count": len(changed_fields),
            "changed_fields": changed_fields[:16],
            "summary": (
                "Selected execution contract event matches the current persisted contract."
                if not changed_fields
                else f"Restoring this contract will change {len(changed_fields)} persisted execution field(s)."
            ),
        }

    def external_connector_execution_contract_restore(
        self,
        *,
        event_id: int = 0,
        action: str = "",
        provider: str = "",
        mission_mode: str = "",
        source: str = "desktop-ui",
        reason: str = "",
        dry_run: bool = True,
        force: bool = False,
    ) -> Dict[str, Any]:
        self._load_connector_execution_contract_state()
        requested_event_id = int(event_id or 0)
        action_filter = str(action or "").strip().lower()
        provider_filter = self._normalize_external_provider_name(provider)
        mission_mode_filter = (
            self._connector_remediation_policy_normalize_mission_mode(mission_mode, wildcard_default=True)
            if str(mission_mode or "").strip()
            else ""
        )
        with self._connector_execution_contract_lock:
            state = (
                self._connector_execution_contract_state
                if isinstance(self._connector_execution_contract_state, dict)
                else self._connector_execution_contract_default_state()
            )
            history_rows = [dict(item) for item in state.get("history", []) if isinstance(item, dict)]
        target_row: Dict[str, Any] = {}
        for row in reversed(history_rows):
            row_event_id = int(row.get("event_id", 0) or 0)
            if requested_event_id and row_event_id != requested_event_id:
                continue
            scope_meta = self._connector_remediation_policy_parse_scope_key(row.get("scope_key", ""))
            row_action = str(row.get("action", scope_meta["action"])).strip().lower()
            row_provider = self._normalize_external_provider_name(row.get("provider", scope_meta["provider"])) or "auto"
            row_mode = self._connector_remediation_policy_normalize_mission_mode(
                row.get("mission_mode", scope_meta["mission_mode"]),
                wildcard_default=True,
            )
            if action_filter and row_action != action_filter:
                continue
            if provider_filter and row_provider != provider_filter:
                continue
            if mission_mode_filter and row_mode != mission_mode_filter:
                continue
            target_row = dict(row)
            target_row["action"] = row_action
            target_row["provider"] = row_provider
            target_row["mission_mode"] = row_mode
            break
        if not target_row:
            return {"status": "error", "message": "matching execution contract history event was not found"}

        current = self.external_connector_execution_contract_status(
            action=str(target_row.get("action", "")).strip().lower(),
            provider=str(target_row.get("provider", "auto")).strip().lower() or "auto",
            mission_mode=str(target_row.get("mission_mode", "*")).strip().lower() or "*",
            include_history=False,
        )
        current_entry = current.get("entry", {}) if isinstance(current.get("entry"), dict) else {}
        diff_summary = self._connector_execution_contract_diff_summary(current_entry, target_row)
        restore_metadata = {
            "restore_event_id": int(target_row.get("event_id", 0) or 0),
            "restore_scope_key": str(target_row.get("scope_key", "")).strip().lower(),
            "restore_created_at": str(target_row.get("created_at", "")).strip(),
            "restore_source": str(target_row.get("updated_by_source", target_row.get("source", ""))).strip().lower(),
            "restore_reason": str(target_row.get("reason", "")).strip(),
            "restore_previous_entry": _to_jsonable(current_entry),
            "restore_diff": _to_jsonable(diff_summary),
        }
        if dry_run:
            return {
                "status": "dry_run",
                "applied": False,
                "event_id": int(target_row.get("event_id", 0) or 0),
                "target": _to_jsonable(target_row),
                "current": _to_jsonable(current_entry),
                "diff": _to_jsonable(diff_summary),
                "message": str(diff_summary.get("summary", "Execution contract restore preview completed.")).strip()
                or "Execution contract restore preview completed.",
            }
        if not force and int(diff_summary.get("changed_field_count", 0) or 0) <= 0:
            return {
                "status": "skip",
                "applied": False,
                "event_id": int(target_row.get("event_id", 0) or 0),
                "target": _to_jsonable(target_row),
                "current": _to_jsonable(current_entry),
                "diff": _to_jsonable(diff_summary),
                "message": "Selected execution contract event already matches the current persisted contract.",
            }
        apply_payload = self._connector_execution_contract_write_entry(
            action=str(target_row.get("action", "")).strip().lower(),
            provider=str(target_row.get("provider", "auto")).strip().lower() or "auto",
            mission_mode=str(target_row.get("mission_mode", "*")).strip().lower() or "*",
            entry_payload=self._connector_execution_contract_entry_payload_from_history_row(target_row),
            source=str(source or "desktop-ui").strip().lower() or "desktop-ui",
            reason=str(reason or "restore_execution_contract_history").strip() or "restore_execution_contract_history",
            metadata=restore_metadata,
            event_type="restore",
        )
        if str(apply_payload.get("status", "")).strip().lower() != "success":
            return apply_payload
        return {
            "status": "applied",
            "applied": True,
            "event_id": int(target_row.get("event_id", 0) or 0),
            "target": _to_jsonable(target_row),
            "current": _to_jsonable(current_entry),
            "diff": _to_jsonable(diff_summary),
            "apply": _to_jsonable(apply_payload),
            "entry": _to_jsonable(apply_payload.get("entry", {})),
            "message": str(
                apply_payload.get("message", "Execution contract restore applied from history event.")
            ).strip()
            or "Execution contract restore applied from history event.",
        }

    def external_connector_preflight_simulation_promote(
        self,
        *,
        simulation_id: str,
        compare_against_simulation_id: str = "",
        source: str = "desktop-ui",
        reason: str = "",
        dry_run: bool = True,
        force: bool = False,
        require_compare: bool = True,
        require_improvement: bool = True,
        mission_mode: str = "",
        limit: int = 320,
        recent_window: int = 16,
        baseline_window: int = 72,
        status: str = "",
    ) -> Dict[str, Any]:
        clean_id = str(simulation_id or "").strip()
        if not clean_id:
            return {"status": "error", "message": "simulation_id is required"}

        simulation = self._find_connector_simulation_history_row(clean_id)
        if not isinstance(simulation, dict):
            return {"status": "error", "message": f"simulation '{clean_id}' was not found"}

        action_name = str(simulation.get("action", "")).strip().lower()
        if not action_name:
            return {"status": "error", "message": "simulation action is missing"}
        provider_name = self._normalize_external_provider_name(
            simulation.get("recommended_provider", simulation.get("requested_provider", "auto"))
        ) or "auto"
        if not self._connector_remediation_policy_external_action_managed(action_name):
            return {
                "status": "blocked",
                "simulation_id": clean_id,
                "applied": False,
                "message": f"action '{action_name}' is not managed by connector remediation policy",
            }

        compare_target = (
            str(compare_against_simulation_id or simulation.get("compare_against_simulation_id", "") or "").strip()
        )
        comparison_payload: Dict[str, Any] = {}
        if compare_target:
            comparison_payload = self.compare_external_connector_preflight_simulations(
                left_id=compare_target,
                right_id=clean_id,
            )
            if str(comparison_payload.get("status", "")).strip().lower() != "success":
                if require_compare and not force:
                    return {
                        "status": "blocked",
                        "simulation_id": clean_id,
                        "compare_against_simulation_id": compare_target,
                        "applied": False,
                        "message": str(
                            comparison_payload.get("message", "compare evidence is required before promotion")
                        ).strip()
                        or "compare evidence is required before promotion",
                    }
                comparison_payload = {}

        mission_mode_name = (
            self._connector_remediation_policy_normalize_mission_mode(mission_mode, wildcard_default=False)
            if str(mission_mode or "").strip()
            else self._connector_remediation_policy_runtime_mission_mode()
        )
        trends = self.external_connector_preflight_simulation_trends(
            limit=limit,
            action=action_name,
            provider=provider_name,
            status=status,
            recent_window=recent_window,
            baseline_window=baseline_window,
        )
        if str(trends.get("status", "")).strip().lower() != "success":
            return {
                "status": "error",
                "simulation_id": clean_id,
                "message": str(trends.get("message", "trend diagnostics failed")).strip() or "trend diagnostics failed",
            }

        promotion = self._external_connector_build_simulation_promotion_preview(
            simulation=simulation,
            comparison=comparison_payload if comparison_payload else None,
            trends=trends,
            require_compare=require_compare,
        )
        gate_reasons = promotion.get("gate_reasons", []) if isinstance(promotion.get("gate_reasons"), list) else []
        if require_improvement and require_compare and compare_target and not bool(promotion.get("compare_improved", False)) and not force:
            if "compare_not_improved" not in gate_reasons:
                gate_reasons = [*gate_reasons, "compare_not_improved"]
                promotion["gate_reasons"] = gate_reasons[:8]
        promotion["compare_against_simulation_id"] = compare_target
        promotion["mission_mode"] = mission_mode_name

        if (not bool(promotion.get("eligible", False)) or gate_reasons) and not force:
            message = str(promotion.get("summary", "simulation is not promotion-ready")).strip() or "simulation is not promotion-ready"
            blocked_payload = {
                "status": "blocked",
                "simulation_id": clean_id,
                "compare_against_simulation_id": compare_target,
                "mission_mode": mission_mode_name,
                "applied": False,
                "promotion": promotion,
                "trend_summary": {
                    "recent": _to_jsonable(trends.get("recent", {})),
                    "deltas": _to_jsonable(trends.get("deltas", {})),
                    "stability": _to_jsonable(trends.get("stability", {})),
                },
                "message": message,
            }
            self._update_connector_simulation_history_row(
                clean_id,
                {
                    "promotion_preview": promotion,
                    "policy_promotion": {
                        "status": "blocked",
                        "applied": False,
                        "message": message,
                        "promotion": _to_jsonable(promotion),
                        "mission_mode": mission_mode_name,
                        "compare_against_simulation_id": compare_target,
                        "updated_at": self._utc_now_iso(),
                    },
                },
            )
            return blocked_payload

        if dry_run:
            message = str(
                promotion.get(
                    "summary",
                    "Dry-run completed; review the promotion preview before persisting policy changes.",
                )
            ).strip() or "Dry-run completed; review the promotion preview before persisting policy changes."
            dry_run_payload = {
                "status": "dry_run",
                "simulation_id": clean_id,
                "compare_against_simulation_id": compare_target,
                "mission_mode": mission_mode_name,
                "applied": False,
                "promotion": promotion,
                "trend_summary": {
                    "recent": _to_jsonable(trends.get("recent", {})),
                    "deltas": _to_jsonable(trends.get("deltas", {})),
                    "stability": _to_jsonable(trends.get("stability", {})),
                },
                "message": message,
            }
            self._update_connector_simulation_history_row(
                clean_id,
                {
                    "promotion_preview": promotion,
                    "policy_promotion": {
                        "status": "dry_run",
                        "applied": False,
                        "message": message,
                        "promotion": _to_jsonable(promotion),
                        "mission_mode": mission_mode_name,
                        "compare_against_simulation_id": compare_target,
                        "updated_at": self._utc_now_iso(),
                    },
                },
            )
            return dry_run_payload

        apply_payload = self.external_connector_remediation_policy_apply(
            action=action_name,
            provider=provider_name,
            mission_mode=mission_mode_name,
            profile=str(promotion.get("recommended_profile", "balanced")),
            controls=promotion.get("recommended_controls", {})
            if isinstance(promotion.get("recommended_controls"), dict)
            else {},
            source=str(source or "desktop-ui").strip().lower() or "desktop-ui",
            reason=str(reason or "promote_simulation_policy").strip() or "promote_simulation_policy",
            metadata={
                "simulation_id": clean_id,
                "compare_against_simulation_id": compare_target,
                "promotion_preview": _to_jsonable(promotion),
                "promoted_from": "connector_preflight_simulation",
                "mission_mode": mission_mode_name,
            },
            use_recommendation=False,
            limit=limit,
            recent_window=recent_window,
            baseline_window=baseline_window,
            status=status,
        )
        if str(apply_payload.get("status", "")).strip().lower() != "success":
            return apply_payload
        execution_contract_payload = self.external_connector_execution_contract_apply_from_simulation(
            simulation_id=clean_id,
            action=action_name,
            provider=provider_name,
            mission_mode=mission_mode_name,
            source=str(source or "desktop-ui").strip().lower() or "desktop-ui",
            reason=str(reason or "promote_simulation_execution_contract").strip()
            or "promote_simulation_execution_contract",
            compare_against_simulation_id=compare_target,
            promotion=promotion,
            trend_summary={
                "recent": _to_jsonable(trends.get("recent", {})),
                "deltas": _to_jsonable(trends.get("deltas", {})),
                "stability": _to_jsonable(trends.get("stability", {})),
            },
            remediation_apply=apply_payload,
            metadata={
                "simulation_id": clean_id,
                "compare_against_simulation_id": compare_target,
                "promotion_preview": _to_jsonable(promotion),
                "promoted_from": "connector_preflight_simulation",
                "mission_mode": mission_mode_name,
            },
        )
        if str(execution_contract_payload.get("status", "")).strip().lower() != "success":
            return execution_contract_payload

        message = str(
            apply_payload.get(
                "message",
                "Simulation promotion applied to connector remediation policy.",
            )
        ).strip() or "Simulation promotion applied to connector remediation policy."
        result = {
            "status": "applied",
            "simulation_id": clean_id,
            "compare_against_simulation_id": compare_target,
            "mission_mode": mission_mode_name,
            "applied": True,
            "promotion": promotion,
            "apply": apply_payload,
            "entry": _to_jsonable(apply_payload.get("entry", {})),
            "execution_contract": _to_jsonable(execution_contract_payload),
            "execution_contract_entry": _to_jsonable(execution_contract_payload.get("entry", {})),
            "trend_summary": {
                "recent": _to_jsonable(trends.get("recent", {})),
                "deltas": _to_jsonable(trends.get("deltas", {})),
                "stability": _to_jsonable(trends.get("stability", {})),
            },
            "message": message,
        }
        self._update_connector_simulation_history_row(
            clean_id,
            {
                "promotion_preview": promotion,
                "policy_promotion": {
                    "status": "applied",
                    "applied": True,
                    "message": message,
                    "promotion": _to_jsonable(promotion),
                    "apply": _to_jsonable(apply_payload),
                    "entry": _to_jsonable(apply_payload.get("entry", {})),
                    "execution_contract": _to_jsonable(execution_contract_payload),
                    "execution_contract_entry": _to_jsonable(execution_contract_payload.get("entry", {})),
                    "mission_mode": mission_mode_name,
                    "compare_against_simulation_id": compare_target,
                    "updated_at": self._utc_now_iso(),
                },
            },
        )
        try:
            self.kernel.telemetry.emit(
                "external.connector_preflight_simulation_promoted",
                {
                    "simulation_id": clean_id,
                    "action": action_name,
                    "provider": provider_name,
                    "mission_mode": mission_mode_name,
                    "promotion_score": float(promotion.get("promotion_score", 0.0) or 0.0),
                    "source": str(source or "desktop-ui"),
                },
            )
        except Exception:
            pass
        return result

    @staticmethod
    def _connector_remediation_policy_normalize_profile(profile: str) -> str:
        clean = str(profile or "").strip().lower()
        if clean in {"strict", "balanced", "aggressive"}:
            return clean
        return "balanced"

    def _connector_remediation_policy_default_controls(self, profile: str) -> Dict[str, Any]:
        clean_profile = self._connector_remediation_policy_normalize_profile(profile)
        presets: Dict[str, Dict[str, Any]] = {
            "strict": {
                "allow_high_risk": False,
                "max_steps": 4,
                "require_compare": True,
                "stop_on_blocked": True,
            },
            "balanced": {
                "allow_high_risk": False,
                "max_steps": 8,
                "require_compare": False,
                "stop_on_blocked": True,
            },
            "aggressive": {
                "allow_high_risk": True,
                "max_steps": 12,
                "require_compare": False,
                "stop_on_blocked": False,
            },
        }
        return dict(presets.get(clean_profile, presets["balanced"]))

    @staticmethod
    def _connector_remediation_policy_normalize_mission_mode(
        mission_mode: Any,
        *,
        wildcard_default: bool = False,
    ) -> str:
        clean = str(mission_mode or "").strip().lower()
        if not clean:
            return "*" if wildcard_default else "stable"
        if clean in {"*", "any", "all", "global", "default"}:
            return "*"
        if clean in {"stable", "normal", "healthy", "baseline"}:
            return "stable"
        if clean in {"degraded", "moderate", "worsening", "elevated", "constrained"}:
            return "degraded"
        if clean in {"critical", "severe", "outage", "emergency"}:
            return "critical"
        return "*" if wildcard_default else "stable"

    @staticmethod
    def _connector_remediation_policy_parse_scope_key(scope_key: Any) -> Dict[str, str]:
        clean = str(scope_key or "").strip().lower()
        if not clean:
            return {"action": "*", "provider": "auto", "mission_mode": "*", "scope_key": ""}
        parts = [item.strip().lower() for item in clean.split("|") if str(item).strip()]
        if len(parts) >= 3:
            action, provider, mission_mode = parts[0], parts[1], parts[2]
            return {
                "action": action or "*",
                "provider": provider or "auto",
                "mission_mode": mission_mode or "*",
                "scope_key": f"{action or '*'}|{provider or 'auto'}|{mission_mode or '*'}",
            }
        if len(parts) == 2:
            action, provider = parts[0], parts[1]
            return {
                "action": action or "*",
                "provider": provider or "auto",
                "mission_mode": "*",
                "scope_key": f"{action or '*'}|{provider or 'auto'}",
            }
        if len(parts) == 1:
            action = parts[0]
            return {
                "action": action or "*",
                "provider": "auto",
                "mission_mode": "*",
                "scope_key": f"{action or '*'}|auto",
            }
        return {"action": "*", "provider": "auto", "mission_mode": "*", "scope_key": clean}

    def _connector_remediation_policy_runtime_mission_mode(self, metadata: Any = None) -> str:
        meta = metadata if isinstance(metadata, dict) else {}
        for key in ("mission_mode", "__mission_mode", "__runtime_mission_mode"):
            if key in meta:
                return self._connector_remediation_policy_normalize_mission_mode(meta.get(key), wildcard_default=False)
        analysis = self._external_connector_mission_analysis_cached(force_refresh=False)
        return self._connector_remediation_policy_normalize_mission_mode(
            analysis.get("mission_mode", "stable") if isinstance(analysis, dict) else "stable",
            wildcard_default=False,
        )

    def _connector_remediation_policy_scope(
        self,
        *,
        action: str,
        provider: str = "auto",
        mission_mode: str = "*",
    ) -> Dict[str, str]:
        clean_action = str(action or "").strip().lower() or "*"
        clean_provider = self._normalize_external_provider_name(provider) or "auto"
        clean_mode = self._connector_remediation_policy_normalize_mission_mode(mission_mode, wildcard_default=True)
        return {
            "action": clean_action,
            "provider": clean_provider,
            "mission_mode": clean_mode,
            "scope_key": f"{clean_action}|{clean_provider}|{clean_mode}",
            "legacy_scope_key": f"{clean_action}|{clean_provider}",
        }

    def _connector_remediation_policy_scope_candidates(
        self,
        *,
        action: str,
        provider: str = "auto",
        mission_mode: str = "*",
    ) -> list[str]:
        scope = self._connector_remediation_policy_scope(action=action, provider=provider, mission_mode=mission_mode)
        action_key = scope["action"]
        provider_key = scope["provider"]
        mode_key = scope["mission_mode"]
        mode_rows = [mode_key, "*"] if mode_key != "*" else ["*"]
        rows: list[str] = []
        for mode in mode_rows:
            rows.extend(
                [
                    f"{action_key}|{provider_key}|{mode}",
                    f"{action_key}|auto|{mode}",
                    f"*|{provider_key}|{mode}",
                    f"*|auto|{mode}",
                ]
            )
        # Backward-compatible key resolution for pre-mission_mode state rows.
        rows.extend(
            [
                f"{action_key}|{provider_key}",
                f"{action_key}|auto",
                f"*|{provider_key}",
                "*|auto",
            ]
        )
        dedup: list[str] = []
        for row in rows:
            clean = str(row or "").strip().lower()
            if clean and clean not in dedup:
                dedup.append(clean)
        return dedup

    def _connector_remediation_policy_sanitize_controls(
        self,
        *,
        profile: str,
        controls: Any = None,
    ) -> Dict[str, Any]:
        base = self._connector_remediation_policy_default_controls(profile)
        if isinstance(controls, dict):
            if "allow_high_risk" in controls:
                base["allow_high_risk"] = bool(controls.get("allow_high_risk", False))
            if "max_steps" in controls:
                try:
                    base["max_steps"] = max(1, min(int(controls.get("max_steps", base["max_steps"]) or base["max_steps"]), 40))
                except Exception:
                    pass
            if "require_compare" in controls:
                base["require_compare"] = bool(controls.get("require_compare", False))
            if "stop_on_blocked" in controls:
                base["stop_on_blocked"] = bool(controls.get("stop_on_blocked", True))
        base["profile"] = self._connector_remediation_policy_normalize_profile(profile)
        return _to_jsonable(base)

    def _connector_remediation_policy_pick_entry_locked(
        self,
        *,
        action: str,
        provider: str,
        mission_mode: str = "*",
    ) -> Dict[str, Any]:
        state = (
            self._connector_remediation_policy_state
            if isinstance(self._connector_remediation_policy_state, dict)
            else {}
        )
        profiles = state.get("profiles", {}) if isinstance(state.get("profiles"), dict) else {}
        candidates = self._connector_remediation_policy_scope_candidates(
            action=action,
            provider=provider,
            mission_mode=mission_mode,
        )
        for scope_key in candidates:
            row = profiles.get(scope_key)
            if isinstance(row, dict):
                parsed_scope = self._connector_remediation_policy_parse_scope_key(scope_key)
                row_payload = dict(row)
                if not str(row_payload.get("scope_key", "")).strip():
                    row_payload["scope_key"] = scope_key
                if not str(row_payload.get("action", "")).strip():
                    row_payload["action"] = parsed_scope["action"]
                if not str(row_payload.get("provider", "")).strip():
                    row_payload["provider"] = parsed_scope["provider"]
                row_payload["mission_mode"] = self._connector_remediation_policy_normalize_mission_mode(
                    row_payload.get("mission_mode", parsed_scope["mission_mode"]),
                    wildcard_default=True,
                )
                return {
                    "entry": row_payload,
                    "scope_key": scope_key,
                    "scope_meta": parsed_scope,
                    "scope_candidates": candidates,
                }
        clean_provider = self._normalize_external_provider_name(provider) or "auto"
        clean_action = str(action or "").strip().lower() or "*"
        clean_mode = self._connector_remediation_policy_normalize_mission_mode(mission_mode, wildcard_default=True)
        if clean_provider in {"", "auto"} and profiles:
            best_row: Optional[Dict[str, Any]] = None
            best_scope = ""
            best_meta: Dict[str, str] = {}
            best_score = -1.0
            for scope_key, raw_row in profiles.items():
                if not isinstance(raw_row, dict):
                    continue
                parsed_scope = self._connector_remediation_policy_parse_scope_key(scope_key)
                row_action = str(parsed_scope.get("action", "*")).strip().lower() or "*"
                row_provider = self._normalize_external_provider_name(parsed_scope.get("provider", "")) or "auto"
                row_mode = self._connector_remediation_policy_normalize_mission_mode(
                    parsed_scope.get("mission_mode", "*"),
                    wildcard_default=True,
                )
                if row_provider in {"", "auto"}:
                    continue
                if row_action not in {clean_action, "*"}:
                    continue
                if row_mode not in {clean_mode, "*"}:
                    continue
                score = 0.0
                if row_action == clean_action:
                    score += 2.0
                if row_mode == clean_mode:
                    score += 2.0
                elif row_mode == "*":
                    score += 1.0
                try:
                    score += max(0.0, min(float(raw_row.get("recommendation_confidence", 0.0) or 0.0), 1.0)) * 0.2
                except Exception:
                    pass
                if score <= best_score:
                    continue
                best_score = score
                best_row = dict(raw_row)
                best_scope = str(scope_key).strip().lower()
                best_meta = parsed_scope
            if isinstance(best_row, dict):
                if not str(best_row.get("scope_key", "")).strip():
                    best_row["scope_key"] = best_scope
                if not str(best_row.get("action", "")).strip():
                    best_row["action"] = best_meta.get("action", clean_action)
                if not str(best_row.get("provider", "")).strip():
                    best_row["provider"] = best_meta.get("provider", "auto")
                best_row["mission_mode"] = self._connector_remediation_policy_normalize_mission_mode(
                    best_row.get("mission_mode", best_meta.get("mission_mode", "*")),
                    wildcard_default=True,
                )
                return {
                    "entry": best_row,
                    "scope_key": best_scope,
                    "scope_meta": best_meta,
                    "scope_candidates": candidates,
                }
        return {
            "entry": {},
            "scope_key": "",
            "scope_meta": self._connector_remediation_policy_scope(
                action=action,
                provider=provider,
                mission_mode=mission_mode,
            ),
            "scope_candidates": candidates,
        }

    @staticmethod
    def _connector_remediation_policy_flag(value: Any, default: bool = False) -> bool:
        if isinstance(value, bool):
            return value
        if isinstance(value, (int, float)):
            return bool(value)
        if isinstance(value, str):
            clean = value.strip().lower()
            if clean in {"1", "true", "yes", "on", "enabled"}:
                return True
            if clean in {"0", "false", "no", "off", "disabled"}:
                return False
        return bool(default)

    @staticmethod
    def _connector_remediation_policy_external_action_managed(action: str) -> bool:
        clean_action = str(action or "").strip().lower()
        if not clean_action or not clean_action.startswith("external_"):
            return False
        if clean_action in DesktopBackendService._CONNECTOR_REMEDIATION_EXTERNAL_EXCLUDED_ACTIONS:
            return False
        return True

    def _connector_remediation_policy_resolve_provider(self, request: ActionRequest) -> str:
        args = request.args if isinstance(request.args, dict) else {}
        metadata = request.metadata if isinstance(request.metadata, dict) else {}
        candidates = [
            args.get("provider"),
            metadata.get("provider"),
            metadata.get("selected_provider"),
            metadata.get("__external_selected_provider"),
            metadata.get("__provider"),
        ]
        for raw in candidates:
            provider = self._normalize_external_provider_name(raw)
            if provider and provider != "auto":
                return provider
        fallback = self._normalize_external_provider_name(args.get("provider", "")) or ""
        if fallback:
            return fallback
        return "auto"

    @staticmethod
    def _connector_remediation_policy_compare_verified(metadata: Any) -> bool:
        if not isinstance(metadata, dict):
            return False
        truthy_keys = (
            "external_compare_verified",
            "connector_compare_verified",
            "remediation_compare_verified",
            "__external_compare_verified",
        )
        for key in truthy_keys:
            if DesktopBackendService._connector_remediation_policy_flag(metadata.get(key), default=False):
                return True
        compare_id = str(
            metadata.get("external_compare_id")
            or metadata.get("connector_compare_id")
            or metadata.get("__external_compare_id")
            or ""
        ).strip()
        return bool(compare_id)

    @staticmethod
    def _connector_remediation_policy_severity_rank(severity: str) -> int:
        clean = str(severity or "").strip().lower()
        if clean in {"critical", "severe", "high"}:
            return 3
        if clean in {"medium", "moderate", "warning"}:
            return 2
        if clean in {"low", "info"}:
            return 1
        return 0

    def _connector_remediation_policy_build_alerts(
        self,
        *,
        action: str,
        provider: str,
        mission_mode: str,
        current_profile: str,
        recommendation_payload: Optional[Dict[str, Any]] = None,
    ) -> list[Dict[str, Any]]:
        recommendation_root = recommendation_payload if isinstance(recommendation_payload, dict) else {}
        recommendation = (
            recommendation_root.get("recommendation", {})
            if isinstance(recommendation_root.get("recommendation"), dict)
            else {}
        )
        trend_summary = (
            recommendation_root.get("trend_summary", {})
            if isinstance(recommendation_root.get("trend_summary"), dict)
            else {}
        )
        deltas = trend_summary.get("deltas", {}) if isinstance(trend_summary.get("deltas"), dict) else {}
        stability = trend_summary.get("stability", {}) if isinstance(trend_summary.get("stability"), dict) else {}

        recommended_profile = self._connector_remediation_policy_normalize_profile(
            str(recommendation.get("profile", current_profile))
        )
        confidence = max(0.0, min(float(recommendation.get("confidence", 0.0) or 0.0), 1.0))
        would_change_profile = bool(recommendation.get("would_change_profile", False))
        ready_delta = float(deltas.get("ready_ratio", 0.0) or 0.0)
        error_delta = float(deltas.get("error_ratio", 0.0) or 0.0)
        confidence_delta = float(deltas.get("confidence", 0.0) or 0.0)
        drift_pressure = max(0.0, min(float(stability.get("drift_pressure", 0.0) or 0.0), 1.0))
        sample_count = max(0, int(trend_summary.get("count", 0) or 0))

        alerts: list[Dict[str, Any]] = []
        if would_change_profile and confidence >= 0.55:
            alerts.append(
                {
                    "id": "policy_profile_drift_detected",
                    "severity": "high" if confidence >= 0.78 else "medium",
                    "message": (
                        f"Recommended profile shifted from '{current_profile}' to '{recommended_profile}' "
                        f"for {action} ({provider}|{mission_mode})."
                    ),
                    "confidence": round(confidence, 6),
                    "recommended_profile": recommended_profile,
                }
            )
        if drift_pressure >= 0.22:
            alerts.append(
                {
                    "id": "execution_drift_pressure_elevated",
                    "severity": "high" if drift_pressure >= 0.35 else "medium",
                    "message": (
                        f"Simulation drift pressure is elevated ({drift_pressure:.3f}); "
                        "execution behavior is diverging from baseline."
                    ),
                    "drift_pressure": round(drift_pressure, 6),
                    "recommended_profile": recommended_profile,
                }
            )
        if error_delta >= 0.1:
            alerts.append(
                {
                    "id": "error_ratio_regression",
                    "severity": "high" if error_delta >= 0.16 else "medium",
                    "message": (
                        f"Error ratio increased by {error_delta:.3f} in the recent connector window."
                    ),
                    "error_delta": round(error_delta, 6),
                    "recommended_profile": recommended_profile,
                }
            )
        if ready_delta <= -0.1:
            alerts.append(
                {
                    "id": "readiness_regression",
                    "severity": "high" if ready_delta <= -0.2 else "medium",
                    "message": (
                        f"Readiness ratio dropped by {abs(ready_delta):.3f} in the recent connector window."
                    ),
                    "ready_delta": round(ready_delta, 6),
                    "recommended_profile": recommended_profile,
                }
            )
        if confidence_delta <= -0.1:
            alerts.append(
                {
                    "id": "routing_confidence_decay",
                    "severity": "medium",
                    "message": (
                        f"Provider routing confidence decayed by {abs(confidence_delta):.3f} versus baseline."
                    ),
                    "confidence_delta": round(confidence_delta, 6),
                    "recommended_profile": recommended_profile,
                }
            )
        if sample_count < 6:
            alerts.append(
                {
                    "id": "low_sample_coverage",
                    "severity": "low",
                    "message": (
                        f"Only {sample_count} simulation samples available; drift alerts may have lower confidence."
                    ),
                    "sample_count": sample_count,
                }
            )
        return alerts[:8]

    def _emit_connector_remediation_drift_alerts(
        self,
        *,
        scope_key: str,
        action: str,
        provider: str,
        mission_mode: str,
        profile: str,
        alerts: list[Dict[str, Any]],
    ) -> None:
        if not alerts:
            return
        signature = "|".join(
            sorted(
                {
                    f"{str(alert.get('id', '')).strip().lower()}:{str(alert.get('severity', '')).strip().lower()}"
                    for alert in alerts
                    if isinstance(alert, dict)
                }
            )
        )
        if not signature:
            return
        now = time.monotonic()
        cache_max = max(40, int(getattr(self, "_connector_remediation_alert_emit_cache_max", 1000) or 1000))
        cooldown_s = max(5.0, float(getattr(self, "_connector_remediation_alert_emit_cooldown_s", 75.0) or 75.0))
        emit_allowed = True
        with self._connector_remediation_alert_lock:
            cache = (
                self._connector_remediation_alert_last_emit
                if isinstance(self._connector_remediation_alert_last_emit, dict)
                else {}
            )
            previous = cache.get(scope_key, {}) if isinstance(cache.get(scope_key), dict) else {}
            if (
                str(previous.get("signature", "")) == signature
                and (now - float(previous.get("at_monotonic", 0.0) or 0.0)) < cooldown_s
            ):
                emit_allowed = False
            if emit_allowed:
                cache[scope_key] = {"signature": signature, "at_monotonic": now}
                if len(cache) > cache_max:
                    ordered = sorted(
                        cache.items(),
                        key=lambda item: float(
                            item[1].get("at_monotonic", 0.0) if isinstance(item[1], dict) else 0.0
                        ),
                    )
                    cache = {key: value for key, value in ordered[-cache_max:]}
                self._connector_remediation_alert_last_emit = cache
        if not emit_allowed:
            return
        highest = "low"
        highest_rank = 0
        for alert in alerts:
            if not isinstance(alert, dict):
                continue
            severity = str(alert.get("severity", "low")).strip().lower() or "low"
            rank = self._connector_remediation_policy_severity_rank(severity)
            if rank >= highest_rank:
                highest_rank = rank
                highest = severity
        try:
            self.kernel.telemetry.emit(
                "external.connector_remediation_policy_drift_alert",
                {
                    "scope_key": scope_key,
                    "action": action,
                    "provider": provider,
                    "mission_mode": mission_mode,
                    "profile": profile,
                    "alert_count": len(alerts),
                    "highest_severity": highest,
                    "alerts": _to_jsonable(alerts[:6]),
                },
            )
        except Exception:
            pass

    def _connector_remediation_policy_runtime_guard(
        self,
        *,
        request: ActionRequest,
        risk_level: str,
    ) -> Optional[ActionResult]:
        clean_action = str(request.action or "").strip().lower()
        if not self._connector_remediation_policy_external_action_managed(clean_action):
            return None
        metadata = request.metadata if isinstance(request.metadata, dict) else {}
        if not isinstance(request.metadata, dict):
            request.metadata = metadata
        provider = self._connector_remediation_policy_resolve_provider(request)
        mission_mode = self._connector_remediation_policy_runtime_mission_mode(metadata)
        status_payload = self.external_connector_remediation_policy_status(
            action=clean_action,
            provider=provider,
            mission_mode=mission_mode,
            include_history=False,
            include_alerts=False,
        )
        if str(status_payload.get("status", "")).strip().lower() != "success":
            return None

        profile = self._connector_remediation_policy_normalize_profile(str(status_payload.get("profile", "balanced")))
        controls = (
            status_payload.get("controls", {})
            if isinstance(status_payload.get("controls"), dict)
            else self._connector_remediation_policy_default_controls(profile)
        )
        controls = self._connector_remediation_policy_sanitize_controls(profile=profile, controls=controls)
        scope_key = str(status_payload.get("matched_scope_key", "") or status_payload.get("scope_key", "")).strip().lower()
        entry = status_payload.get("entry", {}) if isinstance(status_payload.get("entry"), dict) else {}
        alerts = status_payload.get("alerts", []) if isinstance(status_payload.get("alerts"), list) else []

        metadata["__connector_remediation_policy"] = {
            "scope_key": scope_key,
            "action": clean_action,
            "provider": provider,
            "mission_mode": mission_mode,
            "profile": profile,
            "controls": _to_jsonable(controls),
            "alert_count": int(status_payload.get("alert_count", len(alerts)) or len(alerts)),
        }

        target_provider = self._normalize_external_provider_name(entry.get("provider", "")) or ""
        request_provider = self._normalize_external_provider_name(provider)
        if target_provider and target_provider != "auto" and request_provider in {"", "auto"}:
            args = request.args if isinstance(request.args, dict) else {}
            args["provider"] = target_provider
            request.args = args
            provider = target_provider
            try:
                self.kernel.telemetry.emit(
                    "external.connector_remediation_policy_provider_pinned",
                    {
                        "action": clean_action,
                        "scope_key": scope_key,
                        "provider": target_provider,
                        "mission_mode": mission_mode,
                        "profile": profile,
                    },
                )
            except Exception:
                pass

        risk_key = str(risk_level or "").strip().lower()
        allow_high_risk = self._connector_remediation_policy_flag(controls.get("allow_high_risk", False), default=False)
        if risk_key in {"high", "critical"} and not allow_high_risk:
            reason = (
                f"Connector remediation policy '{profile}' blocks high-risk execution "
                f"for action '{clean_action}' (scope={scope_key or 'n/a'})."
            )
            try:
                self.kernel.telemetry.emit(
                    "external.connector_remediation_policy_blocked",
                    {
                        "action": clean_action,
                        "scope_key": scope_key,
                        "provider": provider,
                        "mission_mode": mission_mode,
                        "profile": profile,
                        "reason": "high_risk_blocked",
                        "risk_level": risk_key,
                    },
                )
            except Exception:
                pass
            return ActionResult(
                action=clean_action,
                status="blocked",
                error=reason,
                output={
                    "status": "error",
                    "policy_required": True,
                    "error_code": "connector_policy_high_risk_blocked",
                    "message": reason,
                    "remediation_policy": _to_jsonable(metadata.get("__connector_remediation_policy", {})),
                    "alerts": _to_jsonable(alerts[:6]),
                },
            )

        require_compare = self._connector_remediation_policy_flag(controls.get("require_compare", False), default=False)
        compare_override = self._connector_remediation_policy_flag(
            metadata.get("external_compare_override", metadata.get("__external_compare_override", False)),
            default=False,
        )
        require_compare_for_action = (
            self._required_permission_for_action(
                action=clean_action,
                definition=None,
                risk_level=risk_key,
            )
            == "write"
        )
        if require_compare and require_compare_for_action and not compare_override:
            compare_verified = self._connector_remediation_policy_compare_verified(metadata)
            if not compare_verified:
                reason = (
                    f"Connector remediation policy '{profile}' requires compare verification before "
                    f"executing '{clean_action}' (scope={scope_key or 'n/a'})."
                )
                try:
                    self.kernel.telemetry.emit(
                        "external.connector_remediation_policy_blocked",
                        {
                            "action": clean_action,
                            "scope_key": scope_key,
                            "provider": provider,
                            "mission_mode": mission_mode,
                            "profile": profile,
                            "reason": "compare_verification_required",
                        },
                    )
                except Exception:
                    pass
                return ActionResult(
                    action=clean_action,
                    status="blocked",
                    error=reason,
                    output={
                        "status": "error",
                        "policy_required": True,
                        "error_code": "connector_policy_compare_required",
                        "message": reason,
                        "remediation_policy": _to_jsonable(metadata.get("__connector_remediation_policy", {})),
                        "alerts": _to_jsonable(alerts[:6]),
                    },
                )
        return None

    @staticmethod
    def _connector_remediation_autotune_default_state() -> Dict[str, Any]:
        return {
            "runs": 0,
            "applied": 0,
            "last_status": "",
            "last_reason": "",
            "last_run_at": "",
            "last_apply_at": "",
            "last_scope_key": "",
            "last_run_monotonic": 0.0,
            "last_apply_by_scope": {},
            "history": [],
        }

    def _connector_remediation_autotune_state_locked(self) -> Dict[str, Any]:
        state = (
            self._connector_remediation_policy_state
            if isinstance(self._connector_remediation_policy_state, dict)
            else {}
        )
        default = self._connector_remediation_autotune_default_state()
        raw = state.get("autotune", {}) if isinstance(state.get("autotune"), dict) else {}
        history_limit = max(
            20,
            int(getattr(self, "_connector_remediation_autotune_history_max", 240) or 240),
        )

        last_apply_map_raw = (
            raw.get("last_apply_by_scope", {})
            if isinstance(raw.get("last_apply_by_scope"), dict)
            else {}
        )
        last_apply_map: Dict[str, float] = {}
        for key, value in last_apply_map_raw.items():
            clean_key = str(key or "").strip().lower()
            if not clean_key:
                continue
            try:
                last_apply_map[clean_key] = max(0.0, float(value or 0.0))
            except Exception:
                continue

        history_rows_raw = raw.get("history", []) if isinstance(raw.get("history"), list) else []
        history_rows = [_to_jsonable(dict(item)) for item in history_rows_raw if isinstance(item, dict)]
        if len(history_rows) > history_limit:
            history_rows = history_rows[-history_limit:]

        sanitized = {
            **default,
            "runs": max(0, int(raw.get("runs", default["runs"]) or default["runs"])),
            "applied": max(0, int(raw.get("applied", default["applied"]) or default["applied"])),
            "last_status": str(raw.get("last_status", default["last_status"]) or "").strip().lower(),
            "last_reason": str(raw.get("last_reason", default["last_reason"]) or "").strip(),
            "last_run_at": str(raw.get("last_run_at", default["last_run_at"]) or "").strip(),
            "last_apply_at": str(raw.get("last_apply_at", default["last_apply_at"]) or "").strip(),
            "last_scope_key": str(raw.get("last_scope_key", default["last_scope_key"]) or "").strip().lower(),
            "last_run_monotonic": max(
                0.0,
                float(raw.get("last_run_monotonic", default["last_run_monotonic"]) or default["last_run_monotonic"]),
            ),
            "last_apply_by_scope": last_apply_map,
            "history": history_rows,
        }
        state["autotune"] = sanitized
        self._connector_remediation_policy_state = state
        return sanitized

    def _connector_remediation_policy_autotune_maybe(
        self,
        *,
        action: str,
        provider: str,
        mission_mode: str,
        source: str,
        reason: str,
    ) -> None:
        if not bool(getattr(self, "_connector_remediation_autotune_enabled", True)):
            return
        try:
            self.external_connector_remediation_policy_autotune(
                action=action,
                provider=provider,
                mission_mode=mission_mode,
                source=source,
                reason=reason,
                force=False,
                dry_run=False,
            )
        except Exception as exc:  # noqa: BLE001
            try:
                self.kernel.telemetry.emit(
                    "external.connector_remediation_policy_autotune_error",
                    {
                        "action": str(action or "").strip().lower(),
                        "provider": str(provider or "").strip().lower(),
                        "mission_mode": str(mission_mode or "").strip().lower(),
                        "source": str(source or "").strip().lower(),
                        "reason": str(reason or "").strip(),
                        "message": str(exc),
                    },
                )
            except Exception:
                pass

    def external_connector_remediation_policy_autotune_status(
        self,
        *,
        limit: int = 40,
    ) -> Dict[str, Any]:
        self._load_connector_remediation_policy_state()
        bounded_limit = max(1, min(int(limit), 1000))
        with self._connector_remediation_policy_lock:
            state = (
                self._connector_remediation_policy_state
                if isinstance(self._connector_remediation_policy_state, dict)
                else {}
            )
            autotune = self._connector_remediation_autotune_state_locked()
            history = autotune.get("history", []) if isinstance(autotune.get("history"), list) else []
            items = [_to_jsonable(dict(item)) for item in history[-bounded_limit:]]
            items.reverse()
            enabled = bool(getattr(self, "_connector_remediation_autotune_enabled", True))
            interval_s = max(
                3.0,
                float(getattr(self, "_connector_remediation_autotune_interval_s", 90.0) or 90.0),
            )
            now_monotonic = time.monotonic()
            last_run_monotonic = max(0.0, float(autotune.get("last_run_monotonic", 0.0) or 0.0))
            elapsed_s = max(0.0, now_monotonic - last_run_monotonic) if last_run_monotonic > 0 else interval_s
            cooldown_remaining_s = max(0.0, interval_s - elapsed_s) if enabled else 0.0

            payload = {
                "status": "success",
                "enabled": enabled,
                "config": {
                    "interval_s": interval_s,
                    "apply_cooldown_s": max(
                        5.0,
                        float(
                            getattr(self, "_connector_remediation_autotune_apply_cooldown_s", 220.0)
                            or 220.0
                        ),
                    ),
                    "min_confidence": max(
                        0.0,
                        min(
                            float(
                                getattr(self, "_connector_remediation_autotune_min_confidence", 0.66)
                                or 0.66
                            ),
                            1.0,
                        ),
                    ),
                    "min_samples": max(
                        1,
                        int(getattr(self, "_connector_remediation_autotune_min_samples", 12) or 12),
                    ),
                    "min_drift_pressure": max(
                        0.0,
                        min(
                            float(
                                getattr(self, "_connector_remediation_autotune_min_drift_pressure", 0.22)
                                or 0.22
                            ),
                            1.0,
                        ),
                    ),
                },
                "state_updated_at": str(state.get("updated_at", "")).strip(),
                "runs": int(autotune.get("runs", 0) or 0),
                "applied": int(autotune.get("applied", 0) or 0),
                "last_status": str(autotune.get("last_status", "") or "").strip().lower(),
                "last_reason": str(autotune.get("last_reason", "") or "").strip(),
                "last_run_at": str(autotune.get("last_run_at", "") or "").strip(),
                "last_apply_at": str(autotune.get("last_apply_at", "") or "").strip(),
                "last_scope_key": str(autotune.get("last_scope_key", "") or "").strip().lower(),
                "cooldown_remaining_s": round(cooldown_remaining_s, 6),
                "history": items,
                "history_count": len(items),
                "history_total": len(history),
            }
        return payload

    def external_connector_remediation_policy_autotune(
        self,
        *,
        action: str,
        provider: str = "auto",
        mission_mode: str = "",
        source: str = "desktop-ui",
        reason: str = "",
        force: bool = False,
        dry_run: bool = False,
        limit: int = 320,
        recent_window: int = 16,
        baseline_window: int = 72,
        status: str = "",
    ) -> Dict[str, Any]:
        clean_action = str(action or "").strip().lower()
        if not clean_action:
            return {"status": "error", "message": "action is required"}
        clean_provider = self._normalize_external_provider_name(provider) or "auto"
        clean_mission_mode = (
            self._connector_remediation_policy_normalize_mission_mode(mission_mode, wildcard_default=False)
            if str(mission_mode or "").strip()
            else self._connector_remediation_policy_runtime_mission_mode()
        )
        clean_source = str(source or "desktop-ui").strip().lower() or "desktop-ui"
        clean_reason = str(reason or "").strip() or "autotune"
        now_iso = self._utc_now_iso()
        now_monotonic = time.monotonic()
        with self._connector_remediation_autotune_lock:
            self._load_connector_remediation_policy_state()
            with self._connector_remediation_policy_lock:
                autotune = self._connector_remediation_autotune_state_locked()
                enabled = bool(getattr(self, "_connector_remediation_autotune_enabled", True))
                interval_s = max(
                    3.0,
                    float(getattr(self, "_connector_remediation_autotune_interval_s", 90.0) or 90.0),
                )
                last_run_monotonic = max(0.0, float(autotune.get("last_run_monotonic", 0.0) or 0.0))
                if not force:
                    if not enabled:
                        return {
                            "status": "skip",
                            "applied": False,
                            "reason": "autotune_disabled",
                            "action": clean_action,
                            "provider": clean_provider,
                            "mission_mode": clean_mission_mode,
                        }
                    elapsed = (now_monotonic - last_run_monotonic) if last_run_monotonic > 0 else interval_s
                    if elapsed < interval_s:
                        return {
                            "status": "skip",
                            "applied": False,
                            "reason": "interval_cooldown",
                            "action": clean_action,
                            "provider": clean_provider,
                            "mission_mode": clean_mission_mode,
                            "cooldown_remaining_s": round(interval_s - elapsed, 6),
                        }

        recommendation_payload = self.external_connector_remediation_policy_recommendation(
            action=clean_action,
            provider=clean_provider,
            mission_mode=clean_mission_mode,
            limit=limit,
            recent_window=recent_window,
            baseline_window=baseline_window,
            status=status,
        )
        if str(recommendation_payload.get("status", "")).strip().lower() != "success":
            with self._connector_remediation_policy_lock:
                autotune = self._connector_remediation_autotune_state_locked()
                history_rows = autotune.get("history", []) if isinstance(autotune.get("history"), list) else []
                history_rows.append(
                    {
                        "run_at": now_iso,
                        "status": "error",
                        "reason": "recommendation_failed",
                        "action": clean_action,
                        "provider": clean_provider,
                        "mission_mode": clean_mission_mode,
                        "message": str(recommendation_payload.get("message", "recommendation failed")).strip(),
                        "source": clean_source,
                    }
                )
                history_limit = max(
                    20,
                    int(getattr(self, "_connector_remediation_autotune_history_max", 240) or 240),
                )
                if len(history_rows) > history_limit:
                    history_rows = history_rows[-history_limit:]
                autotune["history"] = history_rows
                autotune["runs"] = int(autotune.get("runs", 0) or 0) + 1
                autotune["last_status"] = "error"
                autotune["last_reason"] = "recommendation_failed"
                autotune["last_run_at"] = now_iso
                autotune["last_scope_key"] = f"{clean_action}|{clean_provider}|{clean_mission_mode}"
                autotune["last_run_monotonic"] = now_monotonic
                self._connector_remediation_policy_state["autotune"] = autotune
                self._connector_remediation_policy_dirty = True
            self._persist_connector_remediation_policy_state(force=False)
            return {
                "status": "error",
                "applied": False,
                "reason": "recommendation_failed",
                "action": clean_action,
                "provider": clean_provider,
                "mission_mode": clean_mission_mode,
                "message": str(recommendation_payload.get("message", "recommendation failed")).strip(),
            }

        recommendation = (
            recommendation_payload.get("recommendation", {})
            if isinstance(recommendation_payload.get("recommendation"), dict)
            else {}
        )
        trend_summary = (
            recommendation_payload.get("trend_summary", {})
            if isinstance(recommendation_payload.get("trend_summary"), dict)
            else {}
        )
        stability = trend_summary.get("stability", {}) if isinstance(trend_summary.get("stability"), dict) else {}
        current = recommendation_payload.get("current", {}) if isinstance(recommendation_payload.get("current"), dict) else {}
        current_profile = self._connector_remediation_policy_normalize_profile(str(current.get("profile", "balanced")))
        current_controls = current.get("controls", {}) if isinstance(current.get("controls"), dict) else {}
        recommended_profile = self._connector_remediation_policy_normalize_profile(
            str(recommendation.get("profile", current_profile))
        )
        recommended_controls = recommendation.get("controls", {}) if isinstance(recommendation.get("controls"), dict) else {}
        confidence = max(0.0, min(float(recommendation.get("confidence", 0.0) or 0.0), 1.0))
        sample_count = max(0, int(trend_summary.get("count", 0) or 0))
        drift_pressure = max(0.0, min(float(stability.get("drift_pressure", 0.0) or 0.0), 1.0))
        normalized_current_controls = self._connector_remediation_policy_sanitize_controls(
            profile=current_profile,
            controls=current_controls,
        )
        normalized_recommended_controls = self._connector_remediation_policy_sanitize_controls(
            profile=recommended_profile,
            controls=recommended_controls,
        )
        profile_change = bool(recommended_profile != current_profile)
        controls_change = bool(
            json.dumps(_to_jsonable(normalized_current_controls), sort_keys=True)
            != json.dumps(_to_jsonable(normalized_recommended_controls), sort_keys=True)
        )

        min_confidence = max(
            0.0,
            min(float(getattr(self, "_connector_remediation_autotune_min_confidence", 0.66) or 0.66), 1.0),
        )
        min_samples = max(1, int(getattr(self, "_connector_remediation_autotune_min_samples", 12) or 12))
        min_drift_pressure = max(
            0.0,
            min(float(getattr(self, "_connector_remediation_autotune_min_drift_pressure", 0.22) or 0.22), 1.0),
        )
        apply_cooldown_s = max(
            5.0,
            float(getattr(self, "_connector_remediation_autotune_apply_cooldown_s", 220.0) or 220.0),
        )
        scope_key = f"{clean_action}|{clean_provider}|{clean_mission_mode}"
        decision_reason = "apply"
        would_apply = True
        if sample_count < min_samples and not force:
            would_apply = False
            decision_reason = "insufficient_samples"
        elif confidence < min_confidence and not force:
            would_apply = False
            decision_reason = "low_confidence"
        elif not (profile_change or controls_change) and not force:
            would_apply = False
            decision_reason = "no_policy_change"
        elif clean_mission_mode == "stable" and drift_pressure < min_drift_pressure and not force:
            would_apply = False
            decision_reason = "low_drift_pressure"

        cooldown_remaining_s = 0.0
        if would_apply and not force:
            with self._connector_remediation_policy_lock:
                autotune_state = self._connector_remediation_autotune_state_locked()
                last_apply_map = (
                    autotune_state.get("last_apply_by_scope", {})
                    if isinstance(autotune_state.get("last_apply_by_scope"), dict)
                    else {}
                )
                last_apply_monotonic = max(0.0, float(last_apply_map.get(scope_key, 0.0) or 0.0))
            if last_apply_monotonic > 0.0 and (now_monotonic - last_apply_monotonic) < apply_cooldown_s:
                would_apply = False
                decision_reason = "apply_cooldown"
                cooldown_remaining_s = apply_cooldown_s - (now_monotonic - last_apply_monotonic)

        apply_payload: Dict[str, Any] = {}
        applied = False
        result_status = "skip"
        if would_apply:
            if dry_run:
                result_status = "dry_run"
            else:
                apply_payload = self.external_connector_remediation_policy_apply(
                    action=clean_action,
                    provider=clean_provider,
                    mission_mode=clean_mission_mode,
                    profile="",
                    controls=None,
                    source=clean_source,
                    reason=f"autotune:{clean_reason}",
                    metadata={
                        "autotune": {
                            "source": clean_source,
                            "reason": clean_reason,
                            "confidence": round(confidence, 6),
                            "sample_count": int(sample_count),
                            "drift_pressure": round(drift_pressure, 6),
                            "profile_change": bool(profile_change),
                            "controls_change": bool(controls_change),
                        }
                    },
                    use_recommendation=True,
                    limit=limit,
                    recent_window=recent_window,
                    baseline_window=baseline_window,
                    status=status,
                )
                applied = str(apply_payload.get("status", "")).strip().lower() == "success"
                result_status = "applied" if applied else "error"
                if not applied and not decision_reason:
                    decision_reason = "apply_failed"
        else:
            result_status = "skip"

        with self._connector_remediation_policy_lock:
            autotune = self._connector_remediation_autotune_state_locked()
            runs = int(autotune.get("runs", 0) or 0) + 1
            applied_count = int(autotune.get("applied", 0) or 0) + (1 if applied else 0)
            history_rows = autotune.get("history", []) if isinstance(autotune.get("history"), list) else []
            history_rows.append(
                {
                    "run_at": now_iso,
                    "status": result_status,
                    "reason": decision_reason,
                    "action": clean_action,
                    "provider": clean_provider,
                    "mission_mode": clean_mission_mode,
                    "scope_key": scope_key,
                    "source": clean_source,
                    "dry_run": bool(dry_run),
                    "force": bool(force),
                    "confidence": round(confidence, 6),
                    "sample_count": int(sample_count),
                    "drift_pressure": round(drift_pressure, 6),
                    "profile_change": bool(profile_change),
                    "controls_change": bool(controls_change),
                    "profile_from": current_profile,
                    "profile_to": recommended_profile,
                }
            )
            history_limit = max(
                20,
                int(getattr(self, "_connector_remediation_autotune_history_max", 240) or 240),
            )
            if len(history_rows) > history_limit:
                history_rows = history_rows[-history_limit:]

            last_apply_map = (
                autotune.get("last_apply_by_scope", {})
                if isinstance(autotune.get("last_apply_by_scope"), dict)
                else {}
            )
            if applied:
                last_apply_map[scope_key] = now_monotonic
                autotune["last_apply_at"] = now_iso
                autotune["last_scope_key"] = scope_key

            autotune.update(
                {
                    "runs": runs,
                    "applied": applied_count,
                    "last_status": result_status,
                    "last_reason": decision_reason,
                    "last_run_at": now_iso,
                    "last_run_monotonic": now_monotonic,
                    "last_apply_by_scope": last_apply_map,
                    "history": history_rows,
                }
            )
            self._connector_remediation_policy_state["autotune"] = autotune
            self._connector_remediation_policy_dirty = True
        self._persist_connector_remediation_policy_state(force=False)
        try:
            self.kernel.telemetry.emit(
                "external.connector_remediation_policy_autotuned",
                {
                    "status": result_status,
                    "reason": decision_reason,
                    "action": clean_action,
                    "provider": clean_provider,
                    "mission_mode": clean_mission_mode,
                    "scope_key": scope_key,
                    "source": clean_source,
                    "dry_run": bool(dry_run),
                    "force": bool(force),
                    "applied": bool(applied),
                    "confidence": round(confidence, 6),
                    "sample_count": int(sample_count),
                    "drift_pressure": round(drift_pressure, 6),
                    "profile_from": current_profile,
                    "profile_to": recommended_profile,
                    "profile_change": bool(profile_change),
                    "controls_change": bool(controls_change),
                },
            )
        except Exception:
            pass

        payload: Dict[str, Any] = {
            "status": result_status,
            "applied": bool(applied),
            "reason": decision_reason,
            "action": clean_action,
            "provider": clean_provider,
            "mission_mode": clean_mission_mode,
            "scope_key": scope_key,
            "source": clean_source,
            "dry_run": bool(dry_run),
            "force": bool(force),
            "decision": {
                "confidence": round(confidence, 6),
                "sample_count": int(sample_count),
                "drift_pressure": round(drift_pressure, 6),
                "profile_change": bool(profile_change),
                "controls_change": bool(controls_change),
                "profile_from": current_profile,
                "profile_to": recommended_profile,
                "would_apply": bool(would_apply),
                "cooldown_remaining_s": round(max(0.0, cooldown_remaining_s), 6),
            },
            "recommendation": _to_jsonable(recommendation),
            "trend_summary": _to_jsonable(trend_summary),
        }
        if apply_payload:
            payload["apply"] = _to_jsonable(apply_payload)
        return payload

    def external_connector_remediation_policy_autotune_scan(
        self,
        *,
        max_pairs: int = 8,
        mission_mode: str = "",
        source: str = "desktop-ui",
        reason: str = "scan",
        force: bool = False,
        dry_run: bool = True,
        limit: int = 320,
        recent_window: int = 16,
        baseline_window: int = 72,
        status: str = "",
    ) -> Dict[str, Any]:
        self._load_connector_simulation_history()
        bounded_pairs = max(1, min(int(max_pairs), 60))
        clean_mission_mode = (
            self._connector_remediation_policy_normalize_mission_mode(mission_mode, wildcard_default=False)
            if str(mission_mode or "").strip()
            else self._connector_remediation_policy_runtime_mission_mode()
        )
        with self._connector_simulation_history_lock:
            rows = list(self._connector_simulation_history)
        rows.sort(
            key=lambda item: str(item.get("created_at", "")) if isinstance(item, dict) else "",
            reverse=True,
        )
        pairs: list[tuple[str, str]] = []
        seen: set[str] = set()
        for row in rows:
            if not isinstance(row, dict):
                continue
            action = str(row.get("action", "")).strip().lower()
            provider = self._normalize_external_provider_name(
                row.get("recommended_provider", row.get("requested_provider", row.get("provider", "auto")))
            ) or "auto"
            if not self._connector_remediation_policy_external_action_managed(action):
                continue
            key = f"{action}|{provider}"
            if key in seen:
                continue
            seen.add(key)
            pairs.append((action, provider))
            if len(pairs) >= bounded_pairs:
                break
        if not pairs:
            return {
                "status": "skip",
                "message": "No connector simulation pairs are available for autotune scan.",
                "count": 0,
                "items": [],
            }
        outputs: list[Dict[str, Any]] = []
        applied_count = 0
        for action_name, provider_name in pairs:
            row = self.external_connector_remediation_policy_autotune(
                action=action_name,
                provider=provider_name,
                mission_mode=clean_mission_mode,
                source=source,
                reason=f"{reason}:scan",
                force=force,
                dry_run=dry_run,
                limit=limit,
                recent_window=recent_window,
                baseline_window=baseline_window,
                status=status,
            )
            outputs.append(_to_jsonable(row))
            if bool(row.get("applied", False)):
                applied_count += 1
        return {
            "status": "success",
            "mission_mode": clean_mission_mode,
            "count": len(outputs),
            "applied_count": applied_count,
            "dry_run": bool(dry_run),
            "force": bool(force),
            "limit": int(limit),
            "recent_window": int(recent_window),
            "baseline_window": int(baseline_window),
            "status_filter": str(status or "").strip(),
            "items": outputs,
        }

    def external_connector_remediation_policies(
        self,
        *,
        limit: int = 180,
        action: str = "",
        provider: str = "",
        mission_mode: str = "",
        include_history: bool = False,
        history_limit: int = 40,
    ) -> Dict[str, Any]:
        self._load_connector_remediation_policy_state()
        bounded = max(1, min(int(limit), 5000))
        bounded_history = max(1, min(int(history_limit), 4000))
        action_filter = str(action or "").strip().lower()
        provider_filter = self._normalize_external_provider_name(provider)
        mission_mode_filter = ""
        if str(mission_mode or "").strip():
            mission_mode_filter = self._connector_remediation_policy_normalize_mission_mode(
                mission_mode,
                wildcard_default=True,
            )

        with self._connector_remediation_policy_lock:
            state = (
                self._connector_remediation_policy_state
                if isinstance(self._connector_remediation_policy_state, dict)
                else {}
            )
            profiles = state.get("profiles", {}) if isinstance(state.get("profiles"), dict) else {}
            rows = [dict(item) for item in profiles.values() if isinstance(item, dict)]
            history_rows_raw = state.get("history", []) if isinstance(state.get("history"), list) else []
            history_rows = [dict(item) for item in history_rows_raw if isinstance(item, dict)]
            updated_at = str(state.get("updated_at", "")).strip()

        filtered: list[Dict[str, Any]] = []
        for row in rows:
            scope_meta = self._connector_remediation_policy_parse_scope_key(row.get("scope_key", ""))
            row_action = str(row.get("action", scope_meta["action"])).strip().lower()
            row_provider = self._normalize_external_provider_name(
                row.get("provider", scope_meta["provider"])
            ) or "auto"
            row_mode = self._connector_remediation_policy_normalize_mission_mode(
                row.get("mission_mode", scope_meta["mission_mode"]),
                wildcard_default=True,
            )
            if action_filter and row_action != action_filter:
                continue
            if provider_filter and row_provider != provider_filter:
                continue
            if mission_mode_filter and row_mode != mission_mode_filter:
                continue
            row_payload = dict(row)
            if not str(row_payload.get("scope_key", "")).strip():
                row_payload["scope_key"] = scope_meta["scope_key"]
            row_payload["action"] = row_action
            row_payload["provider"] = row_provider
            row_payload["mission_mode"] = row_mode
            filtered.append(_to_jsonable(row_payload))

        filtered.sort(key=lambda item: str(item.get("updated_at", "")), reverse=True)
        items = filtered[:bounded]
        payload: Dict[str, Any] = {
            "status": "success",
            "items": items,
            "count": len(items),
            "total": len(filtered),
            "state_updated_at": updated_at,
            "filters": {
                "action": action_filter,
                "provider": provider_filter,
                "mission_mode": mission_mode_filter,
            },
        }
        if include_history:
            filtered_history: list[Dict[str, Any]] = []
            for row in history_rows:
                scope_meta = self._connector_remediation_policy_parse_scope_key(row.get("scope_key", ""))
                row_action = str(row.get("action", scope_meta["action"])).strip().lower()
                row_provider = self._normalize_external_provider_name(
                    row.get("provider", scope_meta["provider"])
                ) or "auto"
                row_mode = self._connector_remediation_policy_normalize_mission_mode(
                    row.get("mission_mode", scope_meta["mission_mode"]),
                    wildcard_default=True,
                )
                if action_filter and row_action != action_filter:
                    continue
                if provider_filter and row_provider != provider_filter:
                    continue
                if mission_mode_filter and row_mode != mission_mode_filter:
                    continue
                row_payload = dict(row)
                row_payload["action"] = row_action
                row_payload["provider"] = row_provider
                row_payload["mission_mode"] = row_mode
                filtered_history.append(row_payload)
            filtered_history.sort(
                key=lambda item: (
                    int(item.get("event_id", 0) or 0),
                    str(item.get("created_at", "")),
                ),
                reverse=True,
            )
            payload["history"] = _to_jsonable(filtered_history[:bounded_history])
            payload["history_count"] = min(len(filtered_history), bounded_history)
            payload["history_total"] = len(filtered_history)
        return payload

    def external_connector_remediation_policy_status(
        self,
        *,
        action: str,
        provider: str = "auto",
        mission_mode: str = "",
        include_history: bool = False,
        history_limit: int = 30,
        include_alerts: bool = True,
    ) -> Dict[str, Any]:
        clean_action = str(action or "").strip().lower()
        if not clean_action:
            return {"status": "error", "message": "action is required"}

        self._load_connector_remediation_policy_state()
        clean_provider = self._normalize_external_provider_name(provider) or "auto"
        clean_mission_mode = (
            self._connector_remediation_policy_normalize_mission_mode(mission_mode, wildcard_default=False)
            if str(mission_mode or "").strip()
            else self._connector_remediation_policy_runtime_mission_mode()
        )
        with self._connector_remediation_policy_lock:
            picked = self._connector_remediation_policy_pick_entry_locked(
                action=clean_action,
                provider=clean_provider,
                mission_mode=clean_mission_mode,
            )
            entry = picked.get("entry", {}) if isinstance(picked.get("entry"), dict) else {}
            state = (
                self._connector_remediation_policy_state
                if isinstance(self._connector_remediation_policy_state, dict)
                else {}
            )
            history_rows_raw = state.get("history", []) if isinstance(state.get("history"), list) else []
            history_rows = [dict(item) for item in history_rows_raw if isinstance(item, dict)]
            state_updated_at = str(state.get("updated_at", "")).strip()

        active_profile = self._connector_remediation_policy_normalize_profile(str(entry.get("profile", "balanced")))
        active_controls = self._connector_remediation_policy_sanitize_controls(
            profile=active_profile,
            controls=entry.get("controls", {}),
        )
        scope = self._connector_remediation_policy_scope(
            action=clean_action,
            provider=clean_provider,
            mission_mode=clean_mission_mode,
        )
        payload: Dict[str, Any] = {
            "status": "success",
            "action": clean_action,
            "provider": clean_provider,
            "mission_mode": clean_mission_mode,
            "scope_key": scope["scope_key"],
            "scope_candidates": picked.get("scope_candidates", []),
            "matched_scope_key": str(picked.get("scope_key", "")).strip().lower(),
            "profile": active_profile,
            "controls": active_controls,
            "entry": _to_jsonable(entry) if entry else {},
            "state_updated_at": state_updated_at,
            "defaults": {
                "strict": self._connector_remediation_policy_default_controls("strict"),
                "balanced": self._connector_remediation_policy_default_controls("balanced"),
                "aggressive": self._connector_remediation_policy_default_controls("aggressive"),
            },
        }
        if include_history:
            bounded_history = max(1, min(int(history_limit), 3000))
            candidates = set(
                self._connector_remediation_policy_scope_candidates(
                    action=clean_action,
                    provider=clean_provider,
                    mission_mode=clean_mission_mode,
                )
            )
            scoped_history: list[Dict[str, Any]] = []
            for row in history_rows:
                scope_meta = self._connector_remediation_policy_parse_scope_key(row.get("scope_key", ""))
                scope_key = str(row.get("scope_key", scope_meta["scope_key"])).strip().lower()
                if scope_key not in candidates:
                    continue
                row_payload = dict(row)
                row_payload["mission_mode"] = self._connector_remediation_policy_normalize_mission_mode(
                    row_payload.get("mission_mode", scope_meta["mission_mode"]),
                    wildcard_default=True,
                )
                scoped_history.append(row_payload)
            scoped_history.sort(
                key=lambda item: (
                    int(item.get("event_id", 0) or 0),
                    str(item.get("created_at", "")),
                ),
                reverse=True,
            )
            payload["history"] = _to_jsonable(scoped_history[:bounded_history])
            payload["history_count"] = min(len(scoped_history), bounded_history)
            payload["history_total"] = len(scoped_history)
        if include_alerts:
            recommendation = self.external_connector_remediation_policy_recommendation(
                action=clean_action,
                provider=clean_provider,
                mission_mode=clean_mission_mode,
                limit=280,
                recent_window=14,
                baseline_window=56,
                status="",
            )
            if str(recommendation.get("status", "")).strip().lower() == "success":
                alerts = self._connector_remediation_policy_build_alerts(
                    action=clean_action,
                    provider=clean_provider,
                    mission_mode=clean_mission_mode,
                    current_profile=active_profile,
                    recommendation_payload=recommendation,
                )
            else:
                alerts = []
            payload["alerts"] = _to_jsonable(alerts)
            payload["alert_count"] = len(alerts)
            if alerts:
                highest = "low"
                highest_rank = 0
                for alert in alerts:
                    if not isinstance(alert, dict):
                        continue
                    severity = str(alert.get("severity", "low")).strip().lower() or "low"
                    rank = self._connector_remediation_policy_severity_rank(severity)
                    if rank >= highest_rank:
                        highest_rank = rank
                        highest = severity
                payload["highest_alert_severity"] = highest
                self._emit_connector_remediation_drift_alerts(
                    scope_key=str(payload.get("matched_scope_key", "") or payload.get("scope_key", "")),
                    action=clean_action,
                    provider=clean_provider,
                    mission_mode=clean_mission_mode,
                    profile=active_profile,
                    alerts=alerts,
                )
            else:
                payload["highest_alert_severity"] = "none"
        return payload

    def external_connector_remediation_policy_recommendation(
        self,
        *,
        action: str,
        provider: str = "auto",
        mission_mode: str = "",
        limit: int = 320,
        recent_window: int = 16,
        baseline_window: int = 72,
        status: str = "",
    ) -> Dict[str, Any]:
        clean_action = str(action or "").strip().lower()
        if not clean_action:
            return {"status": "error", "message": "action is required"}
        clean_provider = self._normalize_external_provider_name(provider) or "auto"
        clean_mission_mode = (
            self._connector_remediation_policy_normalize_mission_mode(mission_mode, wildcard_default=False)
            if str(mission_mode or "").strip()
            else self._connector_remediation_policy_runtime_mission_mode()
        )

        trends = self.external_connector_preflight_simulation_trends(
            limit=limit,
            action=clean_action,
            provider=clean_provider,
            status=status,
            recent_window=recent_window,
            baseline_window=baseline_window,
        )
        if str(trends.get("status", "")).strip().lower() != "success":
            return {
                "status": "error",
                "message": str(trends.get("message", "trend diagnostics failed")).strip() or "trend diagnostics failed",
            }

        profile = self._connector_remediation_policy_normalize_profile(
            str(trends.get("recommended_profile", "balanced"))
        )
        controls = self._connector_remediation_policy_sanitize_controls(
            profile=profile,
            controls=trends.get("recommended_controls", {}),
        )
        recent = trends.get("recent", {}) if isinstance(trends.get("recent"), dict) else {}
        deltas = trends.get("deltas", {}) if isinstance(trends.get("deltas"), dict) else {}
        stability = trends.get("stability", {}) if isinstance(trends.get("stability"), dict) else {}
        sample_count = int(trends.get("count", 0) or 0)
        ready_delta = float(deltas.get("ready_ratio", 0.0) or 0.0)
        error_delta = float(deltas.get("error_ratio", 0.0) or 0.0)
        confidence_delta = float(deltas.get("confidence", 0.0) or 0.0)
        stability_score = max(0.0, min(float(stability.get("score", 0.0) or 0.0), 1.0))
        recent_error = max(0.0, min(float(recent.get("error_ratio", 0.0) or 0.0), 1.0))
        sample_coverage = max(0.0, min(float(sample_count) / float(max(10, int(recent_window) * 2)), 1.0))
        confidence = max(
            0.0,
            min(
                1.0,
                (stability_score * 0.46)
                + (sample_coverage * 0.3)
                + ((1.0 - recent_error) * 0.16)
                + (max(0.0, confidence_delta + 0.12) * 0.08),
            ),
        )

        reasons: list[str] = []
        if ready_delta <= -0.08:
            reasons.append("readiness drift detected in recent simulation window")
        if error_delta >= 0.08:
            reasons.append("error ratio increased versus baseline")
        if confidence_delta <= -0.08:
            reasons.append("routing confidence decayed versus baseline")
        if stability_score <= 0.5:
            reasons.append("stability score indicates elevated execution volatility")
        if not reasons:
            reasons.append("trend diagnostics indicate stable routing behavior")

        current = self.external_connector_remediation_policy_status(
            action=clean_action,
            provider=clean_provider,
            mission_mode=clean_mission_mode,
            include_history=False,
            include_alerts=False,
        )
        current_profile = self._connector_remediation_policy_normalize_profile(str(current.get("profile", "balanced")))
        current_controls = current.get("controls", {}) if isinstance(current.get("controls"), dict) else {}

        return {
            "status": "success",
            "action": clean_action,
            "provider": clean_provider,
            "mission_mode": clean_mission_mode,
            "current": {
                "profile": current_profile,
                "controls": _to_jsonable(current_controls),
                "matched_scope_key": str(current.get("matched_scope_key", "")).strip().lower(),
            },
            "recommendation": {
                "profile": profile,
                "controls": controls,
                "confidence": round(confidence, 6),
                "reasons": reasons[:8],
                "would_change_profile": profile != current_profile,
            },
            "trend_summary": {
                "count": sample_count,
                "recent": _to_jsonable(recent),
                "deltas": _to_jsonable(deltas),
                "stability": _to_jsonable(stability),
                "provider_mix": _to_jsonable(trends.get("provider_mix", [])),
            },
        }

    def external_connector_remediation_policy_apply(
        self,
        *,
        action: str,
        provider: str = "auto",
        mission_mode: str = "",
        profile: str = "",
        controls: Any = None,
        source: str = "desktop-ui",
        reason: str = "",
        metadata: Optional[Dict[str, Any]] = None,
        use_recommendation: bool = True,
        limit: int = 320,
        recent_window: int = 16,
        baseline_window: int = 72,
        status: str = "",
    ) -> Dict[str, Any]:
        clean_action = str(action or "").strip().lower()
        if not clean_action:
            return {"status": "error", "message": "action is required"}
        clean_provider = self._normalize_external_provider_name(provider) or "auto"
        clean_source = str(source or "desktop-ui").strip().lower() or "desktop-ui"
        metadata_payload = metadata if isinstance(metadata, dict) else {}
        if str(mission_mode or "").strip():
            clean_mission_mode = self._connector_remediation_policy_normalize_mission_mode(
                mission_mode,
                wildcard_default=True,
            )
        elif "mission_mode" in metadata_payload:
            clean_mission_mode = self._connector_remediation_policy_normalize_mission_mode(
                metadata_payload.get("mission_mode"),
                wildcard_default=True,
            )
        else:
            clean_mission_mode = "*"

        recommendation_payload: Dict[str, Any] = {}
        if use_recommendation or not str(profile or "").strip():
            recommendation_payload = self.external_connector_remediation_policy_recommendation(
                action=clean_action,
                provider=clean_provider,
                mission_mode=clean_mission_mode,
                limit=limit,
                recent_window=recent_window,
                baseline_window=baseline_window,
                status=status,
            )
            if str(recommendation_payload.get("status", "")).strip().lower() != "success":
                return recommendation_payload

        recommendation = (
            recommendation_payload.get("recommendation", {})
            if isinstance(recommendation_payload.get("recommendation"), dict)
            else {}
        )
        recommended_profile = self._connector_remediation_policy_normalize_profile(
            str(recommendation.get("profile", "balanced"))
        )
        effective_profile = self._connector_remediation_policy_normalize_profile(
            str(profile or "").strip().lower() or recommended_profile
        )
        recommended_controls = recommendation.get("controls", {}) if isinstance(recommendation.get("controls"), dict) else {}
        merged_controls_seed: Dict[str, Any] = dict(recommended_controls) if use_recommendation else {}
        if isinstance(controls, dict):
            merged_controls_seed.update(controls)
        effective_controls = self._connector_remediation_policy_sanitize_controls(
            profile=effective_profile,
            controls=merged_controls_seed,
        )
        scope = self._connector_remediation_policy_scope(
            action=clean_action,
            provider=clean_provider,
            mission_mode=clean_mission_mode,
        )
        now_iso = self._utc_now_iso()

        self._load_connector_remediation_policy_state()
        with self._connector_remediation_policy_lock:
            state = self._connector_remediation_policy_state if isinstance(self._connector_remediation_policy_state, dict) else {}
            profiles = state.get("profiles", {}) if isinstance(state.get("profiles"), dict) else {}
            history = state.get("history", []) if isinstance(state.get("history"), list) else []

            previous = profiles.get(scope["scope_key"], {}) if isinstance(profiles.get(scope["scope_key"], {}), dict) else {}
            next_version = int(previous.get("version", 0) or 0) + 1
            event_id = int(history[-1].get("event_id", 0) or 0) + 1 if history and isinstance(history[-1], dict) else 1
            recommendation_confidence = float(recommendation.get("confidence", 0.0) or 0.0)

            entry = {
                "scope_key": scope["scope_key"],
                "legacy_scope_key": scope["legacy_scope_key"],
                "action": scope["action"],
                "provider": scope["provider"],
                "mission_mode": scope["mission_mode"],
                "profile": effective_profile,
                "controls": effective_controls,
                "version": next_version,
                "updated_at": now_iso,
                "updated_by_source": clean_source,
                "reason": str(reason or "").strip(),
                "recommendation_confidence": round(max(0.0, min(recommendation_confidence, 1.0)), 6),
                "metadata": _to_jsonable(metadata_payload),
            }
            profiles[scope["scope_key"]] = _to_jsonable(entry)
            state["profiles"] = profiles
            history.append(
                {
                    "event_id": event_id,
                    "created_at": now_iso,
                    "scope_key": scope["scope_key"],
                    "legacy_scope_key": scope["legacy_scope_key"],
                    "action": scope["action"],
                    "provider": scope["provider"],
                    "mission_mode": scope["mission_mode"],
                    "profile": effective_profile,
                    "controls": effective_controls,
                    "source": clean_source,
                    "reason": str(reason or "").strip(),
                    "recommendation_confidence": round(max(0.0, min(recommendation_confidence, 1.0)), 6),
                    "used_recommendation": bool(use_recommendation),
                    "metadata": _to_jsonable(metadata_payload),
                }
            )
            max_history = max(40, int(getattr(self, "_connector_remediation_policy_history_max", 1200) or 1200))
            if len(history) > max_history:
                history = history[-max_history:]
            state["history"] = history
            state["updated_at"] = now_iso
            state["version"] = str(state.get("version", "1.0") or "1.0")
            self._connector_remediation_policy_state = state
            self._connector_remediation_policy_dirty = True

        self._persist_connector_remediation_policy_state(force=False)
        try:
            self.kernel.telemetry.emit(
                "external.connector_remediation_policy_applied",
                {
                    "scope_key": scope["scope_key"],
                    "action": scope["action"],
                    "provider": scope["provider"],
                    "mission_mode": scope["mission_mode"],
                    "profile": effective_profile,
                    "source": clean_source,
                    "use_recommendation": bool(use_recommendation),
                },
            )
        except Exception:
            pass
        return {
            "status": "success",
            "action": scope["action"],
            "provider": scope["provider"],
            "mission_mode": scope["mission_mode"],
            "scope_key": scope["scope_key"],
            "event_id": event_id,
            "entry": _to_jsonable(entry),
            "history_event": {
                "event_id": event_id,
                "created_at": now_iso,
                "scope_key": scope["scope_key"],
                "legacy_scope_key": scope["legacy_scope_key"],
                "action": scope["action"],
                "provider": scope["provider"],
                "mission_mode": scope["mission_mode"],
                "profile": effective_profile,
                "controls": effective_controls,
                "source": clean_source,
                "reason": str(reason or "").strip(),
                "recommendation_confidence": round(max(0.0, min(recommendation_confidence, 1.0)), 6),
                "used_recommendation": bool(use_recommendation),
                "metadata": _to_jsonable(metadata_payload),
            },
            "recommendation": _to_jsonable(recommendation_payload.get("recommendation", {}))
            if isinstance(recommendation_payload, dict)
            else {},
            "message": f"Remediation policy updated for {scope['scope_key']}.",
        }

