    @staticmethod
    def _connector_remediation_policy_default_state() -> Dict[str, Any]:
        return {
            "version": "1.0",
            "updated_at": "",
            "profiles": {},
            "history": [],
            "autotune": DesktopBackendService._connector_remediation_autotune_default_state(),
        }

    def _load_connector_remediation_policy_state(self) -> None:
        with self._connector_remediation_policy_lock:
            if bool(self._connector_remediation_policy_state_loaded):
                return
            self._connector_remediation_policy_state_loaded = True

        path = self._connector_remediation_policy_store_path()
        state = self._connector_remediation_policy_default_state()
        if os.path.exists(path):
            try:
                with open(path, "r", encoding="utf-8") as handle:
                    parsed = json.load(handle)
                if isinstance(parsed, dict):
                    state = {
                        **state,
                        **parsed,
                    }
            except Exception as exc:  # noqa: BLE001
                self.log.warning(f"Failed to load connector remediation policy state '{path}': {exc}")

        profiles = state.get("profiles", {}) if isinstance(state.get("profiles"), dict) else {}
        history = state.get("history", []) if isinstance(state.get("history"), list) else []
        max_history = max(40, int(getattr(self, "_connector_remediation_policy_history_max", 1200) or 1200))
        if len(history) > max_history:
            history = history[-max_history:]
        sanitized_profiles: Dict[str, Dict[str, Any]] = {}
        for scope_key, row in profiles.items():
            clean_scope_key = str(scope_key or "").strip().lower()
            if not clean_scope_key or not isinstance(row, dict):
                continue
            sanitized_profiles[clean_scope_key] = _to_jsonable(dict(row))

        sanitized_history: list[Dict[str, Any]] = []
        for row in history:
            if isinstance(row, dict):
                sanitized_history.append(_to_jsonable(dict(row)))

        with self._connector_remediation_policy_lock:
            self._connector_remediation_policy_state = {
                "version": str(state.get("version", "1.0") or "1.0"),
                "updated_at": str(state.get("updated_at", "")).strip(),
                "profiles": sanitized_profiles,
                "history": sanitized_history,
                "autotune": _to_jsonable(
                    state.get("autotune", {})
                    if isinstance(state.get("autotune"), dict)
                    else self._connector_remediation_autotune_default_state()
                ),
            }
            self._connector_remediation_autotune_state_locked()
            self._connector_remediation_policy_dirty = False

    def _persist_connector_remediation_policy_state(self, *, force: bool = False) -> None:
        with self._connector_remediation_policy_lock:
            if not bool(self._connector_remediation_policy_state_loaded):
                return
            if not force and not bool(getattr(self, "_connector_remediation_policy_dirty", False)):
                return
            state = (
                self._connector_remediation_policy_state
                if isinstance(self._connector_remediation_policy_state, dict)
                else self._connector_remediation_policy_default_state()
            )
            history = state.get("history", []) if isinstance(state.get("history"), list) else []
            max_history = max(40, int(getattr(self, "_connector_remediation_policy_history_max", 1200) or 1200))
            if len(history) > max_history:
                history = history[-max_history:]
            payload = {
                "version": str(state.get("version", "1.0") or "1.0"),
                "updated_at": str(state.get("updated_at", "")).strip(),
                "profiles": _to_jsonable(state.get("profiles", {}) if isinstance(state.get("profiles"), dict) else {}),
                "history": _to_jsonable(history),
                "autotune": _to_jsonable(self._connector_remediation_autotune_state_locked()),
            }
            self._connector_remediation_policy_state = dict(payload)
            path = self._connector_remediation_policy_store_path()

        try:
            directory = os.path.dirname(path)
            if directory:
                os.makedirs(directory, exist_ok=True)
            with open(path, "w", encoding="utf-8") as handle:
                json.dump(payload, handle, indent=2, sort_keys=True)
                handle.write("\n")
            with self._connector_remediation_policy_lock:
                self._connector_remediation_policy_dirty = False
        except Exception as exc:  # noqa: BLE001
            self.log.warning(f"Failed to persist connector remediation policy state '{path}': {exc}")

