    @staticmethod
    def _bridge_scheduler_default_canary_state() -> Dict[str, Any]:
        return {
            "active": False,
            "id": "",
            "baseline_profile": "",
            "candidate_profile": "",
            "switch_reason": "",
            "started_at": "",
            "started_monotonic": 0.0,
            "start_event_id": 0,
            "baseline_metrics": {},
            "last_metrics": {},
            "sample_count": 0,
            "decision": "inactive",
            "decided_at": "",
        }

    @staticmethod
    def _bridge_scheduler_default_mission_tuner_state() -> Dict[str, Any]:
        return {
            "last_eval_at": "",
            "last_eval_monotonic": 0.0,
            "last_tuned_at": "",
            "last_tuned_monotonic": 0.0,
            "eval_count": 0,
            "tune_count": 0,
            "ema_pressure": 0.0,
            "ema_stability": 0.5,
            "last_pack": "default",
            "last_mode": "stable",
            "last_reason": "",
            "last_adjustments": {},
            "signals": {},
            "history": [],
        }

    @classmethod
    def _bridge_scheduler_mission_tuner_state_sanitize(cls, state: Any) -> Dict[str, Any]:
        default = cls._bridge_scheduler_default_mission_tuner_state()
        payload = state if isinstance(state, dict) else {}
        out = dict(default)
        out["last_eval_at"] = str(payload.get("last_eval_at", "")).strip()
        out["last_tuned_at"] = str(payload.get("last_tuned_at", "")).strip()
        try:
            out["last_eval_monotonic"] = max(0.0, float(payload.get("last_eval_monotonic", 0.0) or 0.0))
        except Exception:
            out["last_eval_monotonic"] = 0.0
        try:
            out["last_tuned_monotonic"] = max(0.0, float(payload.get("last_tuned_monotonic", 0.0) or 0.0))
        except Exception:
            out["last_tuned_monotonic"] = 0.0
        try:
            out["eval_count"] = max(0, int(payload.get("eval_count", 0) or 0))
        except Exception:
            out["eval_count"] = 0
        try:
            out["tune_count"] = max(0, int(payload.get("tune_count", 0) or 0))
        except Exception:
            out["tune_count"] = 0
        try:
            out["ema_pressure"] = max(0.0, min(float(payload.get("ema_pressure", 0.0) or 0.0), 1.0))
        except Exception:
            out["ema_pressure"] = 0.0
        try:
            out["ema_stability"] = max(0.0, min(float(payload.get("ema_stability", 0.5) or 0.5), 1.0))
        except Exception:
            out["ema_stability"] = 0.5
        out["last_pack"] = str(payload.get("last_pack", "default") or "default").strip().lower() or "default"
        last_mode = str(payload.get("last_mode", "stable") or "stable").strip().lower()
        out["last_mode"] = (
            last_mode
            if last_mode in {"stable", "moderate", "severe", "relief"}
            else "stable"
        )
        out["last_reason"] = str(payload.get("last_reason", "")).strip()
        out["last_adjustments"] = _to_jsonable(
            payload.get("last_adjustments", {})
            if isinstance(payload.get("last_adjustments", {}), dict)
            else {}
        )
        out["signals"] = _to_jsonable(
            payload.get("signals", {})
            if isinstance(payload.get("signals", {}), dict)
            else {}
        )
        baseline_payload = payload.get("baseline", {}) if isinstance(payload.get("baseline", {}), dict) else {}
        if baseline_payload:
            def _float_baseline(field: str, default_value: float, minimum: float, maximum: float) -> float:
                try:
                    parsed = float(baseline_payload.get(field, default_value) or default_value)
                except Exception:
                    parsed = float(default_value)
                return max(minimum, min(parsed, maximum))

            def _int_baseline(field: str, default_value: int, minimum: int, maximum: int) -> int:
                try:
                    parsed = int(baseline_payload.get(field, default_value) or default_value)
                except Exception:
                    parsed = int(default_value)
                return max(minimum, min(parsed, maximum))

            out["baseline"] = {
                "guardrail_badness_threshold": _float_baseline("guardrail_badness_threshold", 0.74, 0.1, 1.0),
                "guardrail_leakage_threshold": _float_baseline("guardrail_leakage_threshold", 0.22, 0.01, 1.0),
                "guardrail_cooldown_s": _float_baseline("guardrail_cooldown_s", 95.0, 5.0, 3600.0),
                "canary_window": _int_baseline("canary_window", 24, 6, 400),
                "canary_badness_margin": _float_baseline("canary_badness_margin", 0.06, 0.005, 1.0),
                "canary_failure_margin": _float_baseline("canary_failure_margin", 0.05, 0.005, 1.0),
                "canary_queue_wait_margin": _float_baseline("canary_queue_wait_margin", 0.12, 0.005, 1.0),
                "canary_leakage_margin": _float_baseline("canary_leakage_margin", 0.08, 0.005, 1.0),
                "canary_contention_margin": _float_baseline("canary_contention_margin", 0.18, 0.01, 1.0),
            }
        history_raw = payload.get("history", [])
        history_rows = [dict(item) for item in history_raw if isinstance(item, dict)] if isinstance(history_raw, list) else []
        out["history"] = _to_jsonable(history_rows[-220:])
        return out

    def _bridge_scheduler_normalize_mission_tuner_policy(self) -> bool:
        try:
            severe = max(
                0.1,
                min(float(getattr(self, "_bridge_scheduler_mission_tuner_severe_threshold", 0.68) or 0.68), 1.0),
            )
        except Exception:
            severe = 0.68
        try:
            moderate = max(
                0.05,
                min(float(getattr(self, "_bridge_scheduler_mission_tuner_moderate_threshold", 0.44) or 0.44), 1.0),
            )
        except Exception:
            moderate = 0.44
        try:
            relief = max(
                0.01,
                min(float(getattr(self, "_bridge_scheduler_mission_tuner_relief_threshold", 0.22) or 0.22), 1.0),
            )
        except Exception:
            relief = 0.22
        next_severe = severe
        next_moderate = min(moderate, next_severe)
        next_relief = min(relief, next_moderate)
        changed = (
            abs(next_severe - severe) > 0.000001
            or abs(next_moderate - moderate) > 0.000001
            or abs(next_relief - relief) > 0.000001
        )
        self._bridge_scheduler_mission_tuner_severe_threshold = float(next_severe)
        self._bridge_scheduler_mission_tuner_moderate_threshold = float(next_moderate)
        self._bridge_scheduler_mission_tuner_relief_threshold = float(next_relief)
        return bool(changed)

