    @classmethod
    def _bridge_scheduler_sanitize_guardrail_policy_packs(
        cls,
        payload: Dict[str, Any],
    ) -> Dict[str, Dict[str, Any]]:
        defaults = cls._bridge_scheduler_default_guardrail_policy_packs()
        merged: Dict[str, Any] = dict(defaults)
        if isinstance(payload, dict):
            for key, value in payload.items():
                clean_key = str(key or "").strip().lower()
                if not clean_key:
                    continue
                if isinstance(value, dict):
                    merged[clean_key] = value
        sanitized: Dict[str, Dict[str, Any]] = {}
        for pack_name, pack_payload in merged.items():
            if not isinstance(pack_payload, dict):
                continue
            base = defaults.get(pack_name if pack_name in defaults else "default", defaults["default"])
            raw = {**base, **pack_payload}
            def _float_field(field: str, default_value: float, minimum: float, maximum: float) -> float:
                try:
                    parsed = float(raw.get(field, default_value) or default_value)
                except Exception:
                    parsed = float(default_value)
                return max(minimum, min(parsed, maximum))
            target_profile = str(raw.get("target_profile", base.get("target_profile", "safe")) or "safe").strip().lower() or "safe"
            critical_target_profile = str(
                raw.get("critical_target_profile", base.get("critical_target_profile", target_profile)) or target_profile
            ).strip().lower() or target_profile
            degraded_target_profile = str(
                raw.get("degraded_target_profile", base.get("degraded_target_profile", target_profile)) or target_profile
            ).strip().lower() or target_profile
            sanitized[pack_name] = {
                "badness_threshold": _float_field("badness_threshold", 0.74, 0.1, 1.0),
                "leakage_threshold": _float_field("leakage_threshold", 0.22, 0.01, 1.0),
                "critical_queue_ratio_floor": _float_field("critical_queue_ratio_floor", 0.28, 0.01, 1.0),
                "contention_ratio_threshold": _float_field("contention_ratio_threshold", 0.82, 0.2, 1.0),
                "winner_margin_floor": _float_field("winner_margin_floor", 0.06, 0.001, 1.0),
                "pressure_trip_threshold": _float_field("pressure_trip_threshold", 0.72, 0.1, 1.0),
                "cooldown_multiplier": _float_field("cooldown_multiplier", 1.0, 0.25, 6.0),
                "target_profile": target_profile,
                "critical_target_profile": critical_target_profile,
                "degraded_target_profile": degraded_target_profile,
            }
        if "default" not in sanitized:
            sanitized["default"] = dict(defaults["default"])
        return sanitized

    def _bridge_scheduler_resolve_guardrail_pack_locked(
        self,
        runtime_context: Dict[str, Any],
    ) -> Dict[str, Any]:
        mission_mode = str(runtime_context.get("mission_mode", "stable")).strip().lower() or "stable"
        queue_rows = self._bridge_scheduler_queue if isinstance(self._bridge_scheduler_queue, list) else []
        source_counts: Dict[str, int] = {}
        for row in queue_rows:
            if not isinstance(row, dict):
                continue
            source = str(row.get("source", "")).strip().lower() or "desktop-bridge"
            source_counts[source] = int(source_counts.get(source, 0) or 0) + 1
        dominant_source = ""
        if source_counts:
            dominant_source = sorted(
                source_counts.items(),
                key=lambda item: (-int(item[1]), item[0]),
            )[0][0]
        pack_by_source = (
            self._bridge_scheduler_guardrail_pack_by_source
            if isinstance(self._bridge_scheduler_guardrail_pack_by_source, dict)
            else {}
        )
        pack_by_mission_mode = (
            self._bridge_scheduler_guardrail_pack_by_mission_mode
            if isinstance(self._bridge_scheduler_guardrail_pack_by_mission_mode, dict)
            else {}
        )
        requested_pack = ""
        if dominant_source:
            requested_pack = str(pack_by_source.get(dominant_source, "") or "").strip().lower()
        if not requested_pack:
            requested_pack = str(pack_by_mission_mode.get(mission_mode, "") or "").strip().lower()
        if not requested_pack:
            requested_pack = str(getattr(self, "_bridge_scheduler_guardrail_default_pack", "default") or "default").strip().lower()
        packs = (
            self._bridge_scheduler_guardrail_policy_packs
            if isinstance(self._bridge_scheduler_guardrail_policy_packs, dict)
            else {}
        )
        selected_payload = packs.get(requested_pack)
        if not isinstance(selected_payload, dict):
            requested_pack = "default"
            selected_payload = packs.get("default")
        if not isinstance(selected_payload, dict):
            sanitized = self._bridge_scheduler_sanitize_guardrail_policy_packs({})
            self._bridge_scheduler_guardrail_policy_packs = sanitized
            selected_payload = sanitized.get("default", {})
        return {
            "pack_name": str(requested_pack or "default"),
            "pack": _to_jsonable(dict(selected_payload)),
            "dominant_source": dominant_source,
            "mission_mode": mission_mode,
            "source_counts": _to_jsonable(source_counts),
        }

